const MercenaryStatsPanel = ({ 
    mercenary, 
    finalStats, 
    localAllocated, 
    onSetLocalAllocated 
}: { 
    mercenary: Mercenary; 
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
}) => {
    const { actions } = useGame();

    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);

    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, value: number | string, isPercent = false) => (
        <div className="bg-stone-800/50 p-2 rounded-lg border border-stone-800 flex justify-between items-center h-9">
            <span className="text-[10px] text-stone-400 font-bold flex items-center gap-1.5">{icon} {label}</span>
            <span className="font-mono text-sm font-bold text-stone-200">
                {value}{isPercent ? '%' : ''}
            </span>
        </div>
    );

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;

        onSetLocalAllocated({
            ...localAllocated,
            [key]: newVal
        });
    };

    const handleApply = () => {
        actions.updateMercenaryStats(mercenary.id, localAllocated);
    };

    const handleReset = () => {
        onSetLocalAllocated({ ...mercenary.allocatedStats });
    };

    return (
        <div className="p-5 flex flex-col gap-4 overflow-y-auto shrink-0 border-b border-stone-800 custom-scrollbar max-h-[60%]">
            <div className="bg-stone-800/50 p-3 rounded-xl border border-stone-800 shadow-sm shrink-0">
                <div className="flex justify-between items-end mb-1.5">
                    <span className="text-amber-500 font-bold font-mono text-base">LEVEL {mercenary.level}</span>
                    <span className="text-stone-500 text-xs font-mono">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-2.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800">
                    <div className="h-full bg-amber-600 shadow-[0_0_10px_rgba(217,119,6,0.5)] transition-all duration-500 ease-out" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            <div className="bg-stone-950/30 rounded-xl border border-stone-800/50 p-3">
                <div className="flex justify-between items-center mb-3">
                    <h4 className="text-[10px] font-bold text-stone-500 uppercase tracking-widest flex items-center gap-2"><Star className="w-3 h-3" /> Attributes</h4>
                    <div className="flex items-center gap-1.5">
                        {availablePoints > 0 ? (
                             <span className="text-[10px] font-black text-amber-500 animate-pulse">+{availablePoints} POINTS AVAILABLE</span>
                        ) : (
                             <span className="text-[10px] font-bold text-stone-600 uppercase">Points Exhausted</span>
                        )}
                    </div>
                </div>
                <div className="grid grid-cols-5 gap-2">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' }
                    ].map((stat) => {
                        const committedValue = mercenary.stats[stat.key] + mercenary.allocatedStats[stat.key];
                        const currentValue = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const isModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];

                        return (
                            <div key={stat.key} className="flex flex-col gap-1">
                                <div className={`bg-stone-800 border ${isModified ? 'border-amber-500/50' : 'border-stone-700'} p-1.5 rounded-lg flex flex-col items-center justify-center relative transition-colors`}>
                                    <span className={`text-[9px] font-bold ${stat.color}`}>{stat.label}</span>
                                    <span className={`text-sm font-mono font-bold ${isModified ? 'text-amber-400 scale-110' : 'text-stone-200'} transition-all`}>{currentValue}</span>
                                </div>
                                <div className="flex gap-1">
                                    <button 
                                        onClick={() => updateLocalStat(stat.key, -1)}
                                        disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]}
                                        className="flex-1 h-6 bg-stone-800 hover:bg-stone-700 border border-stone-700 rounded flex items-center justify-center text-stone-500 hover:text-red-400 transition-all disabled:opacity-30 disabled:pointer-events-none"
                                    >
                                        <Minus className="w-3 h-3" />
                                    </button>
                                    <button 
                                        onClick={() => updateLocalStat(stat.key, 1)}
                                        disabled={availablePoints <= 0}
                                        className="flex-1 h-6 bg-stone-800 hover:bg-amber-900/40 border border-stone-700 hover:border-amber-600/50 rounded flex items-center justify-center text-stone-500 hover:text-amber-400 transition-all disabled:opacity-30 disabled:pointer-events-none"
                                    >
                                        <Plus className="w-3 h-3" />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {hasChanges && (
                    <div className="mt-4 flex gap-2 animate-in slide-in-from-top-2 duration-300">
                         <button 
                            onClick={handleReset}
                            className="flex-1 py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 hover:text-stone-200 text-xs font-bold rounded-lg border border-stone-700 transition-all flex items-center justify-center gap-2"
                        >
                            <RefreshCw className="w-3 h-3" /> Reset
                        </button>
                        <button 
                            onClick={handleApply}
                            className="flex-[2] py-2 bg-amber-700 hover:bg-amber-600 text-amber-50 text-xs font-bold rounded-lg shadow-lg border border-amber-500 transition-all flex items-center justify-center gap-2"
                        >
                            <Check className="w-3 h-3" /> Apply Changes
                        </button>
                    </div>
                )}
            </div>

            <div className="grid grid-cols-2 gap-3 shrink-0">
                <div className="bg-stone-800/50 p-2.5 rounded-xl border border-stone-800 flex items-center gap-3">
                    <div className="p-1.5 bg-red-900/20 rounded-lg text-red-500 border border-red-900/30"><Heart className="w-4 h-4" /></div>
                    <div className="flex-1">
                        <div className="flex justify-between text-[10px] text-stone-400 font-bold mb-1">
                            <span>HEALTH</span><span className="text-stone-200">{mercenary.currentHp} / {finalStats.maxHp}</span>
                        </div>
                        <div className="w-full h-1 bg-stone-950 rounded-full overflow-hidden">
                            <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }}></div>
                        </div>
                    </div>
                </div>
                <div className="bg-stone-800/50 p-2.5 rounded-xl border border-stone-800 flex items-center gap-3">
                    <div className="p-1.5 bg-blue-900/20 rounded-lg text-blue-500 border border-blue-900/30"><Activity className="w-4 h-4" /></div>
                    <div className="flex-1">
                        <div className="flex justify-between text-[10px] text-stone-400 font-bold mb-1">
                            <span>MANA</span><span className="text-stone-200">{mercenary.currentMp} / {finalStats.maxMp}</span>
                        </div>
                        <div className="w-full h-1 bg-stone-950 rounded-full overflow-hidden">
                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }}></div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="shrink-0">
                <h4 className="text-[10px] font-bold text-stone-500 uppercase tracking-widest mb-2 flex items-center gap-2"><Sword className="w-3 h-3" /> Combat Statistics</h4>
                <div className="grid grid-cols-2 gap-2">
                    {renderStatRow(<Sword className="w-3 h-3" />, 'P.ATK', finalStats.physicalAttack)}
                    {renderStatRow(<Shield className="w-3 h-3" />, 'P.DEF', finalStats.physicalDefense)}
                    {renderStatRow(<Zap className="w-3 h-3" />, 'M.ATK', finalStats.magicalAttack)}
                    {renderStatRow(<Brain className="w-3 h-3" />, 'M.DEF', finalStats.magicalDefense)}
                    {renderStatRow(<Crosshair className="w-3 h-3" />, 'ACC', finalStats.accuracy)}
                    {renderStatRow(<Wind className="w-3 h-3" />, 'EVA', finalStats.evasion)}
                    {renderStatRow(<Target className="w-3 h-3" />, 'CRIT', `${finalStats.critChance}%`, true)}
                    {renderStatRow(<FastForward className="w-3 h-3" />, 'SPD', finalStats.speed)}
                </div>
            </div>
        </div>
    );
};

const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
}) => {
    const totalMercStats = useMemo(() => mergePrimaryStats(mercenary.stats, mercenary.allocatedStats), [mercenary]);

    const displayInventory = useMemo(() => {
        let items = selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
        return items;
    }, [inventory, selectedSlotFilter]);

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    return (
        <div className="bg-stone-950 p-4 flex-1 flex flex-col min-h-0">
            <div className="flex justify-between items-center mb-3 shrink-0">
                <h3 className="text-xs font-bold text-stone-400 uppercase tracking-wider flex items-center gap-2">
                    <Box className="w-4 h-4 text-amber-600" /> 
                    {selectedSlotFilter ? `${selectedSlotFilter.replace('_', ' ')} Storage` : 'Equipment Storage'}
                </h3>
                <span className="text-[10px] text-stone-600 font-mono">{displayInventory.length} Items</span>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar pr-1">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex items-center justify-center border-2 border-dashed border-stone-800 rounded-lg text-stone-600 text-sm italic">
                        {selectedSlotFilter ? 'No matching equipment.' : 'No equipment available.'}
                    </div>
                ) : (
                    <div className="grid grid-cols-1 gap-2 content-start">
                        {displayInventory.map(item => {
                            if (!item.equipmentData) return null;
                            const isSelected = selectedItemId === item.id;
                            const reqs = item.equipmentData.equipRequirements || {};

                            const failedStats = Object.entries(reqs).filter(([stat, val]) => 
                                totalMercStats[stat as keyof PrimaryStats] < (val as number)
                            );
                            const canEquip = failedStats.length === 0;

                            const label = getQualityLabel(item.equipmentData.quality);
                            const qColor = getQualityColor(item.equipmentData.quality);
                            let imageUrl = item.equipmentData.image ? getAssetUrl(item.equipmentData.image) : (item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

                            return (
                                <div 
                                    key={item.id}
                                    onClick={() => !isSelected && onSelect(item.id)}
                                    className={`flex flex-col gap-2 p-3 rounded-lg border transition-all ${isSelected ? 'border-amber-500 bg-stone-800' : 'border-stone-800 hover:bg-stone-900'} cursor-pointer group ${!canEquip ? 'opacity-80' : ''}`}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-stone-900 rounded border border-stone-700 flex items-center justify-center relative shrink-0">
                                            <img src={imageUrl} className="w-8 h-8 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                            <div className="hidden text-xl">{item.icon || '📦'}</div>
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="text-sm font-bold truncate text-stone-300">{item.name}</div>
                                            <div className="flex items-center gap-2 text-[10px]">
                                                <span className="text-stone-500 uppercase">{item.equipmentData.slotType.replace('_', ' ')}</span>
                                                <span className={`${qColor} font-bold`}>{label}</span>
                                            </div>
                                        </div>
                                        {isSelected && canEquip && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                                className="shrink-0 px-3 py-1 bg-amber-700 hover:bg-amber-600 text-white text-[10px] font-bold uppercase rounded-md shadow-lg animate-in fade-in zoom-in duration-200"
                                            >
                                                Equip
                                            </button>
                                        )}
                                    </div>

                                    {/* Additional Info: Durability & Requirements */}
                                    <div className="flex justify-between items-end border-t border-stone-700/50 pt-2">
                                        <div className="flex items-center gap-2">
                                            <div className="flex items-center gap-1 text-[9px] text-stone-500 font-bold" title="Durability">
                                                <ShieldAlert className="w-2.5 h-2.5" />
                                                {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                            </div>
                                            {!item.equipmentData.isRepairable && <span className="text-[8px] bg-stone-800 text-stone-600 px-1 rounded font-bold uppercase tracking-tighter">Disposable</span>}
                                        </div>

                                        {Object.keys(reqs).length > 0 && (
                                            <div className="flex flex-wrap gap-1 justify-end max-w-[150px]">
                                                {Object.entries(reqs).map(([stat, val]) => {
                                                    const met = totalMercStats[stat as keyof PrimaryStats] >= (val as number);
                                                    return (
                                                        <span key={stat} className={`text-[8px] px-1 rounded font-bold uppercase ${met ? 'text-stone-500 border border-stone-800' : 'text-red-400 border border-red-900/30 bg-red-950/20'}`}>
                                                            {stat} {val}
                                                        </span>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>

                                    {!canEquip && isSelected && (
                                        <div className="mt-1 text-[9px] text-red-500 font-bold bg-red-950/30 p-1.5 rounded border border-red-900/30 flex items-center gap-1.5 animate-in slide-in-from-top-1 duration-200">
                                            <AlertCircle className="w-3 h-3" /> Requirements not met.
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
};

const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip }) => {
    const { state, actions } = useGame();

    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [prevAffinity, setPrevAffinity] = useState(0);
    const [showAffinityGain, setShowAffinityGain] = useState(false);

    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setPrevAffinity(mercenary.affinity);
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
        }
    }, [mercenary?.id]);

    useEffect(() => {
        if (mercenary && mercenary.affinity > prevAffinity) {
            setShowAffinityGain(true);
            const timer = setTimeout(() => setShowAffinityGain(false), 3000);
            setPrevAffinity(mercenary.affinity);
            return () => clearTimeout(timer);
        }
    }, [mercenary?.affinity]);

    if (!mercenary) return null;

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);

    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const finalStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);

    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(finalStats, currentAttackType);

    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;

    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;
            previewStats = applyEquipmentBonuses(baseDerived, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, currentAttackType);
        }
    }

    const effectiveFinalStats = previewStats || finalStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    return (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/95 backdrop-blur-sm animate-in fade-in duration-300">
            <button onClick={onClose} className="absolute top-6 right-6 z-[220] p-2 bg-stone-900 hover:bg-stone-800 rounded-full text-stone-500 hover:text-white border border-stone-700 transition-colors"><X className="w-6 h-6" /></button>
            <div className="w-full max-w-6xl h-[85vh] bg-stone-950 border border-stone-800 rounded-2xl shadow-2xl flex flex-col md:flex-row overflow-hidden relative">
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    combatPower={effectiveCombatPower} 
                    showAffinityGain={showAffinityGain} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={setSelectedSlot} 
                    selectedSlot={selectedSlot} 
                />
                <div className="w-full md:w-[60%] bg-stone-900 flex flex-col h-full max-h-full overflow-hidden">
                    <MercenaryStatsPanel 
                        mercenary={mercenary} 
                        finalStats={effectiveFinalStats} 
                        localAllocated={localAllocated}
                        onSetLocalAllocated={setLocalAllocated}
                    />
                    <EquipmentInventoryList 
                        inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                        selectedItemId={selectedInventoryItemId} 
                        onSelect={setSelectedInventoryItemId} 
                        onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                        selectedSlotFilter={selectedSlot}
                        mercenary={mercenary}
                    />
                </div>
            </div>
        </div>
    );
};

export default MercenaryDetailModal;

import React from 'react';
import { useGame } from '../../context/GameContext';
import { Hammer, Sword, Shield, Zap, Brain, Check, Star, ArrowUp, ArrowDown } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { EquipmentStats } from '../../models/Equipment';
import { EQUIPMENT_ITEMS } from '../../data/equipment';

const CraftingResultModal = () => {
    const { state, actions } = useGame();
    const item = state.lastCraftedItem;

    if (!item || !item.equipmentData) return null;

    const data = item.equipmentData;
    const recipe = EQUIPMENT_ITEMS.find(r => r.id === data.recipeId);
    const imageUrl = data.image ? getAssetUrl(data.image) : (data.recipeId ? getAssetUrl(`${data.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    const label = getQualityLabel(data.quality);
    const qColor = getQualityColor(data.quality);

    const renderStatItem = (icon: React.ReactNode, labelStr: string, statKey: keyof EquipmentStats, value: number) => {
        const baseValue = recipe?.baseStats?.[statKey] || 0;
        const diff = value - baseValue;

        let status: 'UP' | 'DOWN' | 'EQUAL' = 'EQUAL';
        if (diff > 0) status = 'UP';
        else if (diff < 0) status = 'DOWN';

        const tooltip = status !== 'EQUAL' 
            ? `Standard ${baseValue} ${diff > 0 ? '+' : '-'} ${Math.abs(diff)} (${diff > 0 ? 'Bonus' : 'Low Quality'})`
            : `Standard ${baseValue}`;

        return (
            <div 
                className={`bg-stone-950/50 p-3 rounded-xl border transition-all hover:bg-stone-900 group cursor-help flex justify-between items-center ${
                    status === 'UP' ? 'border-amber-600/40 shadow-[inner_0_0_10px_rgba(245,158,11,0.1)]' : 
                    status === 'DOWN' ? 'border-red-900/40 shadow-[inner_0_0_10px_rgba(239,68,68,0.05)]' : 
                    'border-stone-800'
                }`}
                title={tooltip}
            >
                <span className="text-[10px] text-stone-500 font-bold uppercase flex items-center gap-1.5 group-hover:text-stone-400">
                    {icon} {labelStr}
                </span>
                <div className="flex items-center gap-1.5">
                    <span className={`text-sm font-mono font-bold transition-colors ${
                        status === 'UP' ? 'text-amber-400 drop-shadow-[0_0_8px_rgba(245,158,11,0.4)]' : 
                        status === 'DOWN' ? 'text-red-500' : 
                        'text-stone-200'
                    }`}>
                        {value}
                    </span>
                    {status === 'UP' && (
                        <ArrowUp className="w-3 h-3 text-amber-500 animate-bounce" />
                    )}
                    {status === 'DOWN' && (
                        <ArrowDown className="w-3 h-3 text-red-700 animate-pulse" />
                    )}
                </div>
            </div>
        );
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md animate-in fade-in duration-500">
            <div className="relative z-10 w-full max-w-md bg-stone-900 border-2 border-amber-600 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-500">

                <div className="absolute top-20 left-1/2 -translate-x-1/2 w-48 h-48 bg-amber-500/10 blur-3xl rounded-full pointer-events-none"></div>

                {/* Header */}
                <div className="bg-stone-850 p-6 border-b border-stone-800 flex flex-col items-center text-center relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-2 opacity-10">
                         <Hammer className="w-20 h-20 text-stone-500" />
                    </div>
                    <div className={`w-24 h-24 bg-stone-900 rounded-full border-4 ${qColor.replace('text-', 'border-')} flex items-center justify-center mb-4 shadow-2xl transform hover:scale-110 transition-transform duration-500`}>
                        <img 
                            src={imageUrl} 
                            className="w-16 h-16 object-contain drop-shadow-lg" 
                            onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                        />
                        <span className="hidden text-5xl">{item.icon || '📦'}</span>
                    </div>
                    <h2 className="text-2xl font-bold text-stone-200 font-serif tracking-wide">{data.name}</h2>
                    <div className={`flex items-center gap-2 mt-2 px-3 py-1 rounded-full bg-stone-950 border border-stone-800 font-bold uppercase tracking-widest text-[10px] ${qColor}`}>
                        <Star className="w-3 h-3 fill-current" />
                        {label} Quality
                    </div>
                </div>

                {/* Content */}
                <div className="p-6 space-y-5">
                    <p className="text-stone-400 text-sm text-center italic leading-relaxed px-4">
                        "{item.description}"
                    </p>

                    <div className="grid grid-cols-2 gap-3">
                        {renderStatItem(<Sword className="w-3 h-3" />, "P.Atk", "physicalAttack", data.stats.physicalAttack)}
                        {renderStatItem(<Shield className="w-3 h-3" />, "P.Def", "physicalDefense", data.stats.physicalDefense)}
                        {renderStatItem(<Zap className="w-3 h-3" />, "M.Atk", "magicalAttack", data.stats.magicalAttack)}
                        {renderStatItem(<Brain className="w-3 h-3" />, "M.Def", "magicalDefense", data.stats.magicalDefense)}
                    </div>

                    <div className="flex justify-between items-center text-xs border-t border-stone-800 pt-4 px-2">
                        <span className="text-stone-500 uppercase font-bold tracking-tighter">Market Value</span>
                        <span className="text-amber-500 font-mono font-bold text-lg">{data.price} G</span>
                    </div>
                </div>

                {/* Footer */}
                <div className="p-4 border-t border-stone-800 bg-stone-850">
                    <button 
                        onClick={actions.dismissCraftingResult}
                        className="w-full py-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all transform active:scale-95"
                    >
                        <Check className="w-5 h-5" />
                        Complete Forge
                    </button>
                </div>
            </div>
        </div>
    );
};

export default CraftingResultModal;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../data/equipment';
import { EquipmentCategory, EquipmentItem } from '../../../types/index';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Shield, Sword, ChevronRight, Info, ChevronLeft, Lock, Check, X as XIcon, Box, Flame, ChevronDown, Heart, Star, Zap, Award, Wrench, X, ShoppingCart, Brain } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import { GAME_CONFIG } from '../../../config/game-config';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const { inventory, stats, isCrafting, craftingMastery, activeEvent } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [hasPromptedFurnace, setHasPromptedFurnace] = useState(false);

  const [expandedSubCat, setExpandedSubCat] = useState<string | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const getInventoryCount = useCallback((id: string) => {
      return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const getResourceName = (id: string) => {
      const itemDef = Object.values(MATERIALS).find(i => i.id === id);
      return itemDef ? itemDef.name : id;
  };

  const getItemImageUrl = (item: EquipmentItem) => {
    if (item.image) return getAssetUrl(item.image);
    // Fallback logic for items without specific image filenames
    return getAssetUrl(`${item.id}.png`);
  };

  const GLOBAL_COOLING_RATE_PER_SEC = 5; 
  const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
  const coolingAmount = timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC;
  const currentResidualTemp = Math.max(0, (state.forgeTemperature || 0) - coolingAmount);

  const hasHeat = currentResidualTemp > 0;
  const charcoalCount = getInventoryCount('charcoal');
  const hasFuel = charcoalCount > 0;

  useEffect(() => {
    if (!hasFurnace && !hasPromptedFurnace && !activeEvent) {
        actions.triggerEvent({
            id: 'CUSTOMER_VISIT',
            title: "The Forge lies in Ruins",
            description: "Your journey as a blacksmith starts with a single spark. To begin forging weapons and armor, you must first install a Furnace from the market.",
            options: [
                {
                    label: "Visit Market (500 G)",
                    action: () => onNavigate('MARKET')
                },
                {
                    label: "I'll look around first",
                    action: () => {}
                }
            ]
        });
        setHasPromptedFurnace(true);
    }
  }, [hasFurnace, hasPromptedFurnace, activeEvent, actions, onNavigate]);

  const canEnterForge = useMemo(() => {
      if (!selectedItem) return false;
      if (selectedItem.craftingType === 'WORKBENCH') return true;
      return hasFuel || hasHeat;
  }, [selectedItem, hasFuel, hasHeat]);

  const requiredEnergy = useMemo(() => {
      if (!selectedItem) return GAME_CONFIG.ENERGY_COST.CRAFT;
      const count = craftingMastery[selectedItem.id] || 0;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) {
          return GAME_CONFIG.ENERGY_COST.CRAFT - MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
      }
      return GAME_CONFIG.ENERGY_COST.CRAFT;
  }, [selectedItem, craftingMastery]);

  const hasEnergy = stats.energy >= requiredEnergy;

  const canAffordResources = useCallback((item: EquipmentItem) => {
      return item.requirements.every(req => getInventoryCount(req.id) >= req.count);
  }, [getInventoryCount]);

  const visibleItems = useMemo(() => {
      return EQUIPMENT_ITEMS.filter(item => {
          if (item.tier > stats.tierLevel) return false;
          const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
          return subCatDef?.categoryId === activeCategory;
      });
  }, [activeCategory, stats.tierLevel]);

  const favoriteItems = useMemo(() => {
      return visibleItems.filter(item => favorites.includes(item.id));
  }, [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
      const groups: Record<string, EquipmentItem[]> = {};
      visibleItems.forEach(item => {
          if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
          groups[item.subCategoryId].push(item);
      });
      return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
      return EQUIPMENT_SUBCATEGORIES.filter(sc => 
          sc.categoryId === activeCategory && groupedItems[sc.id] && groupedItems[sc.id].length > 0
      );
  }, [activeCategory, groupedItems]);

  useEffect(() => {
      if (favoriteItems.length > 0) {
          setExpandedSubCat('FAVORITES');
      } else if (visibleSubCats.length > 0) {
          setExpandedSubCat(visibleSubCats[0].id);
      } else {
          setExpandedSubCat(null);
      }
  }, [activeCategory, visibleSubCats, favoriteItems.length]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);   
  }, []);

  const toggleSubCategory = useCallback((subCatId: string) => {
      setExpandedSubCat(prev => (prev === subCatId ? null : subCatId));
  }, []);

  const toggleFavorite = useCallback((e: React.MouseEvent, itemId: string) => {
      e.stopPropagation(); 
      setFavorites(prev => 
          prev.includes(itemId)
              ? prev.filter(id => id !== itemId)
              : [...prev, itemId]
      );
  }, []);

  const startCrafting = useCallback(() => {
      if (!selectedItem) return;
      actions.startCrafting(selectedItem);
      setIsPanelOpen(false); 
  }, [actions, selectedItem]);

  const cancelCrafting = useCallback(() => {
      if (selectedItem) {
          actions.cancelCrafting(selectedItem);
      } else {
          actions.setCrafting(false); 
      }
      setIsPanelOpen(true);
  }, [actions, selectedItem]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
        actions.finishCrafting(selectedItem, score, bonus);
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      setTooltipPos({ x: e.clientX, y: e.clientY });
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) {
          setTooltipPos({ x: e.clientX, y: e.clientY });
      }
  }, [hoveredItem]);

  const handleMouseLeave = useCallback(() => {
      setHoveredItem(null);
  }, []);

  const getMasteryLevel = (count: number) => {
      if (count >= MASTERY_THRESHOLDS.ARTISAN) return 2;
      if (count >= MASTERY_THRESHOLDS.ADEPT) return 1;
      return 0;
  };

  const getMasteryIcon = (level: number) => {
      if (level === 2) return <Star className="w-3 h-3 text-yellow-400 fill-yellow-400" />;
      if (level === 1) return <Star className="w-3 h-3 text-stone-300 fill-stone-300" />;
      return <Star className="w-3 h-3 text-amber-700/50" />;
  };

  const renderItemCard = (item: EquipmentItem) => {
      const isSelected = selectedItem?.id === item.id;
      const isFav = favorites.includes(item.id);
      const count = inventory.filter(i => i.name === item.name).length;
      const masteryCount = craftingMastery[item.id] || 0;
      const masteryLevel = getMasteryLevel(masteryCount);

      return (
        <div 
            key={item.id}
            onClick={() => setSelectedItem(item)}
            onMouseEnter={(e) => handleMouseEnter(item, e)}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            className={`relative flex flex-col items-center rounded-lg border transition-all cursor-pointer group text-left h-[130px] overflow-hidden ${
                isSelected 
                ? 'bg-amber-900/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' 
                : 'bg-stone-800 border-stone-700 hover:border-stone-500 hover:bg-stone-750'
            }`}
        >
            <div className="w-full flex justify-between items-start p-2 z-10">
                 <span className={`text-[10px] font-bold tracking-wider font-mono ${isSelected ? 'text-amber-400' : 'text-stone-600'}`}>
                    TIER {item.tier}
                </span>

                <div className="flex items-center gap-1 -mt-1 -mr-1">
                    {masteryCount > 0 && (
                        <div className="p-1" title={`Mastery Level ${masteryLevel} (${masteryCount})`}>
                            {getMasteryIcon(masteryLevel)}
                        </div>
                    )}
                    <button 
                        onClick={(e) => toggleFavorite(e, item.id)}
                        className="p-1 rounded-full hover:bg-stone-700 transition-colors"
                    >
                        <Heart className={`w-3.5 h-3.5 ${isFav ? 'fill-red-500 text-red-500' : 'text-stone-600 hover:text-stone-400'}`} />
                    </button>
                </div>
            </div>

            <div className="flex-1 flex items-center justify-center group-hover:scale-110 transition-transform -mt-2">
                <img 
                    src={getItemImageUrl(item)} 
                    className="w-10 h-10 object-contain drop-shadow-md" 
                    onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} 
                />
                <span className="hidden text-3xl">{item.icon}</span>
            </div>

            <div className="w-full text-center pb-2 px-1 flex flex-col items-center gap-1">
                <div className={`text-xs font-bold leading-tight truncate w-full ${isSelected ? 'text-amber-200' : 'text-stone-300'}`}>
                    {item.name}
                </div>

                <div className="h-5 flex items-center justify-center w-full">
                    {count > 0 ? (
                        <div className="inline-flex items-center gap-0.5 bg-stone-950/50 px-2 py-0.5 rounded text-[10px] font-mono text-stone-500 border border-stone-800/50">
                            <Box className="w-2.5 h-2.5" /> {count}
                        </div>
                    ) : (
                        <div className="h-[18px]"></div>
                    )}
                </div>
            </div>
        </div>
      );
  };

  const isRequirementMet = useMemo(() => {
      if (!selectedItem) return true;
      if (selectedItem.craftingType === 'FORGE') return hasFurnace;
      if (selectedItem.craftingType === 'WORKBENCH') return hasWorkbench;
      return true;
  }, [selectedItem, hasFurnace, hasWorkbench]);

  const content = useMemo(() => {
    const canCraft = selectedItem && canAffordResources(selectedItem) && canEnterForge && hasEnergy && isRequirementMet;
    let masteryInfo = null;
    if (selectedItem) {
        const count = craftingMastery[selectedItem.id] || 0;
        const level = getMasteryLevel(count);
        let nextThreshold = MASTERY_THRESHOLDS.ADEPT;
        let progress = 0;
        let label = "Novice";
        let color = "text-stone-500";
        let benefits = "Base Stats";

        if (level === 0) {
            nextThreshold = MASTERY_THRESHOLDS.ADEPT;
            progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
        } else if (level === 1) {
            label = "Adept";
            color = "text-stone-300";
            nextThreshold = MASTERY_THRESHOLDS.ARTISAN;
            progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
            benefits = "Value +10%, Stats +10%";
        } else {
            label = "Artisan";
            color = "text-yellow-400";
            nextThreshold = count;
            progress = 100;
            benefits = "Value +25%, Stats +20%, Cost -5 Energy";
        }
        masteryInfo = { count, level, nextThreshold, progress, label, color, benefits };
    }

    return (
        <div 
            className="relative h-full w-full bg-stone-950 overflow-hidden"
            style={{ 
                backgroundImage: `url(${getAssetUrl('tile_forge.png')})`,
                backgroundRepeat: 'repeat',
                backgroundBlendMode: 'multiply'
            }}
        >

        {selectedItem && !isRequirementMet && (
            <div className="absolute inset-0 z-[60] flex items-center justify-center">
                <div className="absolute inset-0 bg-stone-950/90 backdrop-blur-md animate-in fade-in duration-700"></div>
                <div className="relative z-10 p-8 max-w-md w-full bg-stone-900 border-2 border-stone-800 rounded-2xl shadow-2xl flex flex-col items-center text-center animate-in zoom-in-95 duration-500">
                    <button 
                        onClick={() => setSelectedItem(null)}
                        className="absolute top-4 right-4 p-2 text-stone-500 hover:text-stone-300 transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                    <div className="w-20 h-20 bg-stone-800 rounded-full flex items-center justify-center mb-6 border border-stone-700">
                        {selectedItem.craftingType === 'FORGE' ? <Flame className="w-10 h-10 text-stone-600" /> : <Wrench className="w-10 h-10 text-stone-600" />}
                    </div>
                    <h2 className="text-2xl font-bold text-stone-300 font-serif mb-2">
                        {selectedItem.craftingType === 'FORGE' ? 'Furnace Required' : 'Workbench Required'}
                    </h2>
                    <p className="text-stone-500 mb-8 leading-relaxed">
                        Crafting <span className="text-amber-500 font-bold">{selectedItem.name}</span> requires a functional {selectedItem.craftingType === 'FORGE' ? 'furnace' : 'workbench'}. 
                        Visit the market to purchase one.
                    </p>
                    <button 
                        onClick={() => onNavigate('MARKET')}
                        className="w-full py-4 bg-amber-700 hover:bg-amber-600 text-amber-50 font-bold rounded-xl shadow-lg hover:shadow-amber-900/40 transition-all flex items-center justify-center gap-2 group"
                    >
                        Go to Market
                        <ChevronRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>
            </div>
        )}

        <div className={`absolute inset-0 z-0 flex w-full h-full ${((selectedItem && !isRequirementMet) || !hasFurnace) ? 'blur-sm pointer-events-none' : ''}`}>

            <div className={`h-full relative flex flex-col transition-all duration-500 ease-in-out ${isPanelOpen ? 'w-[60%]' : 'w-full'}`}>
            <div className="w-full h-full flex flex-col items-center justify-center p-8 bg-stone-925/40 relative overflow-hidden">

                <div className="absolute inset-0 opacity-10 pointer-events-none flex items-center justify-center">
                    {selectedItem?.craftingType === 'FORGE' ? (
                        <Hammer className="w-96 h-96 text-stone-500" />
                    ) : (
                        <Wrench className="w-96 h-96 text-stone-500" />
                    )}
                </div>

                {selectedItem ? (
                    <div className="z-10 flex flex-col items-center animate-in fade-in zoom-in duration-300 w-full max-w-lg">
                    <div className="relative group">
                        <div className={`w-48 h-48 bg-stone-900 rounded-full border-4 flex items-center justify-center transition-all duration-500 ${
                            selectedItem.craftingType === 'FORGE' 
                            ? 'border-amber-600 shadow-[0_0_40px_rgba(217,119,6,0.2)]' 
                            : 'border-emerald-600 shadow-[0_0_40px_rgba(16,185,129,0.2)]'
                        } mb-8 group-hover:scale-105`}>
                            <img 
                                src={getItemImageUrl(selectedItem)} 
                                className="w-32 h-32 object-contain drop-shadow-xl z-10" 
                                onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} 
                            />
                            <span className="hidden text-8xl filter drop-shadow-lg">{selectedItem.icon}</span>
                        </div>
                    </div>

                    <h2 className="text-3xl font-bold text-amber-500 mb-2 font-serif tracking-wide">{selectedItem.name}</h2>
                    <p className="text-stone-400 text-center max-w-md mb-4 italic">"{selectedItem.description}"</p>

                    {/* Base Stats Section Added */}
                    <div className="w-full grid grid-cols-4 gap-2 mb-6">
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Sword className="w-2 h-2"/> P.Atk</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.physicalAttack || 0}</span>
                        </div>
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Shield className="w-2 h-2"/> P.Def</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.physicalDefense || 0}</span>
                        </div>
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Zap className="w-2 h-2"/> M.Atk</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.magicalAttack || 0}</span>
                        </div>
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Brain className="w-2 h-2"/> M.Def</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.magicalDefense || 0}</span>
                        </div>
                    </div>

                    {masteryInfo && (
                        <div className="w-full bg-stone-900/50 p-3 rounded-lg border border-stone-800 mb-6 backdrop-blur-sm">
                            <div className="flex justify-between items-center mb-1 text-xs uppercase font-bold tracking-wider">
                                <span className="text-stone-500 flex items-center gap-1">
                                    <Award className="w-3 h-3" /> Mastery
                                </span>
                                <span className={masteryInfo.color}>{masteryInfo.label}</span>
                            </div>
                            <div className="w-full h-2 bg-stone-800 rounded-full overflow-hidden mb-1.5">
                                <div 
                                    className={`h-full transition-all duration-500 ${masteryInfo.level === 2 ? 'bg-yellow-500' : 'bg-amber-600'}`} 
                                    style={{ width: `${masteryInfo.progress}%` }}
                                ></div>
                            </div>
                            <div className="flex justify-between items-center text-[10px]">
                                <span className="text-stone-500">
                                    {masteryInfo.level < 2 ? `${masteryInfo.count} / ${masteryInfo.nextThreshold} Crafted` : 'Max Level'}
                                </span>
                                <span className="text-emerald-500">{masteryInfo.benefits}</span>
                            </div>
                        </div>
                    )}

                    <div className="flex items-center gap-3 mb-6">
                         <div className={`flex items-center gap-2 px-4 py-2 rounded-full border font-mono text-sm backdrop-blur-sm ${
                            hasEnergy 
                            ? 'bg-blue-900/40 border-blue-700/50 text-blue-400' 
                            : 'bg-red-900/40 border-red-700/50 text-red-500 animate-pulse'
                        }`}>
                            <Zap className="w-4 h-4" />
                            <span>Energy: -{requiredEnergy}</span>
                        </div>
                    </div>

                    <button 
                        onClick={startCrafting}
                        disabled={!canCraft}
                        className={`px-12 py-4 rounded-lg font-bold text-lg shadow-lg transition-all transform hover:-translate-y-1 flex items-center gap-3 border ${
                            canCraft 
                            ? selectedItem.craftingType === 'FORGE'
                                ? 'bg-amber-700 hover:bg-amber-600 text-amber-50 border-amber-500 hover:shadow-amber-900/50'
                                : 'bg-emerald-700 hover:bg-emerald-600 text-emerald-50 border-emerald-500 hover:shadow-emerald-900/50'
                            : 'bg-stone-800 text-stone-500 border-stone-700 cursor-not-allowed opacity-70'
                        }`}
                    >
                        {!isRequirementMet ? (
                            <>
                                <Lock className="w-6 h-6" />
                                Facility Required
                            </>
                        ) : !canEnterForge ? (
                            <>
                                <Flame className="w-6 h-6 text-red-500" />
                                Need Heat or Fuel
                            </>
                        ) : !hasEnergy ? (
                             <>
                                <Zap className="w-6 h-6 text-red-500" />
                                Need Energy
                            </>
