 * SHOP_CONFIG
 * 상점 방문객의 생성 주기, 대기 시간(인내심) 등 NPC 행동 로직을 정의합니다.
 * 플레이어가 상점을 열었을 때 발생하는 이벤트의 간격을 조절합니다.
 */
export const SHOP_CONFIG = {
    // 방문객 생성 주기 (밀리초)
    ARRIVAL: {
        MIN_INTERVAL_MS: 5000,      // 최소 대기 시간 (5초)
        VARIANCE_MS: 20000          // 추가 무작위 대기 시간 (0 ~ 20초)
        // 결과: 5초 ~ 25초 사이 랜덤하게 손님이 방문합니다.
    },
    // 손님 인내심 (밀리초)
    PATIENCE_MS: 45000,             // 45초 동안 판매하지 않으면 손님이 떠납니다.

    // 대기열 처리 (밀리초)
    QUEUE_PROCESS_DELAY_MS: 1000    // 카운터가 비었을 때 대기열의 다음 손님이 이동할 때까지의 시간
};

