        {isShopOpen && activeCustomer && (
            <DialogueBox 
                speaker={activeCustomer.mercenary.name}
                text={activeCustomer.request.dialogue}
                options={[
                    { 
                        label: `Sell (${activeCustomer.request.price} G)`, 
                        action: handleSell, 
                        variant: 'primary',
                        disabled: !hasItem()
