  | { type: 'REPAIR_WORK' }
  | { type: 'SLEEP' }        
  | { type: 'CONFIRM_SLEEP' } 
  | { type: 'TRIGGER_EVENT'; payload: GameEvent }
  | { type: 'CLOSE_EVENT' }
