            </div>
          </div>

          <div className="flex items-center space-x-1 md:space-x-2 bg-slate-800 px-2 md:px-3 py-1 md:py-1.5 rounded-lg border border-slate-700 min-w-[70px] md:min-w-[100px] justify-end">
