import React from 'react';
import { useGame } from '../../context/GameContext';
import { Hammer, Sword, Shield, Zap, Brain, Check, Star, ArrowUp, ArrowDown } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { EquipmentStats } from '../../models/Equipment';
import { EQUIPMENT_ITEMS } from '../../data/equipment';

const CraftingResultModal = () => {
    const { state, actions } = useGame();
    const item = state.lastCraftedItem;

    if (!item || !item.equipmentData) return null;

    const data = item.equipmentData;
    const recipe = EQUIPMENT_ITEMS.find(r => r.id === data.recipeId);
    const imageUrl = data.image ? getAssetUrl(data.image) : (data.recipeId ? getAssetUrl(`${data.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    const label = getQualityLabel(data.quality);
    const qColor = getQualityColor(data.quality);

    const renderStatItem = (icon: React.ReactNode, labelStr: string, statKey: keyof EquipmentStats, value: number) => {
        const baseValue = recipe?.baseStats?.[statKey] || 0;
        const diff = value - baseValue;

        let status: 'UP' | 'DOWN' | 'EQUAL' = 'EQUAL';
        if (diff > 0) status = 'UP';
        else if (diff < 0) status = 'DOWN';

        return (
            <div 
                className={`bg-stone-950/50 p-2 md:p-3 rounded-xl border transition-all hover:bg-stone-900 group cursor-help flex justify-between items-center ${
                    status === 'UP' ? 'border-amber-600/40 shadow-[inner_0_0_10px_rgba(245,158,11,0.1)]' : 
                    status === 'DOWN' ? 'border-red-900/40 shadow-[inner_0_0_10px_rgba(239,68,68,0.05)]' : 
                    'border-stone-800'
                }`}
            >
                <span className="text-[9px] md:text-[10px] text-stone-500 font-bold uppercase flex items-center gap-1.5 group-hover:text-stone-400">
                    {icon} {labelStr}
                </span>
                <div className="flex items-center gap-1.5">
                    <span className={`text-xs md:text-sm font-mono font-bold transition-colors ${
                        status === 'UP' ? 'text-amber-400' : 
                        status === 'DOWN' ? 'text-red-500' : 
                        'text-stone-200'
                    }`}>
                        {value}
                    </span>
                    {status === 'UP' && <ArrowUp className="w-2.5 h-2.5 md:w-3 md:h-3 text-amber-500 animate-bounce" />}
                    {status === 'DOWN' && <ArrowDown className="w-2.5 h-2.5 md:w-3 md:h-3 text-red-700 animate-pulse" />}
                </div>
            </div>
        );
    };

    return (
        <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-500 overflow-hidden">
            <div className="relative z-10 w-full max-w-md max-h-[95vh] bg-stone-900 border-2 border-amber-600 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-500">

                {/* Header - Compact for small screens */}
                <div className="bg-stone-850 p-4 md:p-6 border-b border-stone-800 flex flex-col items-center text-center relative overflow-hidden shrink-0">
                    <div className="absolute top-0 right-0 p-2 opacity-5 hidden md:block">
                         <Hammer className="w-20 h-20 text-stone-500" />
                    </div>
                    <div className={`w-16 h-16 md:w-24 md:h-24 bg-stone-900 rounded-full border-4 ${qColor.replace('text-', 'border-')} flex items-center justify-center mb-2 md:mb-4 shadow-2xl`}>
                        <img 
                            src={imageUrl} 
                            className="w-10 h-10 md:w-16 md:h-16 object-contain drop-shadow-lg" 
                            onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                        />
                        <span className="hidden text-3xl md:text-5xl">{item.icon || '📦'}</span>
                    </div>
                    <h2 className="text-xl md:text-2xl font-bold text-stone-200 font-serif tracking-wide truncate w-full">{data.name}</h2>
                    <div className={`flex items-center gap-2 mt-1 md:mt-2 px-3 py-0.5 md:py-1 rounded-full bg-stone-950 border border-stone-800 font-bold uppercase tracking-widest text-[9px] md:text-[10px] ${qColor}`}>
                        <Star className="w-2.5 h-2.5 md:w-3 md:h-3 fill-current" />
                        {label} Quality
                    </div>
                </div>

                {/* Content - Scrollable */}
                <div className="p-4 md:p-6 space-y-4 md:space-y-5 overflow-y-auto flex-1 custom-scrollbar">
                    <p className="text-stone-400 text-xs md:text-sm text-center italic leading-relaxed px-2">
                        "{item.description}"
                    </p>

                    <div className="grid grid-cols-2 gap-2 md:gap-3">
                        {renderStatItem(<Sword className="w-3 h-3" />, "P.Atk", "physicalAttack", data.stats.physicalAttack)}
                        {renderStatItem(<Shield className="w-3 h-3" />, "P.Def", "physicalDefense", data.stats.physicalDefense)}
                        {renderStatItem(<Zap className="w-3 h-3" />, "M.Atk", "magicalAttack", data.stats.magicalAttack)}
                        {renderStatItem(<Brain className="w-3 h-3" />, "M.Def", "magicalDefense", data.stats.magicalDefense)}
                    </div>

                    <div className="flex justify-between items-center text-xs border-t border-stone-800 pt-3 md:pt-4 px-2">
                        <span className="text-stone-500 uppercase font-bold tracking-tighter">Market Value</span>
                        <span className="text-amber-500 font-mono font-bold text-base md:text-lg">{data.price} G</span>
                    </div>
                </div>

                {/* Footer */}
                <div className="p-4 border-t border-stone-800 bg-stone-850 shrink-0">
                    <button 
                        onClick={actions.dismissCraftingResult}
                        className="w-full py-3 md:py-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all transform active:scale-95"
                    >
                        <Check className="w-5 h-5" />
                        Complete Forge
                    </button>
                </div>
            </div>
        </div>
    );
};

export default CraftingResultModal;

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../context/GameContext';
import { Mercenary } from '../../models/Mercenary';
import { EquipmentSlotType } from '../../types/inventory';
import { X, Sword, Shield, Shirt, Hand, Footprints, Crown, Sparkles, Heart, Activity, Star, Box, Zap, Brain, Target, User, Plus, Wind, FastForward, Crosshair, Minus, Check, RefreshCw, AlertCircle, ShieldAlert, ArrowUp, ArrowDown } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, PrimaryStats, mergePrimaryStats } from '../../models/Stats';
import { calculateCombatPower } from '../../utils/combatLogic';
import { InventoryItem } from '../../types/inventory';
import { Equipment } from '../../models/Equipment';

interface MercenaryDetailModalProps {
    mercenary: Mercenary | null;
    onClose: () => void;
    onUnequip: (mercId: string, slot: EquipmentSlotType) => void;
    isReadOnly?: boolean;
}

const StatDiff = ({ current, next, isPercent = false }: { current: number, next: number, isPercent?: boolean }) => {
    const diff = next - current;
    if (Math.abs(diff) < 0.01) return null;

    const isPositive = diff > 0;
    const color = isPositive ? 'text-emerald-400' : 'text-red-400';
    const Icon = isPositive ? ArrowUp : ArrowDown;

    return (
        <div className={`flex items-center gap-0.5 font-mono text-[10px] font-bold ${color} animate-in fade-in slide-in-from-left-1`}>
            <Icon className="w-3 h-3" />
            <span>{isPercent ? Math.abs(diff).toFixed(1) : Math.abs(Math.round(diff))}</span>
        </div>
    );
};

const MercenaryPaperDoll = ({ 
    mercenary, 
    baseCombatPower,
    nextCombatPower,
    showAffinityGain, 
    onUnequip, 
    onSlotClick,
    selectedSlot,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseCombatPower: number; 
    nextCombatPower: number;
    showAffinityGain: boolean; 
    onUnequip: (slot: EquipmentSlotType) => void; 
    onSlotClick: (slot: EquipmentSlotType | null) => void;
    selectedSlot: EquipmentSlotType | null;
    isReadOnly?: boolean;
}) => {
    const renderSlot = ({ slot, icon, style }: { slot: EquipmentSlotType; icon: React.ReactNode; style: string }) => {
        const equippedItem = mercenary.equipment[slot];
        const isSelected = selectedSlot === slot;

        let borderColor = isSelected ? 'border-amber-400' : 'border-stone-700';
        let bgColor = 'bg-stone-900/80';

        if (equippedItem) {
            switch (equippedItem.rarity) {
                case 'Common': borderColor = isSelected ? 'border-amber-400' : 'border-stone-500'; break;
                case 'Uncommon': borderColor = isSelected ? 'border-amber-400' : 'border-emerald-600'; break;
                case 'Rare': borderColor = isSelected ? 'border-amber-400' : 'border-blue-500'; break;
                case 'Epic': borderColor = isSelected ? 'border-amber-400' : 'border-purple-500'; break;
                case 'Legendary': borderColor = isSelected ? 'border-amber-400' : 'border-amber-500'; break;
            }
            bgColor = 'bg-stone-800';
        }

        let imageUrl = '';
        if (equippedItem) {
            imageUrl = equippedItem.image ? getAssetUrl(equippedItem.image) : (equippedItem.recipeId ? getAssetUrl(`${equippedItem.recipeId}.png`) : getAssetUrl(`${equippedItem.id.split('_')[0]}.png`));
        }

        return (
            <div 
                className={`absolute w-10 h-10 md:w-12 md:h-12 rounded-lg border-2 ${borderColor} ${bgColor} flex items-center justify-center shadow-lg transition-all z-20 group ${style} ${isSelected ? 'ring-2 ring-amber-500/50 scale-110' : ''} cursor-pointer`}
                onClick={() => onSlotClick(isSelected ? null : slot)}
            >
                {equippedItem ? (
                    <img 
                        src={imageUrl}
                        className="w-7 h-7 md:w-9 md:h-9 object-contain drop-shadow-md"
                        onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                    />
                ) : (
                    <div className="text-stone-600">{icon}</div>
                )}
                <div className="hidden text-xl">{equippedItem?.icon || '📦'}</div>
                {equippedItem && !isReadOnly && (
                    <button
                        onClick={(e) => { e.stopPropagation(); onUnequip(slot); }}
                        className="absolute -top-2 -right-2 bg-stone-900 rounded-full border border-stone-600 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-900 hover:border-red-500 text-stone-400 hover:text-red-200 z-30"
                    >
                        <X className="w-3 h-3" />
                    </button>
                )}
            </div>
        );
    };

    const cpDiff = nextCombatPower - baseCombatPower;

    return (
        <div className="w-full md:w-[40%] h-full relative bg-gradient-to-b from-stone-900 to-stone-950 border-r border-stone-800 flex flex-col items-center justify-center overflow-hidden group select-none">
            <div className="absolute top-4 left-4 md:top-8 md:left-8 z-30">
                <h2 className="text-2xl md:text-4xl font-black text-stone-200 font-serif tracking-tight drop-shadow-lg leading-none">{mercenary.name}</h2>
                <div className="flex items-center gap-3 mt-1 md:mt-2">
                    <span className="text-[10px] md:text-sm font-bold text-amber-500 uppercase tracking-widest bg-amber-950/30 px-2 py-0.5 rounded border border-amber-900/50">{mercenary.job}</span>
                    <div className={`flex items-center gap-1 text-[10px] md:text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-500'}`}>
                        <Heart className={`w-3 h-3 md:w-3.5 md:h-3.5 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
                        <span className="font-mono font-bold">{mercenary.affinity}</span>
                    </div>
                </div>
            </div>
            <div className="absolute top-4 right-4 md:top-8 md:right-8 z-30">
                <div className="flex flex-col items-end">
                    <span className="text-[8px] md:text-[10px] text-stone-500 uppercase font-bold tracking-wider">Combat Power</span>
                    <div className="flex flex-col items-end">
                        <div className="flex items-center gap-1 text-base md:text-xl font-mono font-bold text-stone-300">
                            <Star className="w-3.5 h-3.5 md:w-4 md:h-4 text-yellow-500 fill-yellow-500" />
                            {nextCombatPower}
                        </div>
                        {Math.abs(cpDiff) > 0 && (
                            <div className={`text-[10px] md:text-xs font-bold flex items-center gap-0.5 ${cpDiff > 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                                {cpDiff > 0 ? <Plus className="w-3 h-3" /> : <Minus className="w-3 h-3" />}
                                {Math.abs(cpDiff)}
                            </div>
                        )}
                    </div>
                </div>
            </div>
            <div className="relative w-full h-[85%] md:h-full flex items-center justify-center mt-8 md:mt-12">
                <div className="relative h-full w-full flex items-center justify-center">
                    <img 
                        src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')}
                        className="h-[90%] md:h-[80%] object-contain filter drop-shadow-[0_0_20px_rgba(0,0,0,0.8)]"
                    />
                </div>
                {renderSlot({ slot: "HEAD", icon: <Crown className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[10%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "BODY", icon: <Shirt className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[35%] left-1/2 -translate-x-1/2" })}
