            <div className="relative w-full max-w-2xl h-[80vh] max-h-[95vh] bg-stone-900 border-2 border-stone-700 rounded-xl shadow-2xl flex flex-col animate-in zoom-in-95 duration-200">

                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b border-stone-800 bg-stone-850 rounded-t-xl shrink-0">
                    <div className="flex items-center gap-3">
                        <div className="bg-stone-800 p-2 rounded-full border border-stone-700">
                            < BookOpen className="w-5 h-5 text-amber-500" />
                        </div>
                        <h2 className="text-xl font-bold text-stone-200 font-serif tracking-wide">Journal</h2>
                    </div>
                    <button 
                        onClick={actions.toggleJournal}
                        className="p-2 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Log Content - Scrollable */}
                <div className="flex-1 overflow-y-auto p-4 md:p-6 bg-stone-925 custom-scrollbar" ref={scrollRef}>
                    {state.logs.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-stone-600 italic opacity-60">
                            <Scroll className="w-12 h-12 mb-4" />
                            <p>No entries yet...</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {state.logs.map((log, i) => (
                                <div key={i} className="flex gap-4 group">
                                    <div className="flex flex-col items-center shrink-0">
                                        <div className="w-2 h-2 rounded-full bg-stone-700 group-first:bg-amber-500 mt-2"></div>
                                        {i !== state.logs.length - 1 && <div className="w-0.5 h-full bg-stone-800 my-1"></div>}
                                    </div>
                                    <div className="pb-2">
                                        <p className={`text-sm leading-relaxed ${i === 0 ? 'text-amber-100 font-medium' : 'text-stone-400'}`}>
                                            {log}
                                        </p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="p-3 border-t border-stone-800 bg-stone-850 rounded-b-xl text-center shrink-0">
                    <span className="text-xs text-stone-500 font-mono uppercase tracking-widest">Day {state.stats.day} • {state.stats.gold} Gold</span>
                </div>
            </div>
        </div>
    );
};

export default JournalModal;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../data/equipment';
import { EquipmentCategory, EquipmentItem } from '../../../types/index';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Shield, Sword, ChevronRight, Info, ChevronLeft, Lock, Check, X as XIcon, Box, Flame, ChevronDown, Heart, Star, Zap, Award, Wrench, X, ShoppingCart, Brain } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import { GAME_CONFIG } from '../../../config/game-config';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const { inventory, stats, isCrafting, craftingMastery, activeEvent, unlockedRecipes } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [hasPromptedFurnace, setHasPromptedFurnace] = useState(false);

  const [expandedSubCat, setExpandedSubCat] = useState<string | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const getInventoryCount = useCallback((id: string) => {
      return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const getResourceName = (id: string) => {
      const itemDef = Object.values(MATERIALS).find(i => i.id === id);
      return itemDef ? itemDef.name : id;
  };

  const getItemImageUrl = (item: EquipmentItem) => {
    if (item.image) return getAssetUrl(item.image);
    return getAssetUrl(`${item.id}.png`);
  };

  const GLOBAL_COOLING_RATE_PER_SEC = 5; 
  const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
  const coolingAmount = timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC;
  const currentResidualTemp = Math.max(0, (state.forgeTemperature || 0) - coolingAmount);

  const hasHeat = currentResidualTemp > 0;
  const charcoalCount = getInventoryCount('charcoal');
  const hasFuel = charcoalCount > 0;

  useEffect(() => {
    if (!hasFurnace && !hasPromptedFurnace && !activeEvent) {
        actions.triggerEvent({
            id: 'CUSTOMER_VISIT',
            title: "The Forge lies in Ruins",
            description: "Your journey as a blacksmith starts with a single spark. To begin forging weapons and armor, you must first install a Furnace from the market.",
            options: [
                { label: "Visit Market (500 G)", action: () => onNavigate('MARKET') },
                { label: "I'll look around first", action: () => {} }
            ]
        });
        setHasPromptedFurnace(true);
    }
  }, [hasFurnace, hasPromptedFurnace, activeEvent, actions, onNavigate]);

  const canEnterForge = useMemo(() => {
      if (!selectedItem) return false;
      if (selectedItem.craftingType === 'WORKBENCH') return true;
      return hasFuel || hasHeat;
  }, [selectedItem, hasFuel, hasHeat]);

  const requiredEnergy = useMemo(() => {
      if (!selectedItem) return GAME_CONFIG.ENERGY_COST.CRAFT;
      const count = craftingMastery[selectedItem.id] || 0;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) {
          return GAME_CONFIG.ENERGY_COST.CRAFT - MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
      }
      return GAME_CONFIG.ENERGY_COST.CRAFT;
  }, [selectedItem, craftingMastery]);

  const hasEnergy = stats.energy >= requiredEnergy;

  const canAffordResources = useCallback((item: EquipmentItem) => {
      return item.requirements.every(req => getInventoryCount(req.id) >= req.count);
  }, [getInventoryCount]);

  const visibleItems = useMemo(() => {
      return EQUIPMENT_ITEMS.filter(item => {
          if (item.id === 'sword_bronze_long_t1') {
              const isUnlocked = unlockedRecipes?.includes(item.id);
              if (!isUnlocked) return false;
          }
          if (item.tier > stats.tierLevel) return false;
          const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
          return subCatDef?.categoryId === activeCategory;
      });
  }, [activeCategory, stats.tierLevel, unlockedRecipes]);

  const favoriteItems = useMemo(() => {
      return visibleItems.filter(item => favorites.includes(item.id));
  }, [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
      const groups: Record<string, EquipmentItem[]> = {};
      visibleItems.forEach(item => {
          if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
          groups[item.subCategoryId].push(item);
      });
      return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
      return EQUIPMENT_SUBCATEGORIES.filter(sc => 
          sc.categoryId === activeCategory && groupedItems[sc.id] && groupedItems[sc.id].length > 0
      );
  }, [activeCategory, groupedItems]);

  useEffect(() => {
      if (favoriteItems.length > 0) {
          setExpandedSubCat('FAVORITES');
      } else if (visibleSubCats.length > 0) {
          setExpandedSubCat(visibleSubCats[0].id);
      } else {
          setExpandedSubCat(null);
      }
  }, [activeCategory, visibleSubCats, favoriteItems.length]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);   
  }, []);

  const toggleSubCategory = useCallback((subCatId: string) => {
      setExpandedSubCat(prev => (prev === subCatId ? null : subCatId));
  }, []);

  const toggleFavorite = useCallback((e: React.MouseEvent, itemId: string) => {
      e.stopPropagation(); 
      setFavorites(prev => prev.includes(itemId) ? prev.filter(id => id !== itemId) : [...prev, itemId]);
  }, []);

  const startCrafting = useCallback(() => {
      if (!selectedItem) return;
      actions.startCrafting(selectedItem);
      setIsPanelOpen(false); 
  }, [actions, selectedItem]);

  const cancelCrafting = useCallback(() => {
      if (selectedItem) actions.cancelCrafting(selectedItem);
      else actions.setCrafting(false); 
      setIsPanelOpen(true);
  }, [actions, selectedItem]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) actions.finishCrafting(selectedItem, score, bonus);
    setIsPanelOpen(true);
  }, [selectedItem, actions]);

  // ROBUST TOOLTIP POSITIONING
  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const updateTooltipPosition = (x: number, y: number) => {
      const TOOLTIP_WIDTH = 240;
      const TOOLTIP_HEIGHT = 160;
      const OFFSET = 20;

      let finalX = x + OFFSET;
      let finalY = y + OFFSET;

      // Boundary check for viewport
      const viewportW = window.innerWidth;
      const viewportH = window.innerHeight;

      if (finalX + TOOLTIP_WIDTH > viewportW) {
          finalX = x - TOOLTIP_WIDTH - OFFSET;
      }
      if (finalY + TOOLTIP_HEIGHT > viewportH) {
          finalY = y - TOOLTIP_HEIGHT - OFFSET;
      }

      // Safety clamp
      finalX = Math.max(10, Math.min(finalX, viewportW - TOOLTIP_WIDTH - 10));
      finalY = Math.max(10, Math.min(finalY, viewportH - TOOLTIP_HEIGHT - 10));

      setTooltipPos({ x: finalX, y: finalY });
  };

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  const renderItemCard = (item: EquipmentItem) => {
      const isSelected = selectedItem?.id === item.id;
      const isFav = favorites.includes(item.id);
      const count = inventory.filter(i => i.name === item.name).length;

      return (
        <div 
            key={item.id}
            onClick={() => setSelectedItem(item)}
            onMouseEnter={(e) => handleMouseEnter(item, e)}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            className={`relative flex flex-col items-center rounded-lg border transition-all cursor-pointer group text-left h-[115px] md:h-[130px] overflow-hidden ${
                isSelected 
                ? 'bg-amber-900/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' 
                : 'bg-stone-800 border-stone-700 hover:border-stone-500 hover:bg-stone-750'
            }`}
        >
            <div className="w-full flex justify-between items-start p-1.5 md:p-2 z-10">
                 <span className={`text-[8px] md:text-[10px] font-bold tracking-wider font-mono ${isSelected ? 'text-amber-400' : 'text-stone-600'}`}>T{item.tier}</span>
                 <button onClick={(e) => toggleFavorite(e, item.id)} className="p-1 rounded-full hover:bg-stone-700 transition-colors">
                    <Heart className={`w-3 h-3 md:w-3.5 md:h-3.5 ${isFav ? 'fill-red-500 text-red-500' : 'text-stone-600 hover:text-stone-400'}`} />
                 </button>
            </div>
            <div className="flex-1 flex items-center justify-center group-hover:scale-110 transition-transform -mt-2">
                <img src={getItemImageUrl(item)} className="w-8 h-8 md:w-10 md:h-10 object-contain drop-shadow-md" />
            </div>
            <div className="w-full text-center pb-1.5 px-1 flex flex-col items-center gap-0.5">
                <div className={`text-[10px] md:text-xs font-bold leading-tight truncate w-full ${isSelected ? 'text-amber-200' : 'text-stone-300'}`}>{item.name}</div>
                {count > 0 && (
                    <div className="inline-flex items-center gap-0.5 bg-stone-950/50 px-1.5 py-0.5 rounded text-[8px] font-mono text-stone-500 border border-stone-800/50">
                        <Box className="w-2 h-2" /> {count}
                    </div>
                )}
            </div>
        </div>
      );
  };

  const isRequirementMet = useMemo(() => {
      if (!selectedItem) return true;
      if (selectedItem.craftingType === 'FORGE') return hasFurnace;
      if (selectedItem.craftingType === 'WORKBENCH') return hasWorkbench;
      return true;
  }, [selectedItem, hasFurnace, hasWorkbench]);

  const content = useMemo(() => {
    const canCraft = selectedItem && canAffordResources(selectedItem) && canEnterForge && hasEnergy && isRequirementMet;
    return (
        <div className="relative h-full w-full bg-stone-950 overflow-hidden" style={{ backgroundImage: `url(${getAssetUrl('tile_forge.png')})`, backgroundRepeat: 'repeat', backgroundBlendMode: 'multiply' }}>

        {selectedItem && !isRequirementMet && (
            <div className="absolute inset-0 z-[60] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-stone-950/90 backdrop-blur-md animate-in fade-in duration-700"></div>
                <div className="relative z-10 p-6 md:p-8 max-w-md w-full bg-stone-900 border-2 border-stone-800 rounded-2xl shadow-2xl flex flex-col items-center text-center animate-in zoom-in-95 duration-500 max-h-[90vh] overflow-y-auto">
                    <button onClick={() => setSelectedItem(null)} className="absolute top-4 right-4 p-2 text-stone-500 hover:text-stone-300 transition-colors"><X className="w-5 h-5" /></button>
                    <div className="w-16 h-16 md:w-20 md:h-20 bg-stone-800 rounded-full flex items-center justify-center mb-4 md:mb-6 border border-stone-700 shrink-0">{selectedItem.craftingType === 'FORGE' ? <Flame className="w-8 h-8 md:w-10 md:h-10 text-stone-600" /> : <Wrench className="w-8 h-8 md:w-10 md:h-10 text-stone-600" />}</div>
                    <h2 className="text-xl md:text-2xl font-bold text-stone-300 font-serif mb-2">{selectedItem.craftingType === 'FORGE' ? 'Furnace Required' : 'Workbench Required'}</h2>
                    <p className="text-sm md:text-base text-stone-500 mb-6 md:mb-8 leading-relaxed">Crafting <span className="text-amber-500 font-bold">{selectedItem.name}</span> requires a functional {selectedItem.craftingType === 'FORGE' ? 'furnace' : 'workbench'}. Visit the market to purchase one.</p>
                    <button onClick={() => onNavigate('MARKET')} className="w-full py-3 md:py-4 bg-amber-700 hover:bg-amber-600 text-amber-50 font-bold rounded-xl shadow-lg hover:shadow-amber-900/40 transition-all flex items-center justify-center gap-2 group shrink-0">Go to Market <ChevronRight className="w-4 h-4 md:w-5 md:h-5 group-hover:translate-x-1 transition-transform" /></button>
                </div>
            </div>
        )}

        <div className={`absolute inset-0 z-0 flex w-full h-full ${((selectedItem && !isRequirementMet) || !hasFurnace) ? 'blur-sm pointer-events-none' : ''}`}>
            <div className={`h-full relative flex flex-col transition-all duration-500 ease-in-out ${isPanelOpen ? 'w-[55%] md:w-[60%]' : 'w-full'}`}>
                <div className="w-full h-full flex flex-col items-center justify-center p-4 md:p-8 bg-stone-925/40 relative overflow-hidden">
                    <div className="absolute inset-0 opacity-10 pointer-events-none flex items-center justify-center">{selectedItem?.craftingType === 'FORGE' ? <Hammer className="w-64 h-64 md:w-96 md:h-96 text-stone-500" /> : <Wrench className="w-64 h-64 md:w-96 md:h-96 text-stone-500" />}</div>
                    {selectedItem ? (
                        <div className="z-10 flex flex-col items-center animate-in fade-in zoom-in duration-300 w-full max-w-lg">
                            <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-full border-4 flex items-center justify-center transition-all duration-500 ${selectedItem.craftingType === 'FORGE' ? 'border-amber-600 shadow-[0_0_40px_rgba(217,119,6,0.2)]' : 'border-emerald-600 shadow-[0_0_40px_rgba(16,185,129,0.2)]'} mb-4 md:mb-8`}>
                                <img src={getItemImageUrl(selectedItem)} className="w-12 h-12 md:w-32 md:h-32 object-contain drop-shadow-xl" />
                            </div>
                            <h2 className="text-xl md:text-3xl font-bold text-amber-500 mb-1 md:mb-2 font-serif tracking-wide">{selectedItem.name}</h2>
                            <p className="text-stone-400 text-center max-w-md mb-4 md:mb-6 italic text-[10px] md:text-base leading-snug">"{selectedItem.description}"</p>
                            <button onClick={startCrafting} disabled={!canCraft} className={`px-8 md:px-12 py-3 md:py-4 rounded-lg font-bold text-sm md:text-lg shadow-lg transition-all transform hover:-translate-y-1 flex items-center gap-2 md:gap-3 border ${canCraft ? (selectedItem.craftingType === 'FORGE' ? 'bg-amber-700 hover:bg-amber-600 border-amber-500' : 'bg-emerald-700 hover:bg-emerald-600 border-emerald-500') : 'bg-stone-800 text-stone-500 border-stone-700 cursor-not-allowed opacity-70'}`}>
                                {selectedItem.craftingType === 'FORGE' ? <Hammer className="w-5 h-5 md:w-6 md:h-6" /> : <Wrench className="w-5 h-5 md:w-6 md:h-6" />}
                                <span>{selectedItem.craftingType === 'FORGE' ? 'Start Forging' : 'Start Crafting'}</span>
                            </button>
                        </div>
                    ) : (
                        <div className="z-10 flex flex-col items-center text-stone-600">
                            <div className="w-16 h-16 md:w-24 md:h-24 rounded-full border-4 border-dashed border-stone-700 flex items-center justify-center mb-4"><Hammer className="w-6 h-6 md:w-10 md:h-10" /></div>
                            <h3 className="text-base md:text-xl font-bold text-stone-500 drop-shadow-md">The Anvil is Cold</h3>
                            <p className="text-[10px] md:text-sm mt-1 md:mt-2 font-medium">Select a recipe from the right to begin.</p>
                        </div>
                    )}
                </div>
            </div>

            <div className={`h-full bg-stone-900/95 border-l border-stone-800 shadow-2xl flex flex-col transition-all duration-500 ease-in-out relative backdrop-blur-sm ${isPanelOpen ? 'w-[45%] md:w-[40%] translate-x-0' : 'w-0 translate-x-full border-none'}`}>
                <button onClick={() => setIsPanelOpen(!isPanelOpen)} disabled={isCrafting} className={`absolute top-1/2 -left-6 w-6 h-20 md:h-24 -translate-y-1/2 bg-stone-800 border-y border-l border-stone-600 rounded-l-lg flex items-center justify-center hover:bg-stone-700 hover:text-amber-400 transition-colors z-20 ${isCrafting ? 'cursor-not-allowed opacity-50' : 'cursor-pointer'}`}>
                    {isCrafting ? <Lock className="w-3.5 h-3.5 text-stone-500" /> : isPanelOpen ? <ChevronRight className="w-4 h-4 text-stone-400" /> : <ChevronLeft className="w-4 h-4 text-amber-500 animate-pulse" />}
                </button>
                <div className="w-full h-full flex flex-col">
                    <div className="flex border-b border-stone-800 shrink-0">
                        <button onClick={() => handleCategoryChange('WEAPON')} className={`flex-1 py-3 md:py-4 text-center font-bold tracking-wider transition-colors flex items-center justify-center gap-1.5 md:gap-2 text-[10px] md:text-xs ${activeCategory === 'WEAPON' ? 'bg-stone-800 text-amber-500 border-b-2 border-amber-500' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/50'}`}><Sword className="w-3 h-3 md:w-4 md:h-4" /> WEAPONS</button>
                        <button onClick={() => handleCategoryChange('ARMOR')} className={`flex-1 py-3 md:py-4 text-center font-bold tracking-wider transition-colors flex items-center justify-center gap-1.5 md:gap-2 text-[10px] md:text-xs ${activeCategory === 'ARMOR' ? 'bg-stone-800 text-amber-500 border-b-2 border-amber-500' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/50'}`}><Shield className="w-3 h-3 md:w-4 md:h-4" /> ARMOR</button>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2 md:p-3 space-y-2">
                        {visibleSubCats.map(subCat => {
                            const isExpanded = expandedSubCat === subCat.id;
                            const items = groupedItems[subCat.id] || [];
                            return (
                                <div key={subCat.id} className="border border-stone-800 rounded-lg overflow-hidden">
                                    <button onClick={() => toggleSubCategory(subCat.id)} className="w-full bg-stone-800 p-2.5 md:p-3 flex items-center justify-between hover:bg-stone-750 transition-colors"><div className="flex items-center gap-1.5 md:gap-2">{isExpanded ? <ChevronDown className="w-3.5 h-3.5 md:w-4 md:h-4 text-amber-500" /> : <ChevronRight className="w-3.5 h-3.5 md:w-4 md:h-4 text-stone-500" />}<span className={`font-bold text-xs md:text-sm truncate ${isExpanded ? 'text-amber-100' : 'text-stone-400'}`}>{subCat.name}</span></div><span className="text-[10px] bg-stone-900 px-1.5 py-0.5 rounded text-stone-500 font-mono">{items.length}</span></button>
                                    {isExpanded && <div className="bg-stone-900/50 p-1.5 md:p-2 grid grid-cols-2 gap-1.5 md:gap-2 animate-in slide-in-from-top-2 duration-200">{items.map(item => renderItemCard(item))}</div>}
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        </div>

        {isCrafting && selectedItem && (
            <div className="absolute inset-0 z-50 animate-in fade-in zoom-in-95 duration-300 bg-stone-950">
                {selectedItem.craftingType === 'FORGE' ? <SmithingMinigame difficulty={selectedItem.tier} onComplete={handleMinigameComplete} onClose={cancelCrafting} /> : <WorkbenchMinigame difficulty={selectedItem.tier} onComplete={handleMinigameComplete} onClose={cancelCrafting} />}
            </div>
        )}

        {hoveredItem && (
            <div 
                className="fixed z-[60] pointer-events-none w-56 md:w-64 bg-stone-950/95 border border-stone-700 rounded-lg shadow-2xl backdrop-blur-sm p-3 md:p-4 animate-in fade-in duration-150" 
                style={{ top: tooltipPos.y, left: tooltipPos.x }}
            >
                <h4 className="font-bold text-stone-200 border-b border-stone-800 pb-2 mb-2 flex justify-between items-center">
                    <span className="text-[10px] md:text-xs">Requirements</span>
                    <span className="text-[9px] md:text-[10px] font-normal text-stone-500 uppercase">Tier {hoveredItem.tier}</span>
                </h4>
                <div className="space-y-1.5">
                    {hoveredItem.requirements.map((req, idx) => {
                        const currentCount = getInventoryCount(req.id);
                        const hasEnough = currentCount >= req.count;
                        return (
                            <div key={idx} className="flex justify-between items-center text-[10px] md:text-xs">
                                <span className="text-stone-400 truncate mr-2">{getResourceName(req.id)}</span>
                                <div className={`flex items-center gap-1 font-mono ${hasEnough ? 'text-emerald-400' : 'text-red-400'}`}>
                                    <span>{currentCount}/{req.count}</span>
                                    {hasEnough ? <Check className="w-2.5 h-2.5" /> : <XIcon className="w-2.5 h-2.5" />}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        )}
        </div>
    );
  }, [activeCategory, selectedItem, isPanelOpen, isCrafting, hoveredItem, tooltipPos, inventory, hasFurnace, hasWorkbench, canEnterForge, hasHeat, charcoalCount, hasEnergy, requiredEnergy, stats.tierLevel, expandedSubCat, favorites, favoriteItems, craftingMastery, isRequirementMet, handleCategoryChange, startCrafting, cancelCrafting, handleMinigameComplete, toggleSubCategory, toggleFavorite, handleMouseEnter, handleMouseMove, handleMouseLeave, canAffordResources, getInventoryCount, onNavigate, groupedItems, visibleSubCats, hasPromptedFurnace, activeEvent, unlockedRecipes]);
  return content;
};

export default ForgeTab;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  add!: Phaser.GameObjects.GameObjectFactory;
  scale!: Phaser.Scale.ScaleManager;
  tweens!: Phaser.Tweens.TweenManager;
  cameras!: Phaser.Cameras.Scene2D.CameraManager;
  input!: Phaser.Input.InputPlugin;
  load!: Phaser.Loader.LoaderPlugin;
  time!: Phaser.Time.Clock;
  textures!: Phaser.Textures.TextureManager;
  anims!: Phaser.Animations.AnimationManager;
  make!: Phaser.GameObjects.GameObjectCreator;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 40,
    imageOffsetX: 0,
    imageOffsetY: 30,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private lastStage: number = -1;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;
  private startRadius: number = 200;
  private targetRadius: number = 50;
  private currentRadius: number = 200;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;
  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;
  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));

    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), {
      frameWidth: 298,
      frameHeight: 188,
    });
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    if (!this.textures.exists('white')) {
        const g = this.make.graphics({ x: 0, y: 0 });
        g.fillStyle(0xffffff, 1);
        g.fillRect(0, 0, 2, 2);
        g.generateTexture('white', 2, 2);
        g.destroy();
    }

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.backgroundTile = this.add.tileSprite(0, 0, this.scale.width, this.scale.height, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.bgOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);
    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.flashOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xffaa00, 0).setOrigin(0).setDepth(100);

    this.handleResize();
    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c))) {
        this.pumpBellows();
        return;
      }
      if (objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c))) {
        this.requestHeatUp();
        return;
      }
      if (!this.isPlaying) { this.handleInput(pointer); return; }
      if (!this.isPointerInHitArea(pointer.worldX, pointer.worldY)) { this.handleMiss(); return; }
      if (Phaser.Math.Distance.Between(pointer.worldX, pointer.worldY, this.hitX, this.hitY) > this.currentRadius + 4) { this.handleMiss(); return; }
      this.handleInput(pointer);
    }, this);
    this.scale.on('resize', this.handleResize, this);

    this.updateProgressBar();
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 20, 0.1, 12, 0xeab308).setOrigin(0, 0.5);
    // FIX: Set progBg origin to 0 to align with progressBar
    const progBg = this.add.rectangle(0, 20, 200, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.uiContainer.add([progBg, this.progressBar]);

    this.qualityText = this.add.text(0, 40, 'PRISTINE', { fontFamily: 'monospace', fontSize: '14px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add(this.qualityText);

    this.tempBar = this.add.rectangle(0, 0, 14, 180, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);

    this.uiContainer.add([
      this.add.rectangle(0, 0, 24, 190, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'), 
      this.add.rectangle(0, 0, 18, 180, 0x0c0a09).setName('tempBg'), 
      this.tempBar, 
      this.tempValueText
    ]);

    this.createBellows();
    this.createHeatUpButton();

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '32px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '20px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);

    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.25);
    const txt = this.add.text(0, 18, 'PUMP', { fontSize: '9px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });
    this.uiContainer.add(this.bellowsContainer);
  }

  private createHeatUpButton() {
    this.heatUpBtnContainer = this.add.container(0, 0);
    const bg = this.add.rectangle(0, 0, 70, 50, 0x1c1917).setStrokeStyle(2, 0x57534e).setName('btnBg');
    const icon = this.add.text(0, -8, '🔥', { fontSize: '14px' }).setOrigin(0.5).setName('btnIcon');
    const label = this.add.text(0, 8, 'HEAT UP', { fontSize: '9px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 18, `x${this.charcoalCount}`, { fontSize: '10px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([bg, icon, label, countTxt]);
    this.heatUpBtnContainer.setInteractive(new Phaser.Geom.Rectangle(-35, -25, 70, 50), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.heatUpBtnContainer);
    this.refreshHeatUpButton();
  }

  private refreshHeatUpButton() {
    if (!this.heatUpBtnContainer) return;
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    const icon = this.heatUpBtnContainer.getByName('btnIcon') as Phaser.GameObjects.Text;
    countTxt.setText(`x${this.charcoalCount}`);
    if (this.charcoalCount > 0) { bg.setStrokeStyle(2, 0xea580c); countTxt.setColor('#a8a29e'); icon.setAlpha(1); } 
    else { bg.setStrokeStyle(2, 0x292524); countTxt.setColor('#44403c'); icon.setAlpha(0.3); }
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.bellowsSprite.play('bellows_pump');
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (!this.isPlaying && !this.isReadyToStart) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      if (this.onHeatUpRequest) this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  private handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
    const h = this.scale.height;
    const w = this.scale.width;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const isCompact = h < 450;
    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);

    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = w * (isCompact ? 1.0 : 1.3);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.45; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;
    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.scale.width;
    const h = this.scale.height;

    // Top Bar (Progress)
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = isCompact ? 150 : 200;
    // FIX: Set positions relative to top center
    progBg.setPosition(this.centerX - (progWidth / 2), 20).setSize(progWidth, 16);
    this.progressBar.setPosition(this.centerX - (progWidth / 2), 20);
    this.qualityText.setPosition(this.centerX, 45);

    // Right Side Stack (Temperature & Controls)
    const sideX = w - (isCompact ? 35 : 50);
    const sideBaseY = isCompact ? 90 : this.centerY - 80;

    const barHeight = isCompact ? 100 : 180;
    const tempFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tempBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;

    tempFrame.setPosition(sideX, sideBaseY).setSize(24, barHeight + 10);
    tempBg.setPosition(sideX, sideBaseY).setSize(18, barHeight);

    this.tempBar.setPosition(sideX, sideBaseY + (barHeight / 2)).setSize(14, barHeight);
    this.tempValueText.setPosition(sideX, sideBaseY - (barHeight / 2) - 15).setFontSize(isCompact ? '11px' : '14px');

    const controlGap = isCompact ? 50 : 65;
    this.bellowsContainer.setPosition(sideX, sideBaseY + (barHeight / 2) + 40).setScale(isCompact ? 0.7 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideBaseY + (barHeight / 2) + 40 + controlGap).setScale(isCompact ? 0.7 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180));
    this.comboText.setPosition(this.centerX, this.centerY - (isCompact ? 140 : 240));
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { this.isPlaying = true; this.infoText.setVisible(false); this.resetRing(); this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 }); } 
      else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); return; }
    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;
    if (diff < 15) {
      this.score += Math.ceil(8 * eff); this.combo++; this.perfectCount++;
      if (this.perfectCount >= 6) { this.currentQuality += 1; this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, swingX, swingY - 40); }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', swingX, swingY); 
      this.showFeedback('PERFECT!', 0xffb300, 1.3, swingX, swingY); this.cameras.main.shake(150, 0.02);
    } else if (diff < 45) {
      this.score += Math.ceil(5 * eff); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', swingX, swingY); this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
    } else { this.handleMiss(swingX, swingY); }
    this.updateProgressBar(); if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01); this.showFeedback('MISS', 0xef4444, 1.1, x, y); this.updateProgressBar(); this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) { this.isReadyToStart = false; this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6'); }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    // FIX: Dynamic Temperature Bar Color
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

    let barColor = 0xeab308; // Default Yellow
    if (ratio < 0.4) {
      // Interpolate Blue to Yellow
      const c = Phaser.Display.Color.Interpolate.ColorWithColor(
        new Phaser.Display.Color(59, 130, 246), // Blue
        new Phaser.Display.Color(234, 179, 8),  // Yellow
        40, ratio * 100
      );
      barColor = Phaser.Display.Color.GetColor(c.r, c.g, c.b);
    } else if (ratio > 0.7) {
      // Interpolate Yellow to Red
      const c = Phaser.Display.Color.Interpolate.ColorWithColor(
        new Phaser.Display.Color(234, 179, 8),  // Yellow
        new Phaser.Display.Color(239, 68, 68),  // Red
        30, (ratio - 0.7) * 100
      );
      barColor = Phaser.Display.Color.GetColor(c.r, c.g, c.b);
    }
    this.tempBar.setFillStyle(barColor);

    const interp = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(63, 63, 70), new Phaser.Display.Color(253, 230, 138), 100, ratio * 100);
    const color = Phaser.Display.Color.GetColor(interp.r, interp.g, interp.b);
    this.bladeFallbackRect.setFillStyle(color, 1); if (this.bladeImage) this.bladeImage.setTint(color);
    const stage = Math.min(5, Math.floor(Phaser.Math.Clamp(this.score / this.targetScore, 0, 1) * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD'; else if (this.temperature > 75) this.currentTempStage = 'AURA'; else if (this.temperature > 40) this.currentTempStage = 'HOT'; else if (this.temperature > 15) this.currentTempStage = 'WARM'; else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) { this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5); this.bladeContainer.add(this.bladeImage); } else this.bladeImage.setTexture(key);
      this.bladeImage.setVisible(true); this.bladeFallbackRect.setVisible(true).setAlpha(0.15);
      if (this.lastStage !== -1) { this.createOmniBurst(50, 0xffcc00, 2.0, 'spark_perfect', this.bladeContainer.x, this.bladeContainer.y); this.flashOverlay.setFillStyle(0xffcc00, 1).setAlpha(0.3); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 250, ease: 'Quad.easeOut' }); this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true, ease: 'Quad.easeOut' }); }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta; const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5); this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) { this.combo = 0; this.resetRing(); }
  }

  private resetRing() {
    if (this.temperature <= 0) { this.isPlaying = false; this.isReadyToStart = false; this.targetRing.clear(); this.approachRing.clear(); this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6'); return; }
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.3, w * 0.3); const v = Phaser.Math.Between(-h * 0.2, h * 0.2);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad)); this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const maxWidth = progBg.width;
    const progressWidth = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * maxWidth, 0, maxWidth));
    this.progressBar.width = progressWidth; 
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private createOmniBurst(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 1000, speed: { min: 150 * scale, max: 400 * scale }, angle: { min: 0, max: 360 }, scale: { start: 0.7, end: 0 }, gravityY: 300, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX; const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 100, text, { fontFamily: 'Arial', fontSize: '24px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 140, alpha: 1, scale: scale, duration: 200, hold: 300, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, scale: { from: 1.3, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  add!: Phaser.GameObjects.GameObjectFactory;
  scale!: Phaser.Scale.ScaleManager;
  tweens!: Phaser.Tweens.TweenManager;
  cameras!: Phaser.Cameras.Scene2D.CameraManager;
  input!: Phaser.Input.InputPlugin;
  load!: Phaser.Loader.LoaderPlugin;
  time!: Phaser.Time.Clock;
  textures!: Phaser.Textures.TextureManager;
  anims!: Phaser.Animations.AnimationManager;
  make!: Phaser.GameObjects.GameObjectCreator;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 40,
    imageOffsetY: 30,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private lastStage: number = -1;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  // DYNAMIC RADIUS PROPERTIES
  private startRadius: number = 180;
  private targetRadius: number = 45;

  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;
  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;
  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    if (!this.textures.exists('white')) {
        const g = this.make.graphics({ x: 0, y: 0 });
        g.fillStyle(0xffffff, 1).fillRect(0, 0, 2, 2).generateTexture('white', 2, 2).destroy();
    }

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, this.scale.width, this.scale.height, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.bgOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.flashOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xffaa00, 0).setOrigin(0).setDepth(100);

    this.handleResize();
    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c))) { this.pumpBellows(); return; }
      if (objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c))) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleInput(pointer); return; }
      if (!this.isPointerInHitArea(pointer.worldX, pointer.worldY)) { this.handleMiss(); return; }
      if (Phaser.Math.Distance.Between(pointer.worldX, pointer.worldY, this.hitX, this.hitY) > this.currentRadius + 4) { this.handleMiss(); return; }
      this.handleInput(pointer);
    }, this);
    this.scale.on('resize', this.handleResize, this);

    this.updateProgressBar();
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 20, 0.1, 12, 0xeab308).setOrigin(0, 0.5);
    // ALIGNMENT FIX: origin(0, 0.5) for both frame and bar
    const progBg = this.add.rectangle(0, 20, 200, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.uiContainer.add([progBg, this.progressBar]);

    this.qualityText = this.add.text(0, 40, 'PRISTINE', { fontFamily: 'monospace', fontSize: '14px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add(this.qualityText);

    this.tempBar = this.add.rectangle(0, 0, 14, 180, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);

    this.uiContainer.add([
      this.add.rectangle(0, 0, 24, 190, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'), 
      this.add.rectangle(0, 0, 18, 180, 0x0c0a09).setName('tempBg'), 
      this.tempBar, 
      this.tempValueText
    ]);

    this.createBellows();
    this.createHeatUpButton();

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '32px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '20px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.25);
    const txt = this.add.text(0, 18, 'PUMP', { fontSize: '9px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });
    this.uiContainer.add(this.bellowsContainer);
  }

  private createHeatUpButton() {
    this.heatUpBtnContainer = this.add.container(0, 0);
    const bg = this.add.rectangle(0, 0, 70, 50, 0x1c1917).setStrokeStyle(2, 0x57534e).setName('btnBg');
    const icon = this.add.text(0, -8, '🔥', { fontSize: '14px' }).setOrigin(0.5).setName('btnIcon');
    const label = this.add.text(0, 8, 'HEAT UP', { fontSize: '9px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 18, `x${this.charcoalCount}`, { fontSize: '10px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([bg, icon, label, countTxt]);
    this.heatUpBtnContainer.setInteractive(new Phaser.Geom.Rectangle(-35, -25, 70, 50), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.heatUpBtnContainer);
    this.refreshHeatUpButton();
  }

  private refreshHeatUpButton() {
    if (!this.heatUpBtnContainer) return;
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    const icon = this.heatUpBtnContainer.getByName('btnIcon') as Phaser.GameObjects.Text;
    countTxt.setText(`x${this.charcoalCount}`);
    if (this.charcoalCount > 0) { bg.setStrokeStyle(2, 0xea580c); countTxt.setColor('#a8a29e'); icon.setAlpha(1); } 
    else { bg.setStrokeStyle(2, 0x292524); countTxt.setColor('#44403c'); icon.setAlpha(0.3); }
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.bellowsSprite.play('bellows_pump');
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (!this.isPlaying && !this.isReadyToStart) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      if (this.onHeatUpRequest) this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  private handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
    const h = this.scale.height;
    const w = this.scale.width;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const isCompact = h < 450;
    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);

    // DYNAMIC RADIUS BASED ON HEIGHT
    this.startRadius = Phaser.Math.Clamp(h * 0.25, 80, 200);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = w * (isCompact ? 1.0 : 1.3);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.45; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;
    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.scale.width;
    const h = this.scale.height;

    // Top Bar (Progress) Aligned to Center Top
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = isCompact ? 150 : 200;
    const startX = this.centerX - (progWidth / 2);
    progBg.setPosition(startX, 20).setSize(progWidth, 16);
    this.progressBar.setPosition(startX, 20);
    this.qualityText.setPosition(this.centerX, 45);

    // Side UI (Temperature Stack)
    const sideX = w - (isCompact ? 35 : 50);
    const sideBaseY = isCompact ? 90 : this.centerY - 80;
    const barHeight = isCompact ? 100 : 180;

    const tempFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tempBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tempFrame.setPosition(sideX, sideBaseY).setSize(24, barHeight + 10);
    tempBg.setPosition(sideX, sideBaseY).setSize(18, barHeight);

    this.tempBar.setPosition(sideX, sideBaseY + (barHeight / 2)).setSize(14, barHeight);
    this.tempValueText.setPosition(sideX, sideBaseY - (barHeight / 2) - 15).setFontSize(isCompact ? '11px' : '14px');

    const controlGap = isCompact ? 50 : 65;
    this.bellowsContainer.setPosition(sideX, sideBaseY + (barHeight / 2) + 40).setScale(isCompact ? 0.7 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideBaseY + (barHeight / 2) + 40 + controlGap).setScale(isCompact ? 0.7 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180));
    this.comboText.setPosition(this.centerX, this.centerY - (isCompact ? 140 : 240));
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { this.isPlaying = true; this.infoText.setVisible(false); this.resetRing(); this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 }); } 
      else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    // SCALED TOLERANCE
    const tolerancePerfect = this.targetRadius * 0.35;
    const toleranceGood = this.targetRadius * 0.95;

    if (diff < tolerancePerfect) {
      this.score += Math.ceil(8 * eff); this.combo++; this.perfectCount++;
      if (this.perfectCount >= 6) { this.currentQuality += 1; this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, swingX, swingY - 40); }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', swingX, swingY); 
      this.showFeedback('PERFECT!', 0xffb300, 1.3, swingX, swingY); this.cameras.main.shake(150, 0.02);
    } else if (diff < toleranceGood) {
      this.score += Math.ceil(5 * eff); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', swingX, swingY); this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
    } else { this.handleMiss(swingX, swingY); }
    this.updateProgressBar(); if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01); this.showFeedback('MISS', 0xef4444, 1.1, x, y); this.updateProgressBar(); this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) { this.isReadyToStart = false; this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6'); }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    // DYNAMIC COLOR INTERPOLATION
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

    let barColor = 0xeab308; // Base Yellow
    if (ratio < 0.4) {
      const c = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(59, 130, 246), new Phaser.Display.Color(234, 179, 8), 40, ratio * 100);
      barColor = Phaser.Display.Color.GetColor(c.r, c.g, c.b);
    } else if (ratio > 0.7) {
      const c = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(234, 179, 8), new Phaser.Display.Color(239, 68, 68), 30, (ratio - 0.7) * 100);
      barColor = Phaser.Display.Color.GetColor(c.r, c.g, c.b);
    }
    this.tempBar.setFillStyle(barColor);

    const interp = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(63, 63, 70), new Phaser.Display.Color(253, 230, 138), 100, ratio * 100);
    const color = Phaser.Display.Color.GetColor(interp.r, interp.g, interp.b);
    this.bladeFallbackRect.setFillStyle(color, 1); if (this.bladeImage) this.bladeImage.setTint(color);

    const stage = Math.min(5, Math.floor(Phaser.Math.Clamp(this.score / this.targetScore, 0, 1) * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD'; else if (this.temperature > 75) this.currentTempStage = 'AURA'; else if (this.temperature > 40) this.currentTempStage = 'HOT'; else if (this.temperature > 15) this.currentTempStage = 'WARM'; else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) { this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5); this.bladeContainer.add(this.bladeImage); } else this.bladeImage.setTexture(key);
      this.bladeImage.setVisible(true); this.bladeFallbackRect.setVisible(true).setAlpha(0.15);
      if (this.lastStage !== -1) { this.createOmniBurst(50, 0xffcc00, 2.0, 'spark_perfect', this.bladeContainer.x, this.bladeContainer.y); this.flashOverlay.setFillStyle(0xffcc00, 1).setAlpha(0.3); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 250 }); this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true }); }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta; const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5); this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) { this.combo = 0; this.resetRing(); }
  }

  private resetRing() {
    if (this.temperature <= 0) { this.isPlaying = false; this.isReadyToStart = false; this.targetRing.clear(); this.approachRing.clear(); this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6'); return; }
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.3, w * 0.3); const v = Phaser.Math.Between(-h * 0.2, h * 0.2);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad)); this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const maxWidth = progBg.width;
    const progressWidth = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * maxWidth, 0, maxWidth));
    this.progressBar.width = progressWidth; 
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private createOmniBurst(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 1000, speed: { min: 150 * scale, max: 400 * scale }, angle: { min: 0, max: 360 }, scale: { start: 0.7, end: 0 }, gravityY: 300, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX; const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 100, text, { fontFamily: 'Arial', fontSize: '24px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 140, alpha: 1, scale: scale, duration: 200, hold: 300, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, scale: { from: 1.3, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  public getTemperature() { return this.temperature; }
}

