const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary,
    isReadOnly
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
    isReadOnly?: boolean;
}) => {
    const totalMercStats = useMemo(() => mergePrimaryStats(mercenary.stats, mercenary.allocatedStats), [mercenary]);

    const displayInventory = useMemo(() => {
        let items = selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
        return items;
    }, [inventory, selectedSlotFilter]);

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    return (
        <div className="bg-stone-950 p-2 md:p-4 flex-1 flex flex-col min-h-0">
            <div className="flex justify-between items-center mb-2 md:mb-3 shrink-0 px-1">
                <h3 className="text-[8px] md:text-[10px] font-bold text-stone-400 uppercase tracking-wider flex items-center gap-1.5 md:gap-2">
                    <Box className="w-3 h-3 md:w-4 md:h-4 text-amber-600" /> 
                    <span className="truncate">{selectedSlotFilter ? `${selectedSlotFilter.replace('_', ' ')}` : 'Storage'}</span>
                </h3>
                <span className="text-[8px] md:text-[10px] text-stone-600 font-mono">{displayInventory.length} Items</span>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar pr-1">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center border-2 border-dashed border-stone-800 rounded-lg text-stone-600 text-[10px] md:text-sm italic p-4 text-center">
                        <Box className="w-6 h-6 md:w-8 md:h-8 opacity-10 mb-2" />
                        <p>{selectedSlotFilter ? 'No matches.' : 'Empty.'}</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 gap-1.5 md:gap-2 content-start">
                        {displayInventory.map(item => {
                            if (!item.equipmentData) return null;
                            const isSelected = selectedItemId === item.id;
                            const reqs = item.equipmentData.equipRequirements || {};

                            const failedStats = Object.entries(reqs).filter(([stat, val]) => 
                                totalMercStats[stat as keyof PrimaryStats] < (val as number)
                            );
                            const canEquip = failedStats.length === 0;

                            const label = getQualityLabel(item.equipmentData.quality);
                            const qColor = getQualityColor(item.equipmentData.quality);
                            let imageUrl = item.equipmentData.image ? getAssetUrl(item.equipmentData.image) : (item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

                            return (
                                <div 
                                    key={item.id}
                                    onClick={() => !isSelected && onSelect(item.id)}
                                    className={`flex flex-col gap-1 p-1.5 md:p-3 rounded-lg border transition-all ${isSelected ? 'border-amber-500 bg-stone-800 shadow-[inset_0_0_10px_rgba(245,158,11,0.1)]' : 'border-stone-800 hover:bg-stone-900'} cursor-pointer group ${!canEquip ? 'opacity-80' : ''}`}
                                >
                                    <div className="flex items-center gap-1.5 md:gap-3">
                                        <div className="w-7 h-7 md:w-10 md:h-10 bg-stone-900 rounded border border-stone-700 flex items-center justify-center relative shrink-0">
                                            <img src={imageUrl} className="w-5 h-5 md:w-8 md:h-8 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                            <div className="hidden text-xl">{item.icon || '📦'}</div>
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="text-[10px] md:text-sm font-bold truncate text-stone-300">{item.name}</div>
                                            <div className="flex items-center gap-1 md:gap-2 text-[7px] md:text-[10px]">
                                                <span className={`${qColor} font-bold whitespace-nowrap`}>{label}</span>
                                            </div>
                                        </div>
                                        {!isReadOnly && isSelected && canEquip && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                                className="shrink-0 px-1.5 md:px-3 py-0.5 md:py-1 bg-amber-700 hover:bg-amber-600 text-white text-[7px] md:text-[10px] font-bold uppercase rounded shadow-lg animate-in fade-in zoom-in duration-200"
                                            >
                                                Equip
                                            </button>
                                        )}
                                    </div>

                                    <div className="flex justify-between items-end border-t border-stone-700/50 pt-1 md:pt-2">
                                        <div className="flex items-center gap-1.5">
                                            <div className="flex items-center gap-0.5 text-[7px] md:text-[9px] text-stone-500 font-bold" title="Durability">
                                                <ShieldAlert className="w-2 h-2 md:w-2.5 md:h-2.5" />
                                                {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                            </div>
                                        </div>

                                        {Object.keys(reqs).length > 0 && (
                                            <div className="flex flex-wrap gap-0.5 justify-end max-w-[80px] md:max-w-[150px]">
                                                {Object.entries(reqs).map(([stat, val]) => {
                                                    const met = totalMercStats[stat as keyof PrimaryStats] >= (val as number);
                                                    return (
                                                        <span key={stat} className={`text-[6px] md:text-[8px] px-0.5 rounded font-bold uppercase ${met ? 'text-stone-500 border border-stone-800' : 'text-red-400 border border-red-900/30 bg-red-950/20'}`}>
                                                            {stat} {val}
                                                        </span>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>

                                    {!canEquip && isSelected && (
                                        <div className="mt-0.5 text-[7px] md:text-[9px] text-red-500 font-bold bg-red-950/30 p-0.5 md:p-1.5 rounded border border-red-900/30 flex items-center gap-1 animate-in slide-in-from-top-1 duration-200">
                                            <AlertCircle className="w-2 h-2 md:w-3 md:h-3" /> Low Stats.
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
};

const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip, isReadOnly = false }) => {
    const { state, actions } = useGame();

    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'STATS' | 'STORAGE'>('STATS');
    const [prevAffinity, setPrevAffinity] = useState(0);
    const [showAffinityGain, setShowAffinityGain] = useState(false);

    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setPrevAffinity(mercenary.affinity);
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
            setActiveTab('STATS');
        }
    }, [mercenary?.id]);

    useEffect(() => {
        if (mercenary && mercenary.affinity > prevAffinity) {
            setShowAffinityGain(true);
            const timer = setTimeout(() => setShowAffinityGain(false), 3000);
            setPrevAffinity(mercenary.affinity);
            return () => clearTimeout(timer);
        }
    }, [mercenary?.affinity]);

    if (!mercenary) return null;

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);

    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const currentStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);

    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(currentStats, currentAttackType);

    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;

    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;
            previewStats = applyEquipmentBonuses(baseDerived, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, currentAttackType);
        }
    }

    const effectiveFinalStats = previewStats || currentStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    const handleSlotClick = (slot: EquipmentSlotType | null) => {
        setSelectedSlot(slot);
        if (slot) {
            setActiveTab('STORAGE');
        }
    };

    return (
        <div className="absolute inset-0 z-[200] flex items-center justify-center bg-black/95 backdrop-blur-sm p-1.5 md:p-6 animate-in fade-in duration-300">
            <button onClick={onClose} className="absolute top-2 right-2 md:top-6 md:right-6 z-[220] p-1.5 md:p-2 bg-stone-900 hover:bg-stone-800 rounded-full text-stone-500 hover:text-white border border-stone-700 transition-colors shadow-2xl"><X className="w-5 h-5 md:w-6 md:h-6" /></button>
            <div className="w-full max-w-6xl h-[92vh] md:h-[85vh] bg-stone-950 border border-stone-800 rounded-2xl shadow-2xl flex flex-row overflow-hidden relative">

                {/* Character View - FIXED ON LEFT (38% width) */}
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    baseCombatPower={currentCombatPower}
                    nextCombatPower={effectiveCombatPower} 
                    showAffinityGain={showAffinityGain} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={handleSlotClick} 
                    selectedSlot={selectedSlot} 
                    isReadOnly={isReadOnly}
                />

                {/* Info Panel - FIXED ON RIGHT (62% width) with Tab System */}
                <div className="w-[62%] md:w-[60%] bg-stone-900 flex flex-col h-full max-h-full overflow-hidden">

                    {/* Tab Navigation */}
                    <div className="flex border-b border-stone-800 bg-stone-950 shrink-0">
                        <button 
                            onClick={() => setActiveTab('STATS')}
                            className={`flex-1 py-3 md:py-4 text-[10px] md:text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'STATS' ? 'text-amber-500 bg-stone-900 border-b-2 border-amber-500' : 'text-stone-500 hover:text-stone-300'}`}
                        >
                            <Activity className="w-3.5 h-3.5" /> <span className="hidden xs:inline">Stats</span>
                        </button>
                        <button 
                            onClick={() => setActiveTab('STORAGE')}
                            className={`flex-1 py-3 md:py-4 text-[10px] md:text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'STORAGE' ? 'text-amber-500 bg-stone-900 border-b-2 border-amber-500' : 'text-stone-500 hover:text-stone-300'}`}
                        >
                            <Box className="w-3.5 h-3.5" /> <span className="hidden xs:inline">Bag</span>
                        </button>
                    </div>

                    <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
                        {activeTab === 'STATS' ? (
                            <MercenaryStatsPanel 
                                mercenary={mercenary} 
                                baseStats={currentStats}
                                finalStats={effectiveFinalStats} 
                                localAllocated={localAllocated}
                                onSetLocalAllocated={setLocalAllocated}
                                isReadOnly={isReadOnly}
                            />
                        ) : (
                            <EquipmentInventoryList 
                                inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                                selectedItemId={selectedInventoryItemId} 
                                onSelect={setSelectedInventoryItemId} 
                                onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                                selectedSlotFilter={selectedSlot}
                                mercenary={mercenary}
                                isReadOnly={isReadOnly}
                            />
                        )}
                    </div>

                </div>
            </div>
        </div>
    );
};

export default MercenaryDetailModal;

import React, { useState, useEffect, useRef } from 'react';
import { User, ChevronRight } from 'lucide-react';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ speaker, text, options = [] }) => {
  const [displayedText, setDisplayedText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const isMounted = useRef(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  useEffect(() => {
    setDisplayedText('');
    setIsTyping(true);
    let index = 0;
    const speed = 25; 

    const timer = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        clearInterval(timer);
        setIsTyping(false);
        setDisplayedText(text);
      } else {
        setDisplayedText(text.slice(0, index));
      }
    }, speed);

    return () => clearInterval(timer);
  }, [text]);

  // Auto-scroll to bottom as text types
  useEffect(() => {
    if (scrollRef.current) {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [displayedText]);

  const handleSkipTyping = () => {
    if (isTyping) {
      setDisplayedText(text);
      setIsTyping(false);
    }
  };

  return (
    <div className="absolute bottom-3 md:bottom-6 left-1/2 -translate-x-1/2 w-[94vw] md:w-[90vw] max-w-5xl z-40">
      <div 
        className="w-full h-[24vh] md:h-[28vh] bg-stone-950/80 backdrop-blur-xl border border-stone-600/40 md:border-2 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] flex flex-col md:flex-row overflow-hidden animate-in slide-in-from-bottom-10 fade-in duration-500"
      >

        {/* Speaker Name Badge */}
        <div className="bg-stone-900/60 p-2 md:p-6 border-b md:border-b-0 md:border-r border-stone-700/50 flex flex-row md:flex-col items-center gap-2 md:gap-4 md:w-44 shrink-0 justify-center md:justify-start">
          <div className="w-8 h-8 md:w-16 md:h-16 rounded-full bg-gradient-to-br from-amber-900/40 to-stone-800 border border-amber-600/50 flex items-center justify-center shadow-inner">
             <User className="w-4 h-4 md:w-8 md:h-8 text-amber-500 drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
          </div>
          <div className="flex flex-col md:items-center">
              <span className="font-black text-amber-100 text-sm md:text-xl md:text-center font-serif leading-none tracking-tight">
                {speaker}
              </span>
              <span className="hidden md:block text-[9px] text-stone-500 uppercase font-black tracking-widest mt-1">Interlocutor</span>
          </div>
        </div>

        {/* Text Area Content */}
        <div className="flex-1 p-3 md:p-8 relative flex flex-col min-h-0 bg-gradient-to-br from-transparent to-stone-900/20">
          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto custom-scrollbar pr-2 cursor-pointer"
            onClick={handleSkipTyping}
          >
            <div 
              className={`text-sm md:text-xl text-stone-100 leading-snug md:leading-relaxed font-medium drop-shadow-sm transition-opacity duration-300 ${isTyping ? 'after:content-["_"] after:inline-block after:w-2 after:h-5 after:bg-amber-500 after:animate-pulse after:ml-1' : ''}`}
            >
              {displayedText}
            </div>
          </div>

          {/* Options - Positioned at bottom right of the text area */}
          {!isTyping && options.length > 0 && (
            <div className="mt-3 md:mt-4 flex flex-wrap gap-2 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={option.action}
                  disabled={option.disabled}
                  className={`px-4 md:px-7 py-2 md:py-3 rounded-xl font-black text-[10px] md:text-sm flex items-center gap-2 transition-all transform active:scale-95 border shadow-xl ${
                    option.disabled 
                      ? 'bg-stone-800/50 text-stone-600 border-stone-700/50 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/50 text-red-200 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/80 text-stone-300 border-stone-600 hover:bg-stone-700 hover:border-stone-400'
                            : 'bg-amber-700 text-amber-50 border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/40'
                  }`}
                >
                  {option.label}
                  {!option.disabled && <ChevronRight className="w-3 h-3 md:w-5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}

          {/* Decorative Corner */}
          <div className="absolute bottom-2 right-2 w-4 h-4 border-r-2 border-b-2 border-stone-700/30 rounded-br-lg pointer-events-none"></div>
        </div>
      </div>
    </div>
  );
};

