                <div className="relative z-10 flex flex-col items-center animate-in zoom-in-95 duration-500">
                    {!canAffordOpen ? (
                        <div className="bg-stone-900 border-2 border-red-900 p-4 md:p-8 rounded-2xl shadow-2xl flex flex-col items-center text-center max-w-xs ring-4 ring-black/50">
