                                <ZapOff className="w-6 h-6 md:w-8 md:h-8 text-red-500 animate-pulse" />
                            </div>
                            <h3 className="text-lg md:text-xl font-bold text-red-100 font-serif">Exhausted</h3>
                            <p className="text-stone-500 text-[10px] md:text-sm mt-1 md:mt-2 mb-4 md:mb-6">
                                You don't have the energy to manage the counter today. Get some rest.
                            </p>
                            <button onClick={() => onNavigate('FORGE')} className="w-full py-2 md:py-3 bg-stone-800 hover:bg-stone-700 text-stone-200 rounded-lg font-bold text-xs md:text-sm transition-all border border-stone-700 pointer-events-auto flex items-center justify-center gap-2"><ArrowLeft className="w-4 h-4" />Return to Forge</button>
                        </div>
                    ) : (
                        <div className="text-center group">
                             <div className="w-16 h-16 md:w-20 md:h-20 bg-stone-800/80 rounded-full flex items-center justify-center mx-auto mb-3 md:mb-4 border border-stone-700 backdrop-blur-sm shadow-xl transition-transform group-hover:scale-110 duration-500">
                                <Store className="w-6 h-6 md:w-8 md:h-8 text-stone-500" />
                            </div>
                            <h3 className="text-xl md:text-2xl font-bold text-stone-300 font-serif tracking-wide drop-shadow-md uppercase">Shop is Closed</h3>
                            <p className="text-stone-500 text-xs md:text-sm mt-1 font-medium">Flip the sign to welcome customers.</p>
                        </div>
                    )}
                </div>
            </div>
        )}

        {isShopOpen && !activeCustomer && (
            <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none pb-20">
                <div className="text-center animate-in fade-in zoom-in duration-500">
                    <div className="w-16 h-16 md:w-24 md:h-24 bg-black/20 rounded-full flex items-center justify-center mx-auto mb-3 md:mb-4 border border-white/10 backdrop-blur-sm">
                        <Store className="w-8 h-8 md:w-10 md:h-10 text-stone-500" />
                    </div>
                    <h3 className="text-lg md:text-xl font-bold text-stone-400 uppercase tracking-wide">Waiting for customers...</h3>
                </div>
            </div>
        )}
    </div>
  );
};

