const StatDiff = ({ current, next, isPercent = false }: { current: number, next: number, isPercent?: boolean }) => {
    const diff = next - current;
    if (Math.abs(diff) < 0.01) return null;

    const isPositive = diff > 0;
    const color = isPositive ? 'text-emerald-400' : 'text-red-400';
    const Icon = isPositive ? ArrowUp : ArrowDown;

    return (
        <div className={`flex items-center gap-0.5 font-mono text-[10px] font-bold ${color} animate-in fade-in slide-in-from-left-1`}>
            <Icon className="w-3 h-3" />
            <span>{isPercent ? Math.abs(diff).toFixed(1) : Math.abs(Math.round(diff))}</span>
        </div>
    );
};

const MercenaryPaperDoll = ({ 
    mercenary, 
    baseCombatPower,
    nextCombatPower,
    showAffinityGain, 
    onUnequip, 
    onSlotClick,
    selectedSlot,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseCombatPower: number; 
    nextCombatPower: number;
    showAffinityGain: boolean; 
    onUnequip: (slot: EquipmentSlotType) => void; 
    onSlotClick: (slot: EquipmentSlotType | null) => void;
    selectedSlot: EquipmentSlotType | null;
    isReadOnly?: boolean;
}) => {
    const renderSlot = ({ slot, icon, style }: { slot: EquipmentSlotType; icon: React.ReactNode; style: string }) => {
        const equippedItem = mercenary.equipment[slot];
        const isSelected = selectedSlot === slot;

        let borderColor = isSelected ? 'border-amber-400' : 'border-stone-700';
        let bgColor = 'bg-stone-900/80';

        if (equippedItem) {
            switch (equippedItem.rarity) {
                case 'Common': borderColor = isSelected ? 'border-amber-400' : 'border-stone-500'; break;
                case 'Uncommon': borderColor = isSelected ? 'border-amber-400' : 'border-emerald-600'; break;
                case 'Rare': borderColor = isSelected ? 'border-amber-400' : 'border-blue-500'; break;
                case 'Epic': borderColor = isSelected ? 'border-amber-400' : 'border-purple-500'; break;
                case 'Legendary': borderColor = isSelected ? 'border-amber-400' : 'border-amber-500'; break;
            }
            bgColor = 'bg-stone-800';
        }

        let imageUrl = '';
        if (equippedItem) {
            imageUrl = equippedItem.image ? getAssetUrl(equippedItem.image) : (equippedItem.recipeId ? getAssetUrl(`${equippedItem.recipeId}.png`) : getAssetUrl(`${equippedItem.id.split('_')[0]}.png`));
        }

        return (
            <div 
                className={`absolute w-9 h-9 md:w-12 md:h-12 rounded-lg border-2 ${borderColor} ${bgColor} flex items-center justify-center shadow-lg transition-all z-20 group ${style} ${isSelected ? 'ring-2 ring-amber-500/50 scale-110' : ''} cursor-pointer`}
                onClick={() => onSlotClick(isSelected ? null : slot)}
            >
                {equippedItem ? (
                    <img 
                        src={imageUrl}
                        className="w-6 h-6 md:w-9 md:h-9 object-contain drop-shadow-md"
