    const cpDiff = nextCombatPower - baseCombatPower;

    return (
        <div className="w-[38%] md:w-[40%] h-full relative bg-gradient-to-b from-stone-900 to-stone-950 border-r border-stone-800 flex flex-col items-center justify-center overflow-hidden group select-none">
