                <h2 className="text-lg md:text-4xl font-black text-stone-200 font-serif tracking-tight drop-shadow-lg leading-none truncate">{mercenary.name}</h2>
                <div className="flex flex-wrap items-center gap-1 md:gap-3 mt-1 md:mt-2">
                    <span className="text-[7px] md:text-sm font-bold text-amber-500 uppercase tracking-widest bg-amber-950/30 px-1 md:px-2 py-0.5 rounded border border-amber-900/50">{mercenary.job}</span>
                    <div className={`flex items-center gap-1 text-[8px] md:text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-500'}`}>
                        <Heart className={`w-2.5 h-2.5 md:w-3.5 md:h-3.5 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
