const MercenaryStatsPanel = ({ 
    mercenary, 
    baseStats,
    finalStats, 
    localAllocated, 
    onSetLocalAllocated,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseStats: DerivedStats;
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
    isReadOnly?: boolean;
}) => {
    const { actions } = useGame();

    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);

    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
        const diff = nextValue - baseValue;
        const colorClass = diff > 0 ? 'text-emerald-400' : diff < 0 ? 'text-red-400' : 'text-stone-200';

        return (
            <div className="bg-stone-800/50 p-1 md:p-2 rounded-lg border border-stone-800 flex justify-between items-center h-7 md:h-10">
                <span className="text-[7px] md:text-[10px] text-stone-400 font-bold flex items-center gap-1 md:gap-1.5">{icon} <span className="truncate max-w-[40px] md:max-w-none">{label}</span></span>
                <div className="flex items-center gap-1 md:gap-2">
                    <span className={`font-mono text-[10px] md:text-sm font-bold ${colorClass}`}>
                        {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}{isPercent ? '%' : ''}
                    </span>
                    <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
                </div>
            </div>
        );
    };

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;

        onSetLocalAllocated({
            ...localAllocated,
            [key]: newVal
        });
    };

    const handleApply = () => {
        actions.updateMercenaryStats(mercenary.id, localAllocated);
    };

    const handleReset = () => {
        onSetLocalAllocated({ ...mercenary.allocatedStats });
    };

    return (
        <div className="p-3 md:p-5 flex flex-col gap-2 md:gap-4 overflow-y-auto flex-1 custom-scrollbar">
            <div className="bg-stone-800/50 p-1.5 md:p-3 rounded-xl border border-stone-800 shadow-sm shrink-0">
                <div className="flex justify-between items-end mb-0.5 md:mb-1.5">
                    <span className="text-amber-500 font-bold font-mono text-[10px] md:text-base">LV {mercenary.level}</span>
                    <span className="text-stone-500 text-[8px] md:text-xs font-mono">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-1 md:h-2.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800">
                    <div className="h-full bg-amber-600 shadow-[0_0_10px_rgba(217,119,6,0.5)] transition-all duration-500 ease-out" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            <div className="bg-stone-950/30 rounded-xl border border-stone-800/50 p-1.5 md:p-3">
                <div className="flex justify-between items-center mb-1.5 md:mb-3 px-1">
                    <h4 className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest flex items-center gap-1.5"><Star className="w-2.5 h-2.5 md:w-3 md:h-3" /> Attributes</h4>
                    {!isReadOnly && availablePoints > 0 && (
                         <span className="text-[7px] md:text-[10px] font-black text-amber-500 animate-pulse">+{availablePoints} PT</span>
                    )}
                </div>
                <div className="grid grid-cols-5 gap-1 md:gap-2">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' }
                    ].map((stat) => {
                        const currentValue = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const isModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];

                        return (
                            <div key={stat.key} className="flex flex-col gap-1">
                                <div className={`bg-stone-800 border ${isModified ? 'border-amber-500/50' : 'border-stone-700'} p-1 md:p-1.5 rounded-lg flex flex-col items-center justify-center relative transition-colors h-10 md:h-14`}>
                                    <span className={`text-[7px] md:text-[9px] font-bold ${stat.color}`}>{stat.label}</span>
                                    <span className={`text-[10px] md:text-sm font-mono font-bold ${isModified ? 'text-amber-400 scale-105 md:scale-110' : 'text-stone-200'} transition-all`}>{currentValue}</span>
                                </div>
                                {!isReadOnly && (
                                    <div className="flex gap-0.5 md:gap-1">
                                        <button 
                                            onClick={() => updateLocalStat(stat.key, -1)}
                                            disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]}
                                            className="flex-1 h-4 md:h-6 bg-stone-800 hover:bg-stone-700 text-stone-500 hover:text-red-400 transition-all disabled:opacity-0 disabled:pointer-events-none rounded flex items-center justify-center"
                                        >
                                            <Minus className="w-2 h-2 md:w-3 md:h-3" />
                                        </button>
                                        <button 
                                            onClick={() => updateLocalStat(stat.key, 1)}
                                            disabled={availablePoints <= 0}
                                            className="flex-1 h-4 md:h-6 bg-stone-800 hover:bg-amber-900/40 border border-stone-700 hover:border-amber-600/50 rounded flex items-center justify-center text-stone-500 hover:text-amber-400 transition-all disabled:opacity-0 disabled:pointer-events-none"
                                        >
                                            <Plus className="w-2 h-2 md:w-3 md:h-3" />
                                        </button>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>

                {!isReadOnly && hasChanges && (
                    <div className="mt-2 md:mt-4 flex gap-1 md:gap-2 animate-in slide-in-from-top-2 duration-300">
                         <button 
                            onClick={handleReset}
                            className="flex-1 py-1 md:py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 hover:text-stone-200 text-[8px] md:text-xs font-bold rounded-lg border border-stone-700 transition-all flex items-center justify-center gap-1"
                        >
                            <RefreshCw className="w-2.5 h-2.5 md:w-3 md:h-3" /> <span className="hidden xs:inline">Reset</span>
                        </button>
                        <button 
                            onClick={handleApply}
                            className="flex-[2] py-1 md:py-2 bg-amber-700 hover:bg-amber-600 text-amber-50 text-[8px] md:text-xs font-bold rounded-lg shadow-lg border border-amber-500 transition-all flex items-center justify-center gap-1"
                        >
                            <Check className="w-2.5 h-2.5 md:w-3 md:h-3" /> Apply Changes
                        </button>
                    </div>
                )}
            </div>

            <div className="grid grid-cols-2 gap-1.5 md:gap-3 shrink-0">
                <div className="bg-stone-800/50 p-1.5 md:p-2.5 rounded-xl border border-stone-800 flex items-center gap-1.5 md:gap-3">
                    <div className="p-1 md:p-1.5 bg-red-900/20 rounded-lg text-red-500 border border-red-900/30 shrink-0"><Heart className="w-3 md:w-4 h-3 md:h-4" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[7px] md:text-[10px] text-stone-400 font-bold mb-0.5 md:mb-1">
                            <span className="truncate mr-1">HP</span>
                            <span className="text-stone-200 font-mono">{mercenary.currentHp}/{finalStats.maxHp}</span>
                        </div>
                        <div className="w-full h-0.5 md:h-1 bg-stone-950 rounded-full overflow-hidden">
                            <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }}></div>
                        </div>
                    </div>
                </div>
                <div className="bg-stone-800/50 p-1.5 md:p-2.5 rounded-xl border border-stone-800 flex items-center gap-1.5 md:gap-3">
                    <div className="p-1 md:p-1.5 bg-blue-900/20 rounded-lg text-blue-500 border border-blue-900/30 shrink-0"><Activity className="w-3 md:w-4 h-3 md:h-4" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[7px] md:text-[10px] text-stone-400 font-bold mb-0.5 md:mb-1">
                            <span className="truncate mr-1">MP</span>
                            <span className="text-stone-200 font-mono">{mercenary.currentMp}/{finalStats.maxMp}</span>
                        </div>
                        <div className="w-full h-0.5 md:h-1 bg-stone-950 rounded-full overflow-hidden">
                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }}></div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="shrink-0 pb-1">
                <h4 className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest mb-1 md:mb-2 flex items-center gap-1.5"><Sword className="w-2.5 h-2.5 md:w-3 md:h-3" /> Combat Statistics</h4>
                <div className="grid grid-cols-2 gap-1 md:gap-2">
                    {renderStatRow(<Sword className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'P.ATK', baseStats.physicalAttack, finalStats.physicalAttack)}
                    {renderStatRow(<Shield className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'P.DEF', baseStats.physicalDefense, finalStats.physicalDefense)}
                    {renderStatRow(<Zap className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'M.ATK', baseStats.magicalAttack, finalStats.magicalAttack)}
                    {renderStatRow(<Brain className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'M.DEF', baseStats.magicalDefense, finalStats.magicalDefense)}
                    {renderStatRow(<Crosshair className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'ACC', baseStats.accuracy, finalStats.accuracy)}
                    {renderStatRow(<Wind className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'EVA', baseStats.evasion, finalStats.evasion)}
                    {renderStatRow(<Target className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'CRIT', baseStats.critChance, finalStats.critChance, true)}
                    {renderStatRow(<FastForward className="w-2.5 h-2.5 md:w-3 md:h-3" />, 'SPD', baseStats.speed, finalStats.speed)}
                </div>
            </div>
        </div>
    );
};

const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary,
    isReadOnly
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
    isReadOnly?: boolean;
}) => {
    const totalMercStats = useMemo(() => mergePrimaryStats(mercenary.stats, mercenary.allocatedStats), [mercenary]);

    const displayInventory = useMemo(() => {
        let items = selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
        return items;
    }, [inventory, selectedSlotFilter]);

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    return (
        <div className="bg-stone-950 p-3 md:p-4 flex-1 flex flex-col min-h-0">
            <div className="flex justify-between items-center mb-2 md:mb-3 shrink-0 px-1">
                <h3 className="text-[8px] md:text-[10px] font-bold text-stone-400 uppercase tracking-wider flex items-center gap-1.5 md:gap-2">
                    <Box className="w-3 h-3 md:w-4 md:h-4 text-amber-600" /> 
                    <span className="truncate">{selectedSlotFilter ? `${selectedSlotFilter.replace('_', ' ')}` : 'Storage'}</span>
                </h3>
                <span className="text-[8px] md:text-[10px] text-stone-600 font-mono">{displayInventory.length} Items</span>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar pr-1">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center border-2 border-dashed border-stone-800 rounded-lg text-stone-600 text-[10px] md:text-sm italic p-4 text-center">
                        <Box className="w-6 h-6 md:w-8 md:h-8 opacity-10 mb-2" />
                        <p>{selectedSlotFilter ? 'No matches.' : 'Empty.'}</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 gap-1.5 md:gap-2 content-start">
                        {displayInventory.map(item => {
                            if (!item.equipmentData) return null;
                            const isSelected = selectedItemId === item.id;
                            const reqs = item.equipmentData.equipRequirements || {};

                            const failedStats = Object.entries(reqs).filter(([stat, val]) => 
                                totalMercStats[stat as keyof PrimaryStats] < (val as number)
                            );
                            const canEquip = failedStats.length === 0;

                            const label = getQualityLabel(item.equipmentData.quality);
                            const qColor = getQualityColor(item.equipmentData.quality);
                            let imageUrl = item.equipmentData.image ? getAssetUrl(item.equipmentData.image) : (item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

                            return (
                                <div 
                                    key={item.id}
                                    onClick={() => !isSelected && onSelect(item.id)}
                                    className={`flex flex-col gap-1 p-1.5 md:p-3 rounded-lg border transition-all ${isSelected ? 'border-amber-500 bg-stone-800 shadow-[inset_0_0_10px_rgba(245,158,11,0.1)]' : 'border-stone-800 hover:bg-stone-900'} cursor-pointer group ${!canEquip ? 'opacity-80' : ''}`}
                                >
                                    <div className="flex items-center gap-1.5 md:gap-3">
                                        <div className="w-7 h-7 md:w-10 md:h-10 bg-stone-900 rounded border border-stone-700 flex items-center justify-center relative shrink-0">
                                            <img src={imageUrl} className="w-5 h-5 md:w-8 md:h-8 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                            <div className="hidden text-xl">{item.icon || '📦'}</div>
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="text-[10px] md:text-sm font-bold truncate text-stone-300">{item.name}</div>
                                            <div className="flex items-center gap-1 md:gap-2 text-[7px] md:text-[10px]">
                                                <span className={`${qColor} font-bold whitespace-nowrap`}>{label}</span>
                                            </div>
                                        </div>
                                        {!isReadOnly && isSelected && canEquip && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                                className="shrink-0 px-1.5 md:px-3 py-0.5 md:py-1 bg-amber-700 hover:bg-amber-600 text-white text-[7px] md:text-[10px] font-bold uppercase rounded shadow-lg animate-in fade-in zoom-in duration-200"
                                            >
                                                Equip
                                            </button>
                                        )}
                                    </div>

                                    <div className="flex justify-between items-end border-t border-stone-700/50 pt-1 md:pt-2">
                                        <div className="flex items-center gap-1.5">
                                            <div className="flex items-center gap-0.5 text-[7px] md:text-[9px] text-stone-500 font-bold" title="Durability">
                                                <ShieldAlert className="w-2 h-2 md:w-2.5 md:h-2.5" />
                                                {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                            </div>
                                        </div>

                                        {Object.keys(reqs).length > 0 && (
                                            <div className="flex flex-wrap gap-0.5 justify-end max-w-[80px] md:max-w-[150px]">
                                                {Object.entries(reqs).map(([stat, val]) => {
                                                    const met = totalMercStats[stat as keyof PrimaryStats] >= (val as number);
                                                    return (
                                                        <span key={stat} className={`text-[6px] md:text-[8px] px-0.5 rounded font-bold uppercase ${met ? 'text-stone-500 border border-stone-800' : 'text-red-400 border border-red-900/30 bg-red-950/20'}`}>
                                                            {stat} {val}
                                                        </span>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>

                                    {!canEquip && isSelected && (
                                        <div className="mt-0.5 text-[7px] md:text-[9px] text-red-500 font-bold bg-red-950/30 p-0.5 md:p-1.5 rounded border border-red-900/30 flex items-center gap-1 animate-in slide-in-from-top-1 duration-200">
                                            <AlertCircle className="w-2 h-2 md:w-3 md:h-3" /> Low Stats.
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
};

const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip, isReadOnly = false }) => {
    const { state, actions } = useGame();

    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'STATS' | 'STORAGE'>('STATS');
    const [prevAffinity, setPrevAffinity] = useState(0);
    const [showAffinityGain, setShowAffinityGain] = useState(false);

    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setPrevAffinity(mercenary.affinity);
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
            setActiveTab('STATS');
        }
    }, [mercenary?.id]);

    useEffect(() => {
        if (mercenary && mercenary.affinity > prevAffinity) {
            setShowAffinityGain(true);
            const timer = setTimeout(() => setShowAffinityGain(false), 3000);
            setPrevAffinity(mercenary.affinity);
            return () => clearTimeout(timer);
        }
    }, [mercenary?.affinity]);

    if (!mercenary) return null;

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);

    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const currentStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);

    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(currentStats, currentAttackType);

    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;

    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;
            previewStats = applyEquipmentBonuses(baseDerived, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, currentAttackType);
        }
    }

    const effectiveFinalStats = previewStats || currentStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    const handleSlotClick = (slot: EquipmentSlotType | null) => {
        setSelectedSlot(slot);
        if (slot) {
            setActiveTab('STORAGE');
        }
    };

    return (
        <div className="absolute inset-0 z-[200] flex items-center justify-center bg-black/95 backdrop-blur-sm p-2 md:p-6 animate-in fade-in duration-300">
            <button onClick={onClose} className="absolute top-2 right-2 md:top-6 md:right-6 z-[220] p-1.5 md:p-2 bg-stone-900 hover:bg-stone-800 rounded-full text-stone-500 hover:text-white border border-stone-700 transition-colors shadow-2xl"><X className="w-5 h-5 md:w-6 md:h-6" /></button>
            <div className="w-full max-w-6xl h-[95vh] md:h-[85vh] bg-stone-950 border border-stone-800 rounded-2xl shadow-2xl flex flex-row overflow-hidden relative">

                {/* Character View - FIXED ON LEFT (38% width) */}
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    baseCombatPower={currentCombatPower}
                    nextCombatPower={effectiveCombatPower} 
                    showAffinityGain={showAffinityGain} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={handleSlotClick} 
                    selectedSlot={selectedSlot} 
                    isReadOnly={isReadOnly}
                />

                {/* Info Panel - FIXED ON RIGHT (62% width) with Tab System */}
                <div className="w-[62%] md:w-[60%] bg-stone-900 flex flex-col h-full max-h-full overflow-hidden">

                    {/* Tab Navigation */}
                    <div className="flex border-b border-stone-800 bg-stone-950 shrink-0">
                        <button 
                            onClick={() => setActiveTab('STATS')}
                            className={`flex-1 py-3 md:py-4 text-[10px] md:text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'STATS' ? 'text-amber-500 bg-stone-900 border-b-2 border-amber-500' : 'text-stone-500 hover:text-stone-300'}`}
                        >
                            <Activity className="w-3.5 h-3.5" /> <span className="hidden xs:inline">Stats</span>
                        </button>
                        <button 
                            onClick={() => setActiveTab('STORAGE')}
                            className={`flex-1 py-3 md:py-4 text-[10px] md:text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'STORAGE' ? 'text-amber-500 bg-stone-900 border-b-2 border-amber-500' : 'text-stone-500 hover:text-stone-300'}`}
                        >
                            <Box className="w-3.5 h-3.5" /> <span className="hidden xs:inline">Bag</span>
                        </button>
                    </div>

                    <div className="flex-1 flex flex-col min-h-0 overflow-hidden pt-1 md:pt-0">
                        {activeTab === 'STATS' ? (
                            <MercenaryStatsPanel 
                                mercenary={mercenary} 
                                baseStats={currentStats}
                                finalStats={effectiveFinalStats} 
                                localAllocated={localAllocated}
                                onSetLocalAllocated={setLocalAllocated}
                                isReadOnly={isReadOnly}
                            />
                        ) : (
                            <EquipmentInventoryList 
                                inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                                selectedItemId={selectedInventoryItemId} 
                                onSelect={setSelectedInventoryItemId} 
                                onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                                selectedSlotFilter={selectedSlot}
                                mercenary={mercenary}
                                isReadOnly={isReadOnly}
                            />
                        )}
                    </div>

                </div>
            </div>
        </div>
    );
};

