    const cpDiff = nextCombatPower - baseCombatPower;

    return (
        <div className="w-[38%] md:w-[40%] h-full relative bg-gradient-to-b from-stone-900 to-stone-950 border-r border-stone-800 flex flex-col items-center justify-center overflow-hidden group select-none">
            <div className="absolute top-6 left-4 md:top-10 md:left-8 z-30 max-w-[90%]">
                <h2 className="text-lg md:text-4xl font-black text-stone-200 font-serif tracking-tight drop-shadow-lg leading-none truncate">{mercenary.name}</h2>
                <div className="flex flex-wrap items-center gap-1 md:gap-3 mt-1 md:mt-2">
                    <span className="text-[7px] md:text-sm font-bold text-amber-500 uppercase tracking-widest bg-amber-950/30 px-1 md:px-2 py-0.5 rounded border border-amber-900/50">{mercenary.job}</span>
                    <div className={`flex items-center gap-1 text-[8px] md:text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-500'}`}>
                        <Heart className={`w-2.5 h-2.5 md:w-3.5 md:h-3.5 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
                        <span className="font-mono font-bold">{mercenary.affinity}</span>
                    </div>
                </div>
            </div>
            <div className="absolute top-6 right-4 md:top-10 md:right-8 z-30 text-right">
                <span className="text-[7px] md:text-[10px] text-stone-500 uppercase font-bold tracking-wider block">CP</span>
                <div className="flex flex-col items-end">
                    <div className="flex items-center gap-0.5 md:gap-1 text-xs md:text-xl font-mono font-bold text-stone-300">
                        <Star className="w-2.5 h-2.5 md:w-4 md:h-4 text-yellow-500 fill-yellow-500" />
