                    />
                </div>
                {renderSlot({ slot: "HEAD", icon: <Crown className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[12%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "BODY", icon: <Shirt className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[32%] left-1/2 -translate-x-1/2" })}
