                {renderSlot({ slot: "MAIN_HAND", icon: <Sword className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[52%] left-[5%]" })}
                {renderSlot({ slot: "OFF_HAND", icon: <Shield className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[52%] right-[5%]" })}
