interface MercenaryDetailModalProps {
    mercenary: Mercenary | null;
    onClose: () => void;
    onUnequip: (mercId: string, slot: EquipmentSlotType) => void;
    isReadOnly?: boolean;
}

const StatDiff = ({ current, next, isPercent = false }: { current: number, next: number, isPercent?: boolean }) => {
    const diff = next - current;
    if (Math.abs(diff) < 0.01) return null;

    const isPositive = diff > 0;
    const color = isPositive ? 'text-emerald-400' : 'text-red-400';
    const Icon = isPositive ? ArrowUp : ArrowDown;

    return (
        <div className={`flex items-center gap-0.5 font-mono text-[10px] font-bold ${color} animate-in fade-in slide-in-from-left-1`}>
            <Icon className="w-3 h-3" />
            <span>{isPercent ? Math.abs(diff).toFixed(1) : Math.abs(Math.round(diff))}</span>
        </div>
    );
};

const MercenaryPaperDoll = ({ 
    mercenary, 
    baseCombatPower,
    nextCombatPower,
    showAffinityGain, 
    onUnequip, 
    onSlotClick,
    selectedSlot,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseCombatPower: number; 
    nextCombatPower: number;
    showAffinityGain: boolean; 
    onUnequip: (slot: EquipmentSlotType) => void; 
    onSlotClick: (slot: EquipmentSlotType | null) => void;
    selectedSlot: EquipmentSlotType | null;
    isReadOnly?: boolean;
}) => {
    const renderSlot = ({ slot, icon, style }: { slot: EquipmentSlotType; icon: React.ReactNode; style: string }) => {
        const equippedItem = mercenary.equipment[slot];
        const isSelected = selectedSlot === slot;

        let borderColor = isSelected ? 'border-amber-400' : 'border-stone-700';
        let bgColor = 'bg-stone-900/80';

        if (equippedItem) {
            switch (equippedItem.rarity) {
                case 'Common': borderColor = isSelected ? 'border-amber-400' : 'border-stone-500'; break;
                case 'Uncommon': borderColor = isSelected ? 'border-amber-400' : 'border-emerald-600'; break;
                case 'Rare': borderColor = isSelected ? 'border-amber-400' : 'border-blue-500'; break;
                case 'Epic': borderColor = isSelected ? 'border-amber-400' : 'border-purple-500'; break;
                case 'Legendary': borderColor = isSelected ? 'border-amber-400' : 'border-amber-500'; break;
            }
            bgColor = 'bg-stone-800';
        }

        let imageUrl = '';
        if (equippedItem) {
            imageUrl = equippedItem.image ? getAssetUrl(equippedItem.image) : (equippedItem.recipeId ? getAssetUrl(`${equippedItem.recipeId}.png`) : getAssetUrl(`${equippedItem.id.split('_')[0]}.png`));
        }

        return (
            <div 
                className={`absolute w-9 h-9 md:w-12 md:h-12 rounded-lg border-2 ${borderColor} ${bgColor} flex items-center justify-center shadow-lg transition-all z-20 group ${style} ${isSelected ? 'ring-2 ring-amber-500/50 scale-110' : ''} cursor-pointer`}
                onClick={() => onSlotClick(isSelected ? null : slot)}
            >
                {equippedItem ? (
                    <img 
                        src={imageUrl}
                        className="w-6 h-6 md:w-9 md:h-9 object-contain drop-shadow-md"
                        onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                    />
                ) : (
                    <div className="text-stone-600 scale-75 md:scale-100">{icon}</div>
                )}
                <div className="hidden text-xl">{equippedItem?.icon || '📦'}</div>
                {equippedItem && !isReadOnly && (
                    <button
                        onClick={(e) => { e.stopPropagation(); onUnequip(slot); }}
                        className="absolute -top-1.5 -right-1.5 bg-stone-900 rounded-full border border-stone-600 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-900 hover:border-red-500 text-stone-400 hover:text-red-200 z-30"
                    >
                        <X className="w-2.5 h-2.5" />
                    </button>
                )}
            </div>
        );
    };

    const cpDiff = nextCombatPower - baseCombatPower;

    return (
        <div className="w-[38%] md:w-[40%] h-full relative bg-gradient-to-b from-stone-900 to-stone-950 border-r border-stone-800 flex flex-col overflow-hidden group select-none">
            {/* Header Section - Fixed Top */}
            <div className="p-3 md:p-6 flex flex-col gap-1 md:gap-2 shrink-0 bg-stone-900/50 border-b border-stone-800/50">
                <div className="flex justify-between items-start">
                    <div className="min-w-0 flex-1">
                        <h2 className="text-sm md:text-2xl font-black text-stone-200 font-serif tracking-tight drop-shadow-lg leading-none truncate">{mercenary.name}</h2>
                        <div className="flex flex-wrap items-center gap-1 md:gap-2 mt-1 md:mt-2">
                            <span className="text-[7px] md:text-xs font-bold text-amber-500 uppercase tracking-widest bg-amber-950/30 px-1 md:px-2 py-0.5 rounded border border-amber-900/50">{mercenary.job}</span>
                            <div className={`flex items-center gap-1 text-[8px] md:text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-500'}`}>
                                <Heart className={`w-2.5 h-2.5 md:w-3 md:h-3 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
                                <span className="font-mono font-bold">{mercenary.affinity}</span>
                            </div>
                        </div>
                    </div>
                    <div className="text-right shrink-0">
                        <span className="text-[7px] md:text-[10px] text-stone-500 uppercase font-bold tracking-wider block leading-none">CP</span>
                        <div className="flex items-center gap-0.5 md:gap-1 text-xs md:text-xl font-mono font-bold text-stone-300">
                            <Star className="w-2.5 h-2.5 md:w-4 md:h-4 text-yellow-500 fill-yellow-500" />
                            {nextCombatPower}
                        </div>
                        {Math.abs(cpDiff) > 0 && (
                            <div className={`text-[7px] md:text-xs font-bold flex items-center justify-end gap-0.5 ${cpDiff > 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                                {cpDiff > 0 ? <Plus className="w-2 h-2" /> : <Minus className="w-2 h-2" />}
                                {Math.abs(cpDiff)}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Paper Doll Body - Stays centered in the remaining space */}
            <div className="flex-1 relative w-full flex items-center justify-center overflow-hidden">
                <div className="relative h-[90%] w-full flex items-center justify-center pointer-events-none">
                    <img 
                        src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')}
                        className="h-full object-contain filter drop-shadow-[0_0_20px_rgba(0,0,0,0.8)]"
                    />
                </div>
                {renderSlot({ slot: "HEAD", icon: <Crown className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[8%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "BODY", icon: <Shirt className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[28%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "HANDS", icon: <Hand className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[28%] left-[10%]" })}
                {renderSlot({ slot: "ACCESSORY", icon: <Sparkles className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[28%] right-[10%]" })}
                {renderSlot({ slot: "MAIN_HAND", icon: <Sword className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[48%] left-[5%]" })}
                {renderSlot({ slot: "OFF_HAND", icon: <Shield className="w-5 h-5 md:w-6 md:h-6" />, style: "top-[48%] right-[5%]" })}
                {renderSlot({ slot: "FEET", icon: <Footprints className="w-5 h-5 md:w-6 md:h-6" />, style: "bottom-[12%] left-1/2 -translate-x-1/2" })}
            </div>
        </div>
    );
};

const MercenaryStatsPanel = ({ 
    mercenary, 
    baseStats,
    finalStats, 
    localAllocated, 
    onSetLocalAllocated,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseStats: DerivedStats;
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
    isReadOnly?: boolean;
}) => {
    const { actions } = useGame();

    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);

    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
        const diff = nextValue - baseValue;
        const colorClass = diff > 0 ? 'text-emerald-400' : diff < 0 ? 'text-red-400' : 'text-stone-200';

        return (
            <div className="bg-stone-800/50 p-1 md:p-2 rounded-lg border border-stone-800 flex justify-between items-center h-8 md:h-10">
                <span className="text-[7px] md:text-[10px] text-stone-400 font-bold flex items-center gap-1 md:gap-1.5">{icon} <span className="truncate max-w-[40px] md:max-w-none">{label}</span></span>
                <div className="flex items-center gap-1 md:gap-2">
                    <span className={`font-mono text-[10px] md:text-sm font-bold ${colorClass}`}>
                        {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}{isPercent ? '%' : ''}
                    </span>
                    <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
                </div>
            </div>
        );
    };

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;

        onSetLocalAllocated({
            ...localAllocated,
            [key]: newVal
        });
    };

    const handleApply = () => {
        actions.updateMercenaryStats(mercenary.id, localAllocated);
    };

    const handleReset = () => {
        onSetLocalAllocated({ ...mercenary.allocatedStats });
    };

    return (
        <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-5 flex flex-col gap-3 md:gap-4 min-h-0">
            {/* Level & XP */}
            <div className="bg-stone-800/50 p-1.5 md:p-3 rounded-xl border border-stone-800 shadow-sm shrink-0">
                <div className="flex justify-between items-end mb-1 md:mb-1.5 leading-none">
                    <span className="text-amber-500 font-bold font-mono text-[10px] md:text-base">LV {mercenary.level}</span>
                    <span className="text-stone-500 text-[8px] md:text-xs font-mono">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-1 md:h-2.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800">
                    <div className="h-full bg-amber-600 shadow-[0_0_10px_rgba(217,119,6,0.5)] transition-all duration-500 ease-out" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            {/* Attributes Grid */}
            <div className="bg-stone-950/30 rounded-xl border border-stone-800/50 p-2 md:p-3 shrink-0">
                <div className="flex justify-between items-center mb-2 md:mb-3 px-1">
                    <h4 className="text-[7px] md:text-[10px] font-bold text-stone-500 uppercase tracking-widest flex items-center gap-1.5"><Star className="w-2.5 h-2.5 md:w-3 md:h-3" /> Attributes</h4>
                    {!isReadOnly && availablePoints > 0 && (
                         <span className="text-[7px] md:text-[10px] font-black text-amber-500 animate-pulse">+{availablePoints} PT</span>
                    )}
                </div>
                <div className="grid grid-cols-5 gap-1 md:gap-2">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' }
                    ].map((stat) => {
                        const currentValue = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const isModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];

                        return (
                            <div key={stat.key} className="flex flex-col gap-1">
                                <div className={`bg-stone-800 border ${isModified ? 'border-amber-500/50 shadow-[0_0_5px_rgba(245,158,11,0.2)]' : 'border-stone-700'} p-1 md:p-1.5 rounded-lg flex flex-col items-center justify-center relative transition-all h-10 md:h-14`}>
                                    <span className={`text-[7px] md:text-[9px] font-bold ${stat.color}`}>{stat.label}</span>
                                    <span className={`text-[10px] md:text-sm font-mono font-bold ${isModified ? 'text-amber-400' : 'text-stone-200'}`}>{currentValue}</span>
                                </div>
                                {!isReadOnly && (
                                    <div className="flex gap-0.5 md:gap-1">
                                        <button 
                                            onClick={() => updateLocalStat(stat.key, -1)}
                                            disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]}
                                            className="flex-1 h-4 md:h-6 bg-stone-800 hover:bg-stone-700 text-stone-500 hover:text-red-400 transition-all disabled:opacity-0 disabled:pointer-events-none rounded flex items-center justify-center"
                                        >
                                            <Minus className="w-2 h-2" />
                                        </button>
                                        <button 
                                            onClick={() => updateLocalStat(stat.key, 1)}
                                            disabled={availablePoints <= 0}
                                            className="flex-1 h-4 md:h-6 bg-stone-800 hover:bg-amber-900/40 border border-stone-700 hover:border-amber-600/50 rounded flex items-center justify-center text-stone-500 hover:text-amber-400 transition-all disabled:opacity-0 disabled:pointer-events-none"
                                        >
                                            <Plus className="w-2 h-2" />
                                        </button>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>

                {!isReadOnly && hasChanges && (
                    <div className="mt-2 md:mt-4 flex gap-1 md:gap-2 animate-in slide-in-from-top-2 duration-300">
                         <button 
                            onClick={handleReset}
                            className="flex-1 py-1 md:py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 hover:text-stone-200 text-[8px] md:text-xs font-bold rounded-lg border border-stone-700 transition-all flex items-center justify-center gap-1"
                        >
                            <RefreshCw className="w-2.5 h-2.5 md:w-3 md:h-3" /> <span className="hidden xs:inline">Reset</span>
                        </button>
                        <button 
                            onClick={handleApply}
                            className="flex-[2] py-1 md:py-2 bg-amber-700 hover:bg-amber-600 text-amber-50 text-[8px] md:text-xs font-bold rounded-lg shadow-lg border border-amber-500 transition-all flex items-center justify-center gap-1"
                        >
                            <Check className="w-2.5 h-2.5 md:w-3 md:h-3" /> Apply
                        </button>
                    </div>
                )}
            </div>

            {/* Vitals & Combat Stats List */}
            <div className="flex flex-col gap-3 shrink-0">
                <div className="grid grid-cols-2 gap-2 md:gap-3">
                    <div className="bg-stone-800/50 p-1.5 md:p-2.5 rounded-xl border border-stone-800 flex items-center gap-2">
                        <div className="p-1 md:p-1.5 bg-red-900/20 rounded-lg text-red-500 border border-red-900/30 shrink-0"><Heart className="w-3 md:w-4 h-3 md:h-4" /></div>
                        <div className="flex-1 min-w-0">
                            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-400 font-bold mb-0.5">
                                <span>HP</span>
                                <span className="text-stone-200 font-mono">{mercenary.currentHp}/{finalStats.maxHp}</span>
                            </div>
                            <div className="w-full h-1 bg-stone-950 rounded-full overflow-hidden">
                                <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }}></div>
                            </div>
                        </div>
                    </div>
                    <div className="bg-stone-800/50 p-1.5 md:p-2.5 rounded-xl border border-stone-800 flex items-center gap-2">
                        <div className="p-1 md:p-1.5 bg-blue-900/20 rounded-lg text-blue-500 border border-blue-900/30 shrink-0"><Activity className="w-3 md:w-4 h-3 md:h-4" /></div>
                        <div className="flex-1 min-w-0">
                            <div className="flex justify-between text-[7px] md:text-[10px] text-stone-400 font-bold mb-0.5">
                                <span>MP</span>
                                <span className="text-stone-200 font-mono">{mercenary.currentMp}/{finalStats.maxMp}</span>
