                }}
            />
        </div>

        <ShopSign 
            isOpen={isShopOpen} 
            onToggle={handleToggleShop} 
            disabled={!isShopOpen && !canAffordOpen}
        />

        {isShopOpen && (
            <div className="absolute top-2 md:top-4 right-32 md:right-44 z-50 flex items-center gap-1.5 md:gap-2 bg-stone-900/90 px-2 md:px-4 py-1 md:py-2 rounded-xl border border-stone-700 text-stone-200 shadow-xl">
