        {/* Counter Height adjusted to be lower */}
        <div className="absolute bottom-0 w-full h-32 md:h-48 z-30 flex items-end justify-center pointer-events-none">
            {!counterImgError ? (
                <img 
                    src={getAssetUrl('shop_counter.png')}
                    alt="Shop Counter"
