import { X, Sword, Shield, Shirt, Hand, Footprints, Crown, Sparkles, Heart, Activity, Star, Box, Zap, Brain, Target, User, Plus, Wind, FastForward, Crosshair, Minus, Check, RefreshCw, AlertCircle, ShieldAlert, ArrowUp, ArrowDown } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, PrimaryStats, mergePrimaryStats } from '../../models/Stats';
import { calculateCombatPower } from '../../utils/combatLogic';
import { InventoryItem } from '../../types/inventory';
import { Equipment } from '../../models/Equipment';

interface MercenaryDetailModalProps {
    mercenary: Mercenary | null;
    onClose: () => void;
    onUnequip: (mercId: string, slot: EquipmentSlotType) => void;
    isReadOnly?: boolean;
}

const StatDiff = ({ current, next, isPercent = false }: { current: number, next: number, isPercent?: boolean }) => {
    const diff = next - current;
    if (Math.abs(diff) < 0.01) return null;

    const isPositive = diff > 0;
    const color = isPositive ? 'text-emerald-400' : 'text-red-400';
    const Icon = isPositive ? ArrowUp : ArrowDown;

    return (
        <div className={`flex items-center gap-0.5 font-mono text-[10px] font-bold ${color} animate-in fade-in slide-in-from-left-1`}>
            <Icon className="w-3 h-3" />
            <span>{isPercent ? Math.abs(diff).toFixed(1) : Math.abs(Math.round(diff))}</span>
        </div>
    );
};

const MercenaryPaperDoll = ({ 
    mercenary, 
    baseCombatPower,
    nextCombatPower,
    showAffinityGain, 
    onUnequip, 
    onSlotClick,
    selectedSlot,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseCombatPower: number; 
    nextCombatPower: number;
    showAffinityGain: boolean; 
    onUnequip: (slot: EquipmentSlotType) => void; 
    onSlotClick: (slot: EquipmentSlotType | null) => void;
    selectedSlot: EquipmentSlotType | null;
    isReadOnly?: boolean;
}) => {
    const renderSlot = ({ slot, icon, style }: { slot: EquipmentSlotType; icon: React.ReactNode; style: string }) => {
        const equippedItem = mercenary.equipment[slot];
        const isSelected = selectedSlot === slot;

        let borderColor = isSelected ? 'border-amber-400' : 'border-stone-700';
        let bgColor = 'bg-stone-900/80';

        if (equippedItem) {
            switch (equippedItem.rarity) {
                case 'Common': borderColor = isSelected ? 'border-amber-400' : 'border-stone-500'; break;
                case 'Uncommon': borderColor = isSelected ? 'border-amber-400' : 'border-emerald-600'; break;
                case 'Rare': borderColor = isSelected ? 'border-amber-400' : 'border-blue-500'; break;
                case 'Epic': borderColor = isSelected ? 'border-amber-400' : 'border-purple-500'; break;
                case 'Legendary': borderColor = isSelected ? 'border-amber-400' : 'border-amber-500'; break;
            }
            bgColor = 'bg-stone-800';
        }

        let imageUrl = '';
        if (equippedItem) {
            imageUrl = equippedItem.image ? getAssetUrl(equippedItem.image) : (equippedItem.recipeId ? getAssetUrl(`${equippedItem.recipeId}.png`) : getAssetUrl(`${equippedItem.id.split('_')[0]}.png`));
        }

        return (
            <div 
                className={`absolute w-9 h-9 md:w-12 md:h-12 rounded-lg border-2 ${borderColor} ${bgColor} flex items-center justify-center shadow-lg transition-all z-20 group ${style} ${isSelected ? 'ring-2 ring-amber-500/50 scale-110' : ''} cursor-pointer`}
                onClick={() => onSlotClick(isSelected ? null : slot)}
            >
                {equippedItem ? (
                    <img 
                        src={imageUrl}
                        className="w-6 h-6 md:w-9 md:h-9 object-contain drop-shadow-md"
                        onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                    />
                ) : (
                    <div className="text-stone-600 scale-75 md:scale-100">{icon}</div>
                )}
                <div className="hidden text-xl">{equippedItem?.icon || '📦'}</div>
                {equippedItem && !isReadOnly && (
                    <button
                        onClick={(e) => { e.stopPropagation(); onUnequip(slot); }}
                        className="absolute -top-1.5 -right-1.5 bg-stone-900 rounded-full border border-stone-600 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-900 hover:border-red-500 text-stone-400 hover:text-red-200 z-30"
                    >
                        <X className="w-2.5 h-2.5" />
                    </button>
                )}
            </div>
        );
    };

    const cpDiff = nextCombatPower - baseCombatPower;

    return (
        <div className="w-[38%] md:w-[40%] h-full relative bg-gradient-to-b from-stone-900 to-stone-950 border-r border-stone-800 flex flex-col overflow-hidden group select-none">
            {/* Left Header - Strictly Fixed Top */}
            <div className="p-3 md:p-6 flex flex-col gap-1 md:gap-2 shrink-0 bg-stone-900/80 border-b border-stone-800 backdrop-blur-sm z-30">
                <div className="flex justify-between items-start gap-2">
                    <div className="min-w-0 flex-1">
                        <h2 className="text-xs md:text-2xl font-black text-stone-200 font-serif tracking-tight drop-shadow-lg leading-tight truncate">{mercenary.name}</h2>
                        <div className="flex flex-wrap items-center gap-1 mt-1">
                            <span className="text-[6px] md:text-xs font-bold text-amber-500 uppercase tracking-widest bg-amber-950/30 px-1 md:px-2 py-0.5 rounded border border-amber-900/50">{mercenary.job}</span>
                            <div className={`flex items-center gap-0.5 text-[7px] md:text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-500'}`}>
                                <Heart className={`w-2 h-2 md:w-3 md:h-3 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
                                <span className="font-mono font-bold">{mercenary.affinity}</span>
                            </div>
                        </div>
                    </div>
                    <div className="text-right shrink-0">
                        <span className="text-[6px] md:text-[10px] text-stone-500 uppercase font-bold tracking-wider block leading-none">CP</span>
                        <div className="flex items-center gap-0.5 md:gap-1 text-[10px] md:text-xl font-mono font-bold text-stone-300">
                            <Star className="w-2 h-2 md:w-4 md:h-4 text-yellow-500 fill-yellow-500" />
                            {nextCombatPower}
                        </div>
                        {Math.abs(cpDiff) > 0 && (
                            <div className={`text-[6px] md:text-xs font-bold flex items-center justify-end gap-0.5 ${cpDiff > 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                                {cpDiff > 0 ? <Plus className="w-1.5 h-1.5" /> : <Minus className="w-1.5 h-1.5" />}
                                {Math.abs(cpDiff)}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Character Body - Responds to remaining height */}
            <div className="flex-1 relative w-full flex items-center justify-center overflow-hidden min-h-0">
                <div className="relative h-[85%] w-full flex items-center justify-center pointer-events-none">
                    <img 
                        src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')}
                        className="h-full object-contain filter drop-shadow-[0_0_20px_rgba(0,0,0,0.8)]"
                    />
                </div>
                {/* Responsive Slots - Using % for better fit */}
                {renderSlot({ slot: "HEAD", icon: <Crown className="w-4 h-4 md:w-6 md:h-6" />, style: "top-[6%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "BODY", icon: <Shirt className="w-4 h-4 md:w-6 md:h-6" />, style: "top-[26%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "HANDS", icon: <Hand className="w-4 h-4 md:w-6 md:h-6" />, style: "top-[26%] left-[12%]" })}
                {renderSlot({ slot: "ACCESSORY", icon: <Sparkles className="w-4 h-4 md:w-6 md:h-6" />, style: "top-[26%] right-[12%]" })}
                {renderSlot({ slot: "MAIN_HAND", icon: <Sword className="w-4 h-4 md:w-6 md:h-6" />, style: "top-[46%] left-[6%]" })}
                {renderSlot({ slot: "OFF_HAND", icon: <Shield className="w-4 h-4 md:w-6 md:h-6" />, style: "top-[46%] right-[6%]" })}
                {renderSlot({ slot: "FEET", icon: <Footprints className="w-4 h-4 md:w-6 md:h-6" />, style: "bottom-[10%] left-1/2 -translate-x-1/2" })}
            </div>
        </div>
    );
};

const MercenaryStatsPanel = ({ 
    mercenary, 
    baseStats,
    finalStats, 
    localAllocated, 
    onSetLocalAllocated,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseStats: DerivedStats;
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
    isReadOnly?: boolean;
}) => {
    const { actions } = useGame();

    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);

    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
        const diff = nextValue - baseValue;
        const colorClass = diff > 0 ? 'text-emerald-400' : diff < 0 ? 'text-red-400' : 'text-stone-200';

        return (
            <div className="bg-stone-800/40 p-1 md:p-2 rounded-lg border border-stone-800/50 flex justify-between items-center h-8 md:h-10">
                <span className="text-[7px] md:text-[10px] text-stone-400 font-bold flex items-center gap-1 md:gap-1.5">{icon} <span className="truncate max-w-[45px] md:max-w-none">{label}</span></span>
                <div className="flex items-center gap-1 md:gap-2">
                    <span className={`font-mono text-[9px] md:text-sm font-bold ${colorClass}`}>
                        {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}{isPercent ? '%' : ''}
                    </span>
                    <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
                </div>
            </div>
        );
    };

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;

        onSetLocalAllocated({
            ...localAllocated,
            [key]: newVal
        });
    };

    return (
        <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 flex flex-col gap-4 min-h-0 bg-stone-900/30">
            {/* Progression Info */}
            <div className="bg-stone-800/60 p-2 md:p-4 rounded-xl border border-stone-700/50 shadow-sm shrink-0">
                <div className="flex justify-between items-end mb-1 md:mb-2 leading-none">
                    <span className="text-amber-500 font-bold font-mono text-[10px] md:text-base">LEVEL {mercenary.level}</span>
                    <span className="text-stone-500 text-[8px] md:text-xs font-mono">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-1 md:h-2.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800">
                    <div className="h-full bg-amber-600 transition-all duration-500" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            {/* Attribute Points Editor */}
            <div className="bg-stone-950/40 rounded-xl border border-stone-800 p-2 md:p-4 shrink-0">
                <div className="flex justify-between items-center mb-2 md:mb-4 px-1">
                    <h4 className="text-[7px] md:text-[11px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5"><Star className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" /> Attributes</h4>
                    {!isReadOnly && availablePoints > 0 && (
                         <span className="text-[7px] md:text-[10px] font-black text-amber-500 px-2 py-0.5 bg-amber-900/20 border border-amber-800/50 rounded-full animate-pulse">AVAILABLE: {availablePoints}</span>
                    )}
                </div>
                <div className="grid grid-cols-5 gap-1 md:gap-3">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' }
                    ].map((stat) => {
                        const currentValue = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const isModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];

                        return (
                            <div key={stat.key} className="flex flex-col gap-1">
                                <div className={`bg-stone-900 border ${isModified ? 'border-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.2)]' : 'border-stone-800'} p-1.5 md:p-2 rounded-lg flex flex-col items-center justify-center h-10 md:h-16 transition-all`}>
                                    <span className={`text-[6px] md:text-[9px] font-black ${stat.color}`}>{stat.label}</span>
                                    <span className={`text-[9px] md:text-sm font-mono font-bold ${isModified ? 'text-amber-400' : 'text-stone-300'}`}>{currentValue}</span>
                                </div>
                                {!isReadOnly && (
                                    <div className="flex flex-col gap-0.5">
                                        <button onClick={() => updateLocalStat(stat.key, 1)} disabled={availablePoints <= 0} className="w-full h-4 md:h-6 bg-stone-800 hover:bg-amber-900/40 border border-stone-700 hover:border-amber-600/50 rounded flex items-center justify-center text-stone-500 hover:text-amber-400 transition-all disabled:opacity-0"><Plus className="w-2.5 h-2.5" /></button>
                                        <button onClick={() => updateLocalStat(stat.key, -1)} disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]} className="w-full h-3 md:h-5 bg-stone-900 hover:bg-stone-800 text-stone-600 hover:text-red-500 rounded flex items-center justify-center transition-all disabled:opacity-0"><Minus className="w-2 h-2" /></button>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>

                {!isReadOnly && hasChanges && (
                    <div className="mt-3 md:mt-6 flex gap-2 animate-in slide-in-from-top-2">
                         <button onClick={() => onSetLocalAllocated({ ...mercenary.allocatedStats })} className="flex-1 py-1.5 md:py-2.5 bg-stone-800 hover:bg-stone-700 text-stone-400 text-[8px] md:text-xs font-bold rounded-lg border border-stone-700 transition-all">Cancel</button>
                        <button onClick={() => actions.updateMercenaryStats(mercenary.id, localAllocated)} className="flex-[2] py-1.5 md:py-2.5 bg-amber-700 hover:bg-amber-600 text-amber-50 text-[8px] md:text-xs font-bold rounded-lg shadow-lg border border-amber-500 transition-all">Save Attributes</button>
                    </div>
                )}
            </div>

            {/* Combat Stats Summary */}
            <div className="flex flex-col gap-4 pb-6 shrink-0">
                <div className="grid grid-cols-2 gap-2 md:gap-4">
                    <div className="bg-stone-800/40 p-2 md:p-3 rounded-xl border border-stone-800 flex items-center gap-3">
                        <div className="p-1.5 md:p-2 bg-red-950/30 rounded-lg text-red-500 border border-red-900/30"><Heart className="w-3 h-3 md:w-4 md:h-4" /></div>
                        <div className="flex-1 min-w-0">
                            <div className="flex justify-between text-[7px] md:text-[11px] text-stone-500 font-black mb-0.5"><span>HP</span><span className="text-stone-300 font-mono">{mercenary.currentHp}/{finalStats.maxHp}</span></div>
                            <div className="w-full h-1 bg-stone-950 rounded-full overflow-hidden"><div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }}></div></div>
                        </div>
                    </div>
                    <div className="bg-stone-800/40 p-2 md:p-3 rounded-xl border border-stone-800 flex items-center gap-3">
                        <div className="p-1.5 md:p-2 bg-blue-950/30 rounded-lg text-blue-500 border border-blue-900/30"><Activity className="w-3 h-3 md:w-4 md:h-4" /></div>
                        <div className="flex-1 min-w-0">
                            <div className="flex justify-between text-[7px] md:text-[11px] text-stone-500 font-black mb-0.5"><span>MP</span><span className="text-stone-300 font-mono">{mercenary.currentMp}/{finalStats.maxMp}</span></div>
                            <div className="w-full h-1 bg-stone-950 rounded-full overflow-hidden"><div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }}></div></div>
                        </div>
                    </div>
                </div>

                <div className="space-y-2">
                    <h4 className="text-[7px] md:text-[11px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 px-1"><Sword className="w-3 h-3" /> Battle Performance</h4>
                    <div className="grid grid-cols-2 gap-1.5 md:gap-3">
                        {renderStatRow(<Sword className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'P.ATK', baseStats.physicalAttack, finalStats.physicalAttack)}
                        {renderStatRow(<Shield className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'P.DEF', baseStats.physicalDefense, finalStats.physicalDefense)}
                        {renderStatRow(<Zap className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'M.ATK', baseStats.magicalAttack, finalStats.magicalAttack)}
                        {renderStatRow(<Brain className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'M.DEF', baseStats.magicalDefense, finalStats.magicalDefense)}
                        {renderStatRow(<Crosshair className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'ACC', baseStats.accuracy, finalStats.accuracy)}
                        {renderStatRow(<Wind className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'EVA', baseStats.evasion, finalStats.evasion)}
                        {renderStatRow(<Target className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'CRIT', baseStats.critChance, finalStats.critChance, true)}
                        {renderStatRow(<FastForward className="w-2.5 h-2.5 md:w-3.5 md:h-3.5" />, 'SPEED', baseStats.speed, finalStats.speed)}
                    </div>
                </div>
            </div>
        </div>
    );
};

const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary,
    isReadOnly
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
    isReadOnly?: boolean;
}) => {
    const totalMercStats = useMemo(() => mergePrimaryStats(mercenary.stats, mercenary.allocatedStats), [mercenary]);

    const displayInventory = useMemo(() => {
        return selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
    }, [inventory, selectedSlotFilter]);

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-500';
    };

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-stone-950">
            {/* List Header - Fixed inside the right panel */}
            <div className="p-3 md:p-4 bg-stone-900/80 border-b border-stone-800 flex justify-between items-center shrink-0 z-10 backdrop-blur-sm">
                <h3 className="text-[8px] md:text-[11px] font-black text-stone-400 uppercase tracking-widest flex items-center gap-2">
                    <Box className="w-3 h-3 md:w-4 md:h-4 text-amber-600" /> 
                    <span>{selectedSlotFilter ? `Filtering: ${selectedSlotFilter.replace('_', ' ')}` : 'Equipment Bag'}</span>
                </h3>
                <span className="text-[8px] md:text-[10px] text-stone-600 font-mono">{displayInventory.length} ITEMS</span>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-4 space-y-2.5">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center border-2 border-dashed border-stone-800/40 rounded-2xl text-stone-700 text-[10px] md:text-sm italic p-10 text-center">
                        <Box className="w-10 h-10 opacity-10 mb-4" />
                        <p>{selectedSlotFilter ? 'No items found for this slot.' : 'The bag is currently empty.'}</p>
                    </div>
                ) : (
                    displayInventory.map(item => {
                        if (!item.equipmentData) return null;
                        const isSelected = selectedItemId === item.id;
                        const reqs = item.equipmentData.equipRequirements || {};
                        const failedStats = Object.entries(reqs).filter(([stat, val]) => totalMercStats[stat as keyof PrimaryStats] < (val as number));
                        const canEquip = failedStats.length === 0;
                        const qLabel = getQualityLabel(item.equipmentData.quality);
                        const qColor = getQualityColor(item.equipmentData.quality);
                        let imageUrl = item.equipmentData.image ? getAssetUrl(item.equipmentData.image) : (item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

                        return (
                            <div 
                                key={item.id}
                                onClick={() => !isSelected && onSelect(item.id)}
                                className={`flex flex-col gap-2 p-2.5 md:p-4 rounded-xl border transition-all ${isSelected ? 'border-amber-500 bg-stone-800 shadow-[inset_0_0_15px_rgba(245,158,11,0.05)]' : 'border-stone-800 hover:bg-stone-900/50'} cursor-pointer group ${!canEquip ? 'opacity-80' : ''}`}
                            >
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 md:w-14 md:h-14 bg-stone-900 rounded-lg border border-stone-700 flex items-center justify-center relative shrink-0 overflow-hidden shadow-inner">
                                        <img src={imageUrl} className="w-8 h-8 md:w-10 md:h-10 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                        <div className="hidden text-xl md:text-2xl">{item.icon || '📦'}</div>
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="text-[10px] md:text-base font-bold truncate text-stone-200">{item.name}</div>
                                        <div className="flex items-center gap-2 text-[7px] md:text-[10px]">
                                            <span className={`${qColor} font-black uppercase tracking-widest`}>{qLabel}</span>
                                            <span className="text-stone-700">•</span>
                                            <span className="text-stone-500 font-mono">ID:{item.id.slice(-4)}</span>
                                        </div>
                                    </div>
                                    {!isReadOnly && isSelected && canEquip && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                            className="shrink-0 px-3 md:px-5 py-1.5 md:py-2 bg-amber-700 hover:bg-amber-600 text-white text-[8px] md:text-xs font-black uppercase rounded-lg shadow-lg active:scale-95 transition-all"
                                        >
                                            EQUIP
                                        </button>
                                    )}
                                </div>

                                <div className="flex justify-between items-center border-t border-stone-800/60 pt-2">
                                    <div className="flex items-center gap-2 text-[7px] md:text-[10px] text-stone-500 font-bold">
                                        <ShieldAlert className="w-3 h-3" />
                                        DUR: {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                    </div>
                                    {Object.keys(reqs).length > 0 && (
                                        <div className="flex flex-wrap gap-1 justify-end max-w-[140px] md:max-w-none">
                                            {Object.entries(reqs).map(([stat, val]) => {
                                                const met = totalMercStats[stat as keyof PrimaryStats] >= (val as number);
                                                return (
                                                    <span key={stat} className={`text-[6px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border ${met ? 'text-stone-600 border-stone-800' : 'text-red-500 border-red-900/40 bg-red-950/30'}`}>
                                                        {stat} {val}
                                                    </span>
                                                );
                                            })}
                                        </div>
                                    )}
                                </div>
                                {!canEquip && isSelected && (
                                    <div className="text-[7px] md:text-[10px] text-red-400 font-bold bg-red-950/20 p-1.5 rounded-lg border border-red-900/40 flex items-center gap-2">
                                        <AlertCircle className="w-3 h-3" /> Requirements not met.
                                    </div>
                                )}
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
};

const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip, isReadOnly = false }) => {
    const { state, actions } = useGame();
    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'STATS' | 'STORAGE'>('STATS');
    const [showAffinityGain, setShowAffinityGain] = useState(false);
    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
            setActiveTab('STATS');
        }
    }, [mercenary?.id]);

    if (!mercenary) return null;

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);
    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const currentStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);
    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(currentStats, currentAttackType);

    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;
    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;
            previewStats = applyEquipmentBonuses(baseDerived, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, currentAttackType);
        }
    }

    const effectiveFinalStats = previewStats || currentStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    return (
        <div className="absolute inset-0 z-[200] flex items-center justify-center bg-black/95 backdrop-blur-md p-3 md:p-10 animate-in fade-in duration-300">
            {/* Close Button - More visible and centered in padding */}
            <button 
                onClick={onClose} 
                className="absolute top-2 right-2 md:top-6 md:right-10 z-[220] p-2.5 md:p-3 bg-stone-900/90 hover:bg-stone-800 rounded-full text-stone-400 hover:text-white border border-stone-700 transition-all shadow-2xl backdrop-blur-xl"
            >
                <X className="w-5 h-5 md:w-6 md:h-6" />
            </button>

            {/* Content Container - 보수적인 높이(88vh) 설정으로 상단 잘림 방지 */}
            <div className="w-full max-w-6xl h-[88vh] md:h-[82vh] bg-stone-950 border border-stone-800 rounded-3xl shadow-[0_30px_60px_rgba(0,0,0,0.8)] flex flex-row overflow-hidden relative ring-1 ring-white/10">

                {/* Left Panel: Fixed Header + Dynamic Character View */}
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    baseCombatPower={currentCombatPower}
                    nextCombatPower={effectiveCombatPower} 
                    showAffinityGain={showAffinityGain} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={(s) => { setSelectedSlot(s); if(s) setActiveTab('STORAGE'); }} 
                    selectedSlot={selectedSlot} 
                    isReadOnly={isReadOnly}
                />

                {/* Right Panel: Fixed Tabs + Inner Scrollable Content */}
                <div className="w-[62%] md:w-[60%] bg-stone-900/80 flex flex-col h-full overflow-hidden">

                    {/* Fixed Navigation Tabs */}
                    <div className="flex border-b border-stone-800 bg-stone-950 shrink-0 z-20">
                        <button 
                            onClick={() => setActiveTab('STATS')}
                            className={`flex-1 py-3 md:py-5 text-[9px] md:text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'STATS' ? 'text-amber-500 bg-stone-900 border-b-2 border-amber-500 shadow-[inset_0_-10px_20px_rgba(245,158,11,0.05)]' : 'text-stone-600 hover:text-stone-300 hover:bg-stone-800/50'}`}
                        >
                            <Activity className="w-3 h-3 md:w-4 md:h-4" /> <span>STATISTICS</span>
                        </button>
                        <button 
                            onClick={() => setActiveTab('STORAGE')}
                            className={`flex-1 py-3 md:py-5 text-[9px] md:text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'STORAGE' ? 'text-amber-500 bg-stone-900 border-b-2 border-amber-500 shadow-[inset_0_-10px_20px_rgba(245,158,11,0.05)]' : 'text-stone-600 hover:text-stone-300 hover:bg-stone-800/50'}`}
                        >
                            <Box className="w-3 h-3 md:w-4 md:h-4" /> <span>BAG</span>
                        </button>
                    </div>

                    {/* Dynamic Inner Panel */}
                    <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
                        {activeTab === 'STATS' ? (
                            <MercenaryStatsPanel 
                                mercenary={mercenary} 
                                baseStats={currentStats}
                                finalStats={effectiveFinalStats} 
                                localAllocated={localAllocated}
                                onSetLocalAllocated={setLocalAllocated}
                                isReadOnly={isReadOnly}
                            />
                        ) : (
                            <EquipmentInventoryList 
                                inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                                selectedItemId={selectedInventoryItemId} 
                                onSelect={setSelectedInventoryItemId} 
                                onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                                selectedSlotFilter={selectedSlot}
                                mercenary={mercenary}
                                isReadOnly={isReadOnly}
                            />
                        )}
                    </div>

                </div>
            </div>
        </div>
    );
};

export default MercenaryDetailModal;

import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { Store, Coins, PackageOpen, Heart, Users, ArrowLeft, ZapOff } from 'lucide-react';
