};

const ShopTab: React.FC<ShopTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();
  const { isShopOpen } = state.forge;
  const { activeCustomer, shopQueue } = state;
  const [counterImgError, setCounterImgError] = useState(false);

  const getItemName = (id: string) => {
    const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
    if (eq) return eq.name;
    const res = Object.values(MATERIALS).find(i => i.id === id);
    return res ? res.name : id;
  };

  const getItemImageUrl = (id: string) => {
      const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
      if (eq && eq.image) return getAssetUrl(eq.image);
      const res = Object.values(MATERIALS).find(i => i.id === id);
      if (res) return getAssetUrl(`${res.id}.png`);
      return getAssetUrl(`${id}.png`);
  };

  const getItemIcon = (id: string) => {
      const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
      if (eq) return eq.icon;
      return '📦';
  };

  const handleSell = () => {
      if (!activeCustomer) return;
      const { mercenary, request } = activeCustomer;
      if (request.type === 'RESOURCE') {
          actions.sellItem(request.requestedId, 1, request.price, undefined, mercenary);
      } else {
          const matchingItem = state.inventory.find(i => i.equipmentData && i.id.startsWith(request.requestedId));
          if (matchingItem) actions.sellItem(matchingItem.id, 1, request.price, matchingItem.id, mercenary);
      }
  };

  const handleRefuse = () => actions.dismissCustomer();
  const handleToggleShop = () => actions.toggleShop();

  const hasItem = () => {
      if (!activeCustomer) return false;
      const { request } = activeCustomer;
      if (request.type === 'RESOURCE') {
          const item = state.inventory.find(i => i.id === request.requestedId);
          return item && item.quantity > 0;
      } else {
          return state.inventory.some(i => i.id.startsWith(request.requestedId));
      }
  };

  const canAffordOpen = state.stats.energy >= GAME_CONFIG.ENERGY_COST.OPEN_SHOP;

  return (
    <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">

        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('shop_interior.png')} 
                alt="Shop Interior" 
                className="absolute top-0 opacity-60 w-full h-full object-cover"
                onError={(e) => {
                    e.currentTarget.style.display = 'none';
                    e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)';
                }}
            />
        </div>

        <ShopSign 
            isOpen={isShopOpen} 
            onToggle={handleToggleShop} 
            disabled={!isShopOpen && !canAffordOpen}
        />

        {isShopOpen && (
            <div className="absolute top-2 md:top-4 right-32 md:right-44 z-50 flex items-center gap-1.5 md:gap-2 bg-stone-900/90 px-2 md:px-4 py-1 md:py-2 rounded-xl border border-stone-700 text-stone-200 shadow-xl">
                <div className="bg-stone-800 p-1 md:p-1.5 rounded-full">
                    <Users className="w-3 h-3 md:w-5 md:h-5 text-amber-500" />
                </div>
                <div className="flex flex-col leading-none">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-bold uppercase tracking-wider">Queue</span>
                    <span className="text-sm md:text-lg font-bold font-mono">{shopQueue.length}</span>
                </div>
            </div>
        )}

        {isShopOpen && activeCustomer && (
            <>
                <div className="absolute top-[10%] md:top-[12%] left-4 md:left-10 z-50 animate-in slide-in-from-left-10 fade-in duration-500 transform scale-75 md:scale-100 origin-top-left">
                     <div 
                        className="w-56 md:w-64 h-28 md:h-32 flex items-center justify-center"
                        style={{ backgroundImage: `url(${getAssetUrl('bubble_thought.png')})`, backgroundSize: 'contain', backgroundRepeat: 'no-repeat', backgroundPosition: 'center' }}
                    >
                        <div className="pb-4 md:pb-6 pl-2 flex items-center gap-2 md:gap-3">
                            <div className="bg-stone-100/90 p-1 rounded-lg backdrop-blur-sm border border-stone-300 flex items-center justify-center w-10 h-10 md:w-12 md:h-12 shadow-inner">
                                <img src={getItemImageUrl(activeCustomer.request.requestedId)} className="w-6 h-6 md:w-8 md:h-8 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                <span className="hidden text-xl md:text-2xl">{getItemIcon(activeCustomer.request.requestedId)}</span>
                            </div>
                            <div className="leading-tight">
                                <div className="font-bold text-stone-800 text-xs md:text-sm line-clamp-1 w-20 md:w-24">{getItemName(activeCustomer.request.requestedId)}</div>
                                <div className="text-[10px] md:text-xs font-bold text-emerald-600 flex items-center gap-0.5">
                                    <Coins className="w-2.5 h-2.5 md:w-3 md:h-3" />
                                    {activeCustomer.request.price} G
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="absolute top-[10%] md:top-[12%] right-4 md:right-10 z-50 animate-in slide-in-from-right-10 fade-in duration-500">
                    <div className="w-36 md:w-48 bg-stone-900/90 border border-stone-700 p-2 md:p-3 rounded-lg backdrop-blur-sm shadow-xl text-[9px] md:text-xs">
                        <div className="flex items-center justify-between mb-1.5 md:mb-2">
                            <span className="font-bold text-amber-500">{activeCustomer.mercenary.job}</span>
                            <span className="text-stone-500">Lv.{activeCustomer.mercenary.level}</span>
                        </div>
                        <div className="space-y-0.5 md:space-y-1 mb-1.5 md:mb-2">
                            <div className="w-full bg-stone-800 h-1 md:h-1.5 rounded-full overflow-hidden">
                                <div className="bg-red-500 h-full" style={{ width: `${(activeCustomer.mercenary.currentHp / activeCustomer.mercenary.maxHp) * 100}%` }}></div>
                            </div>
                            <div className="w-full bg-stone-800 h-1 md:h-1.5 rounded-full overflow-hidden">
                                <div className="bg-blue-500 h-full" style={{ width: `${(activeCustomer.mercenary.currentMp / activeCustomer.mercenary.maxMp) * 100}%` }}></div>
                            </div>
                        </div>
                        <div className="flex items-center gap-1 text-pink-400 font-bold">
                            <Heart className="w-2.5 h-2.5 md:w-3 md:h-3 fill-pink-400" />
                            <span>{activeCustomer.mercenary.affinity}</span>
                        </div>
                    </div>
                </div>
            </>
        )}

        {/* Character Placement - Removed translate-y to lift them higher above the dialogue box */}
        <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
            {isShopOpen && activeCustomer && (
               <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-200 ease-out">
                   <div className="relative h-[75vh] md:h-[85vh] w-auto flex justify-center translate-y-0">
                       <img 
                           src={activeCustomer.mercenary.sprite ? getAssetUrl(activeCustomer.mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')} 
                           alt="Adventurer"
                           className="h-full object-contain object-bottom filter drop-shadow-2xl"
                       />
                   </div>
               </div>
            )}
        </div>

        {/* Shop Counter - Lowered mobile height to h-28 */}
        <div className="absolute bottom-0 w-full h-28 md:h-48 z-30 flex items-end justify-center pointer-events-none">
            {!counterImgError ? (
                <img 
                    src={getAssetUrl('shop_counter.png')}
                    alt="Shop Counter"
                    className="w-full h-full object-cover object-top filter drop-shadow-[0_-10px_20px_rgba(0,0,0,0.5)]"
                    onError={() => setCounterImgError(true)}
                />
            ) : (
                <div className="w-full h-full bg-[#3f2e22] border-t-2 md:border-t-[6px] border-[#5d4037] shadow-[0_-10px_20px_rgba(0,0,0,0.5)] relative overflow-hidden">
                    <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, #000 10px, #000 12px)' }}></div>
                </div>
            )}
        </div>

        {isShopOpen && activeCustomer && (
            <DialogueBox 
                speaker={activeCustomer.mercenary.name}
                text={activeCustomer.request.dialogue}
                options={[
                    { label: `Sell (${activeCustomer.request.price} G)`, action: handleSell, variant: 'primary', disabled: !hasItem() },
                    { label: "Refuse", action: handleRefuse, variant: 'danger' }
                ]}
            />
        )}

        {!isShopOpen && (
            <div className="absolute inset-0 z-40 flex items-center justify-center pointer-events-none">
                <div className="absolute inset-0 bg-black/60 backdrop-blur-[1px] transition-opacity duration-700 animate-in fade-in"></div>
                <div className="relative z-10 flex flex-col items-center animate-in zoom-in-95 duration-500">
                    {!canAffordOpen ? (
                        <div className="bg-stone-900 border-2 border-red-900 p-4 md:p-8 rounded-2xl shadow-2xl flex flex-col items-center text-center max-w-xs ring-4 ring-black/50">
                            <div className="w-12 h-12 md:w-16 md:h-16 bg-red-900/20 rounded-full flex items-center justify-center mb-3 md:mb-4 border border-red-800/50">
                                <ZapOff className="w-6 h-6 md:w-8 md:h-8 text-red-500 animate-pulse" />
                            </div>
                            <h3 className="text-lg md:text-xl font-bold text-red-100 font-serif">Exhausted</h3>
                            <p className="text-stone-500 text-[10px] md:text-sm mt-1 md:mt-2 mb-4 md:mb-6">
                                You don't have the energy to manage the counter today. Get some rest.
                            </p>
                            <button onClick={() => onNavigate('FORGE')} className="w-full py-2 md:py-3 bg-stone-800 hover:bg-stone-700 text-stone-200 rounded-lg font-bold text-xs md:text-sm transition-all border border-stone-700 pointer-events-auto flex items-center justify-center gap-2"><ArrowLeft className="w-4 h-4" />Return to Forge</button>
                        </div>
                    ) : (
                        <div className="text-center group">
                             <div className="w-16 h-16 md:w-20 md:h-20 bg-stone-800/80 rounded-full flex items-center justify-center mx-auto mb-3 md:mb-4 border border-stone-700 backdrop-blur-sm shadow-xl transition-transform group-hover:scale-110 duration-500">
                                <Store className="w-6 h-6 md:w-8 md:h-8 text-stone-500" />
                            </div>
                            <h3 className="text-xl md:text-2xl font-bold text-stone-300 font-serif tracking-wide drop-shadow-md uppercase">Shop is Closed</h3>
                            <p className="text-stone-500 text-xs md:text-sm mt-1 font-medium">Flip the sign to welcome customers.</p>
                        </div>
                    )}
                </div>
            </div>
        )}

        {isShopOpen && !activeCustomer && (
            <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none pb-20">
                <div className="text-center animate-in fade-in zoom-in duration-500">
                    <div className="w-16 h-16 md:w-24 md:h-24 bg-black/20 rounded-full flex items-center justify-center mx-auto mb-3 md:mb-4 border border-white/10 backdrop-blur-sm">
                        <Store className="w-8 h-8 md:w-10 md:h-10 text-stone-500" />
                    </div>
                    <h3 className="text-lg md:text-xl font-bold text-stone-400 uppercase tracking-wide">Waiting for customers...</h3>
                </div>
            </div>
        )}
    </div>
  );
};

export default ShopTab;

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../context/GameContext';
import { Mercenary } from '../../models/Mercenary';
import { EquipmentSlotType } from '../../types/inventory';
import { X, Sword, Shield, Shirt, Hand, Footprints, Crown, Sparkles, Heart, Activity, Star, Box, Zap, Brain, Target, User, Plus, Wind, FastForward, Crosshair, Minus, Check, RefreshCw, AlertCircle, ShieldAlert, ArrowUp, ArrowDown } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, PrimaryStats, mergePrimaryStats } from '../../models/Stats';
