interface MercenaryDetailModalProps {
    mercenary: Mercenary | null;
    onClose: () => void;
    onUnequip: (mercId: string, slot: EquipmentSlotType) => void;
    isReadOnly?: boolean;
}

const StatDiff = ({ current, next, isPercent = false }: { current: number, next: number, isPercent?: boolean }) => {
    const diff = next - current;
    if (Math.abs(diff) < 0.01) return null;
    const isPositive = diff > 0;
    const color = isPositive ? 'text-emerald-400' : 'text-red-400';
    const Icon = isPositive ? ArrowUp : ArrowDown;
    return (
        <div className={`flex items-center gap-0.5 font-mono text-[10px] font-bold ${color} animate-in fade-in slide-in-from-left-1`}>
            <Icon className="w-3 h-3" />
            <span>{isPercent ? Math.abs(diff).toFixed(1) : Math.abs(Math.round(diff))}</span>
        </div>
    );
};

const MercenaryPaperDoll = ({ 
    mercenary, 
    baseCombatPower,
    nextCombatPower,
    showAffinityGain, 
    onUnequip, 
    onSlotClick,
    selectedSlot,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseCombatPower: number; 
    nextCombatPower: number;
    showAffinityGain: boolean; 
    onUnequip: (slot: EquipmentSlotType) => void; 
    onSlotClick: (slot: EquipmentSlotType | null) => void;
    selectedSlot: EquipmentSlotType | null;
    isReadOnly?: boolean;
}) => {
    const renderSlot = ({ slot, icon, style }: { slot: EquipmentSlotType; icon: React.ReactNode; style: string }) => {
        const equippedItem = mercenary.equipment[slot];
        const isSelected = selectedSlot === slot;
        let borderColor = isSelected ? 'border-amber-400' : 'border-stone-700/50';
        let bgColor = 'bg-stone-950/40';

        if (equippedItem) {
            switch (equippedItem.rarity) {
                case 'Common': borderColor = isSelected ? 'border-amber-400' : 'border-stone-500'; break;
                case 'Uncommon': borderColor = isSelected ? 'border-amber-400' : 'border-emerald-600'; break;
                case 'Rare': borderColor = isSelected ? 'border-amber-400' : 'border-blue-500'; break;
                case 'Epic': borderColor = isSelected ? 'border-amber-400' : 'border-purple-500'; break;
                case 'Legendary': borderColor = isSelected ? 'border-amber-400' : 'border-amber-500'; break;
            }
            bgColor = 'bg-stone-800/60';
        }

        let imageUrl = '';
        if (equippedItem) {
            imageUrl = equippedItem.image ? getAssetUrl(equippedItem.image) : (equippedItem.recipeId ? getAssetUrl(`${equippedItem.recipeId}.png`) : getAssetUrl(`${equippedItem.id.split('_')[0]}.png`));
        }

        return (
            <div 
                className={`absolute w-10 h-10 md:w-14 md:h-14 rounded-xl border-2 backdrop-blur-md ${borderColor} ${bgColor} flex items-center justify-center shadow-lg transition-all z-20 group ${style} ${isSelected ? 'ring-4 ring-amber-500/30 scale-110' : 'hover:scale-105'} cursor-pointer`}
                onClick={() => onSlotClick(isSelected ? null : slot)}
            >
                {equippedItem ? (
                    <img src={imageUrl} className="w-7 h-7 md:w-10 md:h-10 object-contain drop-shadow-md" />
                ) : (
                    <div className="text-stone-600/80 scale-75 md:scale-100">{icon}</div>
                )}
                {equippedItem && !isReadOnly && (
                    <button
                        onClick={(e) => { e.stopPropagation(); onUnequip(slot); }}
                        className="absolute -top-2 -right-2 bg-red-600 rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity text-white shadow-lg"
                    >
                        <X className="w-3 h-3" />
                    </button>
                )}
            </div>
        );
    };

    const cpDiff = nextCombatPower - baseCombatPower;

    return (
        <div className="w-[40%] h-full relative bg-stone-900/20 flex flex-col overflow-hidden border-r border-stone-800/50">
            {/* Left Fixed Header */}
            <div className="p-4 md:p-6 flex flex-col gap-1 shrink-0 bg-stone-950/60 border-b border-stone-800/50 backdrop-blur-xl z-30">
                <h2 className="text-sm md:text-2xl font-black text-stone-100 font-serif truncate leading-tight">{mercenary.name}</h2>
                <div className="flex justify-between items-end">
                    <div className="flex flex-wrap items-center gap-1.5">
                        <span className="text-[7px] md:text-xs font-black text-amber-500 uppercase tracking-widest bg-amber-950/40 px-1.5 py-0.5 rounded border border-amber-900/30">{mercenary.job}</span>
                        <div className={`flex items-center gap-1 text-[8px] md:text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-400 font-bold'}`}>
                            <Heart className={`w-2.5 h-2.5 md:w-3.5 md:h-3.5 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
                            <span>{mercenary.affinity}</span>
                        </div>
                    </div>
                    <div className="text-right">
                        <span className="text-[7px] md:text-[9px] text-stone-500 uppercase font-black tracking-tighter block leading-none">Power</span>
                        <div className="flex items-center gap-1 text-[10px] md:text-xl font-mono font-black text-stone-200">
                            <Star className="w-2.5 h-2.5 md:w-4 md:h-4 text-amber-500 fill-amber-500" />
                            {nextCombatPower}
                        </div>
                        {Math.abs(cpDiff) > 0 && (
                            <div className={`text-[7px] md:text-xs font-black flex items-center justify-end gap-0.5 ${cpDiff > 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                                {cpDiff > 0 ? <Plus className="w-2 h-2" /> : <Minus className="w-2 h-2" />}
                                {Math.abs(cpDiff)}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Paper Doll Body Area */}
            <div className="flex-1 relative w-full flex items-center justify-center overflow-hidden min-h-0">
                <div className="relative h-[85%] w-full flex items-center justify-center pointer-events-none">
                    <img 
                        src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')}
                        className="h-full object-contain filter drop-shadow-[0_0_30px_rgba(0,0,0,0.7)]"
                    />
                </div>
                {renderSlot({ slot: "HEAD", icon: <Crown className="w-6 h-6" />, style: "top-[5%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "BODY", icon: <Shirt className="w-6 h-6" />, style: "top-[25%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "HANDS", icon: <Hand className="w-6 h-6" />, style: "top-[25%] left-[10%]" })}
                {renderSlot({ slot: "ACCESSORY", icon: <Sparkles className="w-6 h-6" />, style: "top-[25%] right-[10%]" })}
                {renderSlot({ slot: "MAIN_HAND", icon: <Sword className="w-6 h-6" />, style: "top-[48%] left-[5%]" })}
                {renderSlot({ slot: "OFF_HAND", icon: <Shield className="w-6 h-6" />, style: "top-[48%] right-[5%]" })}
                {renderSlot({ slot: "FEET", icon: <Footprints className="w-6 h-6" />, style: "bottom-[12%] left-1/2 -translate-x-1/2" })}
            </div>
        </div>
    );
};

const MercenaryStatsPanel = ({ 
    mercenary, 
    baseStats,
    finalStats, 
    localAllocated, 
    onSetLocalAllocated,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseStats: DerivedStats;
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
    isReadOnly?: boolean;
}) => {
    const { actions } = useGame();
    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);
    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
        const diff = nextValue - baseValue;
        const colorClass = diff > 0 ? 'text-emerald-400' : diff < 0 ? 'text-red-400' : 'text-stone-300';
        return (
            <div className="bg-stone-950/40 p-2 md:p-3 rounded-xl border border-stone-800/40 flex justify-between items-center h-9 md:h-12">
                <span className="text-[8px] md:text-xs text-stone-500 font-black uppercase flex items-center gap-2">{icon} <span className="truncate max-w-[60px] md:max-w-none">{label}</span></span>
                <div className="flex items-center gap-2">
                    <span className={`font-mono text-[10px] md:text-base font-black ${colorClass}`}>
                        {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}{isPercent ? '%' : ''}
                    </span>
                    <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
                </div>
            </div>
        );
    };

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;
        onSetLocalAllocated({ ...localAllocated, [key]: newVal });
    };

    return (
        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-6 flex flex-col gap-6 min-h-0 bg-stone-900/10">
            {/* Level & XP */}
            <div className="bg-stone-950/50 p-3 md:p-5 rounded-2xl border border-stone-800/60 shadow-xl shrink-0">
                <div className="flex justify-between items-end mb-2 leading-none">
                    <span className="text-amber-500 font-black font-mono text-xs md:text-lg uppercase tracking-tighter">LVL {mercenary.level}</span>
                    <span className="text-stone-500 text-[10px] md:text-sm font-mono font-bold">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-1.5 md:h-2.5 bg-stone-900 rounded-full overflow-hidden border border-stone-800/50 shadow-inner">
                    <div className="h-full bg-gradient-to-r from-amber-700 to-amber-400 shadow-[0_0_15px_rgba(245,158,11,0.4)] transition-all duration-700" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            {/* Attribute Points */}
            <div className="bg-stone-950/60 rounded-2xl border border-stone-800 shadow-2xl p-4 md:p-6 shrink-0 relative overflow-hidden">
                <div className="flex justify-between items-center mb-4 px-1">
                    <h4 className="text-[10px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-2"><Star className="w-3 h-3 text-amber-600" /> Attributes</h4>
                    {!isReadOnly && availablePoints > 0 && (
                         <span className="text-[9px] md:text-xs font-black text-amber-400 px-3 py-1 bg-amber-900/30 border border-amber-500/50 rounded-full animate-pulse shadow-glow">POINTS: {availablePoints}</span>
                    )}
                </div>
                <div className="grid grid-cols-5 gap-2 md:gap-4">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-500' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-500' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-500' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-500' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-500' }
                    ].map((stat) => {
                        const currentValue = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const isModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];
                        return (
                            <div key={stat.key} className="flex flex-col gap-1.5">
                                <div className={`bg-stone-900/80 border-2 ${isModified ? 'border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' : 'border-stone-800'} p-2 rounded-xl flex flex-col items-center justify-center h-14 md:h-20 transition-all group hover:bg-stone-800`}>
                                    <span className={`text-[7px] md:text-[10px] font-black ${stat.color} mb-1`}>{stat.label}</span>
                                    <span className={`text-xs md:text-xl font-mono font-black ${isModified ? 'text-amber-400 scale-110' : 'text-stone-300'}`}>{currentValue}</span>
                                </div>
                                {!isReadOnly && (
                                    <div className="flex flex-col gap-1">
                                        <button onClick={() => updateLocalStat(stat.key, 1)} disabled={availablePoints <= 0} className="w-full h-5 md:h-8 bg-stone-800/80 hover:bg-amber-600 text-stone-400 hover:text-white rounded-lg transition-all disabled:opacity-0 flex items-center justify-center shadow-md"><Plus className="w-3 h-3 md:w-4 md:h-4" /></button>
                                        <button onClick={() => updateLocalStat(stat.key, -1)} disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]} className="w-full h-4 md:h-6 bg-stone-950/80 hover:bg-red-700 text-stone-600 hover:text-white rounded-lg transition-all disabled:opacity-0 flex items-center justify-center"><Minus className="w-3 h-3" /></button>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
                {!isReadOnly && hasChanges && (
                    <div className="mt-6 flex gap-3 animate-in slide-in-from-top-2">
                        <button onClick={() => onSetLocalAllocated({ ...mercenary.allocatedStats })} className="flex-1 py-2.5 bg-stone-800 hover:bg-stone-700 text-stone-400 text-xs font-black rounded-xl border border-stone-700 transition-all uppercase tracking-widest">Discard</button>
                        <button onClick={() => actions.updateMercenaryStats(mercenary.id, localAllocated)} className="flex-[2] py-2.5 bg-amber-700 hover:bg-amber-600 text-white text-xs font-black rounded-xl shadow-[0_10px_20px_rgba(180,83,9,0.3)] border border-amber-500 transition-all uppercase tracking-widest">Confirm Stats</button>
                    </div>
                )}
            </div>

            {/* Vital Bars */}
            <div className="grid grid-cols-2 gap-3 md:gap-6 shrink-0">
                <div className="bg-stone-950/50 p-3 md:p-5 rounded-2xl border border-stone-800 flex items-center gap-4 shadow-xl">
                    <div className="p-2 md:p-3 bg-red-950/40 rounded-xl text-red-500 border border-red-900/30"><Heart className="w-5 h-5 md:w-7 md:h-7" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[8px] md:text-xs text-stone-500 font-black mb-1"><span>HEALTH</span><span className="text-stone-200 font-mono font-black">{mercenary.currentHp}/{finalStats.maxHp}</span></div>
                        <div className="w-full h-1.5 md:h-2 bg-stone-900 rounded-full overflow-hidden shadow-inner"><div className="h-full bg-red-600 transition-all duration-500 shadow-[0_0_10px_rgba(220,38,38,0.5)]" style={{ width: `${hpPercent}%` }}></div></div>
                    </div>
                </div>
                <div className="bg-stone-950/50 p-3 md:p-5 rounded-2xl border border-stone-800 flex items-center gap-4 shadow-xl">
                    <div className="p-2 md:p-3 bg-blue-950/40 rounded-xl text-blue-500 border border-blue-900/30"><Activity className="w-5 h-5 md:w-7 md:h-7" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[8px] md:text-xs text-stone-500 font-black mb-1"><span>MANA</span><span className="text-stone-200 font-mono font-black">{mercenary.currentMp}/{finalStats.maxMp}</span></div>
                        <div className="w-full h-1.5 md:h-2 bg-stone-900 rounded-full overflow-hidden shadow-inner"><div className="h-full bg-blue-600 transition-all duration-500 shadow-[0_0_10px_rgba(37,99,235,0.5)]" style={{ width: `${mpPercent}%` }}></div></div>
