                    {renderStatRow(<Shield className="w-3.5 h-3.5 md:w-4 md:h-4 text-blue-500" />, 'Physical Def', baseStats.physicalDefense, finalStats.physicalDefense)}
                    {renderStatRow(<Zap className="w-3.5 h-3.5 md:w-4 md:h-4 text-blue-400" />, 'Magical Atk', baseStats.magicalAttack, finalStats.magicalAttack)}
