                    {renderStatRow(<Wind className="w-3.5 h-3.5 md:w-4 md:h-4 text-emerald-400" />, 'Evasion', baseStats.evasion, finalStats.evasion)}
                    {renderStatRow(<Target className="w-3.5 h-3.5 md:w-4 md:h-4 text-red-500" />, 'Crit Rate', baseStats.critChance, finalStats.critChance, true)}
