const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary,
    isReadOnly
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
    isReadOnly?: boolean;
}) => {
    const totalMercStats = useMemo(() => mergePrimaryStats(mercenary.stats, mercenary.allocatedStats), [mercenary]);
    const displayInventory = useMemo(() => {
        return selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
    }, [inventory, selectedSlotFilter]);

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-stone-950/40">
            {/* List Header */}
            <div className="p-4 md:p-6 bg-stone-900/60 border-b border-stone-800/80 flex justify-between items-center shrink-0 z-10 backdrop-blur-2xl">
                <h3 className="text-[10px] md:text-xs font-black text-stone-300 uppercase tracking-widest flex items-center gap-3">
                    <Box className="w-4 h-4 md:w-5 md:h-5 text-amber-600" /> 
                    <span>{selectedSlotFilter ? `Filtering: ${selectedSlotFilter.replace('_', ' ')}` : 'Full Equipment List'}</span>
                </h3>
                <span className="text-[10px] md:text-xs text-stone-500 font-mono font-black">{displayInventory.length} ITEMS</span>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-6 space-y-3">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center border-2 border-dashed border-stone-800/60 rounded-3xl text-stone-700 italic p-12 text-center">
                        <Box className="w-16 h-16 opacity-10 mb-4" />
                        <p className="text-sm md:text-lg">No equipment found for this slot.</p>
                    </div>
                ) : (
                    displayInventory.map(item => {
                        if (!item.equipmentData) return null;
                        const isSelected = selectedItemId === item.id;
                        const reqs = item.equipmentData.equipRequirements || {};
                        const failedStats = Object.entries(reqs).filter(([stat, val]) => totalMercStats[stat as keyof PrimaryStats] < (val as number));
                        const canEquip = failedStats.length === 0;
                        let imageUrl = item.equipmentData.image ? getAssetUrl(item.equipmentData.image) : (item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

                        return (
                            <div 
                                key={item.id}
                                onClick={() => !isSelected && onSelect(item.id)}
                                className={`flex flex-col gap-3 p-4 md:p-5 rounded-2xl border-2 transition-all ${isSelected ? 'border-amber-500 bg-stone-900/80 shadow-2xl' : 'border-stone-800/50 hover:border-stone-700 bg-stone-900/30 hover:bg-stone-900/50'} cursor-pointer group ${!canEquip ? 'opacity-70 grayscale-[0.3]' : ''}`}
                            >
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 md:w-16 md:h-16 bg-stone-950 rounded-xl border border-stone-800/80 flex items-center justify-center relative shrink-0 overflow-hidden shadow-inner ring-1 ring-white/5">
                                        <img src={imageUrl} className="w-9 h-9 md:w-12 md:h-12 object-contain" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="text-sm md:text-lg font-black truncate text-stone-100">{item.name}</div>
                                        <div className="flex items-center gap-3 text-[9px] md:text-[11px] mt-1">
                                            <span className="text-stone-500 font-mono">#{item.id.slice(-4)}</span>
                                            <span className="text-stone-800">•</span>
                                            <span className="text-amber-500 font-black uppercase tracking-widest">{item.equipmentData.rarity}</span>
                                        </div>
                                    </div>
                                    {!isReadOnly && isSelected && canEquip && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                            className="shrink-0 px-5 md:px-8 py-2 md:py-3 bg-amber-700 hover:bg-amber-600 text-white text-xs font-black uppercase rounded-xl shadow-2xl active:scale-95 transition-all border border-amber-500"
                                        >
                                            Equip Now
                                        </button>
                                    )}
                                </div>
                                <div className="flex justify-between items-center border-t border-stone-800/50 pt-3">
                                    <div className="flex items-center gap-3 text-[9px] md:text-xs text-stone-500 font-bold">
                                        <ShieldAlert className="w-4 h-4" />
                                        DURABILITY: {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                    </div>
                                    {Object.keys(reqs).length > 0 && (
                                        <div className="flex flex-wrap gap-1.5 justify-end max-w-[150px] md:max-w-none">
                                            {Object.entries(reqs).map(([stat, val]) => {
                                                const met = totalMercStats[stat as keyof PrimaryStats] >= (val as number);
                                                return (
                                                    <span key={stat} className={`text-[7px] md:text-[10px] px-2 py-0.5 rounded-full font-black uppercase border ${met ? 'text-stone-600 border-stone-800' : 'text-red-400 border-red-900/50 bg-red-950/40 animate-pulse'}`}>
                                                        {stat} {val}
                                                    </span>
                                                );
                                            })}
                                        </div>
                                    )}
                                </div>
                                {!canEquip && isSelected && (
                                    <div className="text-[9px] md:text-xs text-red-400 font-black bg-red-950/30 p-2 rounded-xl border border-red-900/40 flex items-center gap-2">
                                        <AlertCircle className="w-4 h-4" /> Inadequate stats to wield this item.
                                    </div>
                                )}
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
};

const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip, isReadOnly = false }) => {
    const { state, actions } = useGame();
    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'STATS' | 'STORAGE'>('STATS');
    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
            setActiveTab('STATS');
        }
    }, [mercenary?.id]);

    if (!mercenary) return null;

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);
    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const currentStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);
    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(currentStats, currentAttackType);

    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;
    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;
            previewStats = applyEquipmentBonuses(baseDerived, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, currentAttackType);
        }
    }

    const effectiveFinalStats = previewStats || currentStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    return (
        <div className="absolute inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-xl p-3 md:p-6 animate-in fade-in duration-500 overflow-hidden">
            <button 
                onClick={onClose} 
                className="absolute top-4 right-4 md:top-8 md:right-8 z-[230] p-3 md:p-4 bg-red-900/20 hover:bg-red-600 rounded-full text-red-500 hover:text-white border border-red-500/50 transition-all shadow-[0_0_30px_rgba(220,38,38,0.3)] backdrop-blur-2xl"
            >
                <X className="w-6 h-6 md:w-8 md:h-8" />
            </button>

            <div className="w-full max-w-7xl h-[calc(100dvh-3rem)] md:h-[90dvh] bg-stone-950/80 border border-white/10 rounded-[2.5rem] shadow-[0_50px_100px_rgba(0,0,0,0.9)] flex flex-row overflow-hidden relative ring-1 ring-white/10">
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    baseCombatPower={currentCombatPower}
                    nextCombatPower={effectiveCombatPower} 
                    showAffinityGain={false} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={(s) => { setSelectedSlot(s); if(s) setActiveTab('STORAGE'); }} 
                    selectedSlot={selectedSlot} 
                    isReadOnly={isReadOnly}
                />

                <div className="flex-1 bg-stone-900/40 flex flex-col h-full overflow-hidden">
                    <div className="flex border-b border-stone-800 bg-stone-950/80 shrink-0 z-20 backdrop-blur-3xl">
                        <button 
                            onClick={() => setActiveTab('STATS')}
                            className={`flex-1 py-5 md:py-7 text-xs md:text-sm font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all ${activeTab === 'STATS' ? 'text-amber-400 bg-stone-900/60 border-b-4 border-amber-500' : 'text-stone-600 hover:text-stone-300 hover:bg-white/5'}`}
                        >
                            <Activity className="w-4 h-4 md:w-6 md:h-6" /> <span>Statistics</span>
                        </button>
                        <button 
                            onClick={() => setActiveTab('STORAGE')}
                            className={`flex-1 py-5 md:py-7 text-xs md:text-sm font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all ${activeTab === 'STORAGE' ? 'text-amber-400 bg-stone-900/60 border-b-4 border-amber-500' : 'text-stone-600 hover:text-stone-300 hover:bg-white/5'}`}
                        >
                            <Box className="w-4 h-4 md:w-6 md:h-6" /> <span>Equipment Bag</span>
                        </button>
                    </div>

                    <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
                        {activeTab === 'STATS' ? (
                            <MercenaryStatsPanel 
                                mercenary={mercenary} 
                                baseStats={currentStats}
                                finalStats={effectiveFinalStats} 
                                localAllocated={localAllocated}
                                onSetLocalAllocated={setLocalAllocated}
                                isReadOnly={isReadOnly}
                            />
                        ) : (
                            <EquipmentInventoryList 
                                inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                                selectedItemId={selectedInventoryItemId} 
                                onSelect={setSelectedInventoryItemId} 
                                onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                                selectedSlotFilter={selectedSlot}
                                mercenary={mercenary}
                                isReadOnly={isReadOnly}
                            />
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

