                            <div className="bg-stone-100/95 p-1 rounded-lg backdrop-blur-sm border border-stone-300 flex items-center justify-center w-10 h-10 md:w-12 md:h-12 shadow-inner">
                                <img src={getItemImageUrl(activeCustomer.request.requestedId)} className="w-6 h-6 md:w-8 md:h-8 object-contain" />
                            </div>
                            <div className="leading-tight">
                                <div className="font-bold text-stone-800 text-xs md:text-sm line-clamp-1 w-20 md:w-24">{getItemName(activeCustomer.request.requestedId)}</div>
                                <div className="text-[10px] md:text-xs font-bold text-emerald-600 flex items-center gap-0.5">
                                    <Coins className="w-2.5 h-2.5 md:w-3 md:h-3" />
                                    {activeCustomer.request.price} G
                                </div>
