import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  // Property declarations to ensure TypeScript compatibility with inherited properties
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private lastStage: number = -1;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, this.scale.width, this.scale.height, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.bgOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.flashOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xffaa00, 0).setOrigin(0).setDepth(100);

    this.setupUI();
    this.handleResize();
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleInput(pointer); return; }

      if (this.isPointerInHitArea(pointer.worldX, pointer.worldY) || Phaser.Math.Distance.Between(pointer.worldX, pointer.worldY, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleInput(pointer);
      } else {
          this.handleMiss(pointer.worldX, pointer.worldY);
      }
    }, this);
  }

  private isBellowsClick(objs: any[]) { return objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c)); }
  private isHeatUpClick(objs: any[]) { return objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c)); }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
    const w = this.scale.width;
    const h = this.scale.height;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.scale.width;
    const h = this.scale.height;

    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { this.isPlaying = true; this.infoText.setVisible(false); this.resetRing(); this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 }); } 
      else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, this.centerX, this.centerY); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, swingX, swingY); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;
    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff); this.combo++; this.perfectCount++;
      if (this.perfectCount >= 6) { this.currentQuality += 1; this.showFeedback('QUALITY UP!', 0xfbbf24, this.hitX, this.hitY - 60); }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', swingX, swingY); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY); this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', swingX, swingY); this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else { this.handleMiss(swingX, swingY); }
    this.updateProgressBar(); if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01); this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY); this.updateProgressBar(); this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) { this.isReadyToStart = false; this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6'); }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

    let barColor = 0xeab308; 
    if (ratio < 0.4) barColor = 0x3b82f6; else if (ratio > 0.7) barColor = 0xef4444;
    this.tempBar.setFillStyle(barColor);

    const stage = Math.min(5, Math.floor(Phaser.Math.Clamp(this.score / this.targetScore, 0, 1) * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD'; else if (this.temperature > 75) this.currentTempStage = 'AURA'; else if (this.temperature > 40) this.currentTempStage = 'HOT'; else if (this.temperature > 15) this.currentTempStage = 'WARM'; else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) { this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5); this.bladeContainer.add(this.bladeImage); } else this.bladeImage.setTexture(key);
      if (this.lastStage !== -1) { this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true }); }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta; const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5); this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) { this.combo = 0; this.resetRing(); }
  }

  private resetRing() {
    if (this.temperature <= 0) return;
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35); const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad)); this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true; this.bellowsSprite.play('bellows_pump');
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (!this.isPlaying && !this.isReadyToStart) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    const icon = this.heatUpBtnContainer.getByName('btnIcon') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';

export interface MainForgeData {
  hasFurnace: boolean;
  onInteract: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
}

export default class MainForgeScene extends Phaser.Scene {
  // Property declarations to ensure TypeScript compatibility with inherited properties
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;

  private onInteract?: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
  private hasFurnace: boolean = false;
  private floor?: Phaser.GameObjects.Rectangle;
  private bg?: Phaser.GameObjects.Rectangle;
  private glow?: Phaser.GameObjects.Arc;
  private anvilContainer?: Phaser.GameObjects.Container;
  private anvilText?: Phaser.GameObjects.Text;
  private furnaceObj?: any;

  constructor() {
    super('MainForgeScene');
  }

  init(data: MainForgeData) {
    this.hasFurnace = data.hasFurnace;
    this.onInteract = data.onInteract;
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.bg = this.add.rectangle(0, 0, 0, 0, 0x1c1917); 
    this.floor = this.add.rectangle(0, 0, 0, 0, 0x292524); 
    this.glow = this.add.circle(0, 0, 200, 0x000000, 0.5);

    this.createAnvil();
    this.createFurnaceSlot();
    this.createDust();

    this.handleResize();
    this.scale.on('resize', this.handleResize, this);
  }

  private handleResize() {
    const w = this.scale.width;
    const h = this.scale.height;
    const centerX = w / 2;
    const centerY = h / 2;
    const isCompact = h < 450;

    if (this.bg) this.bg.setPosition(centerX, centerY).setSize(w, h);
    if (this.floor) this.floor.setPosition(centerX, centerY - (h * 0.1)).setSize(w, h * 0.6);
    if (this.glow) this.glow.setPosition(centerX, centerY - (h * 0.2)).setRadius(h * 0.4);

    if (this.anvilContainer) {
        this.anvilContainer.setPosition(centerX - (w * 0.2), centerY + (h * 0.1));
        if (this.anvilText) this.anvilText.setPosition(this.anvilContainer.x, this.anvilContainer.y + (isCompact ? 50 : 70));
    }

    if (this.furnaceObj) {
        const fx = centerX + (w * 0.2);
        const fy = centerY + (h * 0.05);
        if (this.furnaceObj.body) this.furnaceObj.body.setPosition(fx, fy);
        if (this.furnaceObj.fire) this.furnaceObj.fire.setPosition(fx, fy + 20);
        if (this.furnaceObj.text) this.furnaceObj.text.setPosition(fx, fy + (this.hasFurnace ? -80 : 0));
        if (this.furnaceObj.outline) this.furnaceObj.outline.setPosition(fx, fy);
    }
  }

  private createAnvil() {
    this.anvilContainer = this.add.container(0, 0);
    const base = this.add.rectangle(0, 40, 80, 40, 0x44403c).setStrokeStyle(2, 0x000000);
    const top = this.add.rectangle(0, 0, 100, 30, 0x57534e).setStrokeStyle(2, 0x000000);
    const horn = this.add.triangle(-60, 0, 0, 0, 20, 30, 0, 30, 0x57534e).setStrokeStyle(2, 0x000000);

    this.anvilContainer.add([base, horn, top]).setSize(120, 100);
    this.anvilContainer.setInteractive(new Phaser.Geom.Rectangle(-60, -20, 120, 100), Phaser.Geom.Rectangle.Contains);
    this.anvilContainer.on('pointerdown', () => {
      this.tweens.add({ targets: this.anvilContainer, scale: 0.95, yoyo: true, duration: 50 });
      this.onInteract?.('ANVIL');
    });

    this.anvilText = this.add.text(0, 0, 'ANVIL', { fontFamily: 'monospace', fontSize: '12px', color: '#78716c' }).setOrigin(0.5);
  }

  private createFurnaceSlot() {
    this.furnaceObj = {};
    if (this.hasFurnace) {
      this.furnaceObj.body = this.add.rectangle(0, 0, 100, 140, 0x44403c).setStrokeStyle(2, 0x000000);
      this.furnaceObj.fire = this.add.circle(0, 0, 30, 0xea580c);
      this.tweens.add({ targets: this.furnaceObj.fire, alpha: 0.6, scale: 1.1, yoyo: true, repeat: -1, duration: 800, ease: 'Sine.easeInOut' });
      this.furnaceObj.body.setInteractive().on('pointerdown', () => this.onInteract?.('FURNACE'));
      this.furnaceObj.text = this.add.text(0, 0, 'FURNACE', { fontFamily: 'monospace', fontSize: '12px', color: '#ea580c' }).setOrigin(0.5);
    } else {
      this.furnaceObj.outline = this.add.rectangle(0, 0, 100, 140).setStrokeStyle(2, 0x44403c, 1);
      this.furnaceObj.text = this.add.text(0, 0, 'EMPTY SLOT', { fontSize: '10px', color: '#44403c' }).setOrigin(0.5);
      this.furnaceObj.outline.setInteractive().on('pointerdown', () => this.onInteract?.('EMPTY_SLOT'));
    }
  }

  private createDust() {
    this.add.particles(0, 0, 'white', {
      x: { min: 0, max: 2000 }, y: { min: 0, max: 2000 },
      lifespan: 4000, speedY: { min: 5, max: 20 }, scale: { start: 0.2, end: 0 }, alpha: { start: 0.5, end: 0 },
      quantity: 1, frequency: 500, tint: 0xa8a29e
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export default class IntroScene extends Phaser.Scene {
  // Property declarations to ensure TypeScript compatibility with inherited properties
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public game!: Phaser.Game;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private bgs: Phaser.GameObjects.Image[] = [];
  private dragon?: Phaser.GameObjects.Image;
  private narrativeTexts: Phaser.GameObjects.Text[] = [];
  private devText?: Phaser.GameObjects.Text;
  private skipHint?: Phaser.GameObjects.Text;
  private fireEmitter?: Phaser.GameObjects.Particles.ParticleEmitter;
  private breathOverlay?: Phaser.GameObjects.Rectangle;

  constructor() {
    super('IntroScene');
  }

  preload() {
    this.load.image('intro_bg', getAssetUrl('intro_bg_01.png'));
    this.load.image('intro_bg_02', getAssetUrl('intro_bg_02.png'));
    this.load.image('intro_bg_03', getAssetUrl('intro_bg_03.png'));
    this.load.image('intro_bg_04', getAssetUrl('intro_bg_04.png'));
    this.load.image('intro_bg_05', getAssetUrl('intro_bg_05.png'));
    this.load.image('intro_dragon', getAssetUrl('intro_dragon_02.png'));
  }

  private createNarrativeText(text: string, color: string = '#ef4444') {
    const t = this.add
      .text(0, 0, text, {
        fontFamily: 'serif',
        fontSize: '40px',
        color: color,
        align: 'center',
        fontStyle: 'italic',
        stroke: '#000000',
        strokeThickness: 4,
      })
      .setOrigin(0.5)
      .setAlpha(0)
      .setDepth(10);
    this.narrativeTexts.push(t);
    return t;
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    if (!this.textures.exists('intro_flame')) {
        const graphics = this.make.graphics({ x: 0, y: 0 });
        graphics.fillStyle(0xff5500, 1).fillCircle(16, 16, 16).generateTexture('intro_flame', 32, 32).destroy();
    }

    this.input.once('pointerdown', () => {
        this.game.events.emit('intro-complete');
    });

    this.skipHint = this.add.text(0, 0, 'Touch anywhere to skip', {
        fontFamily: 'sans-serif', fontSize: '12px', color: '#57534e', fontStyle: 'bold'
    }).setOrigin(0.5).setAlpha(0).setDepth(20);

    const keys = ['intro_bg', 'intro_bg_02', 'intro_bg_03', 'intro_bg_04', 'intro_bg_05'];
    keys.forEach(key => {
        const img = this.add.image(0, 0, key).setAlpha(0).setDepth(1);
        this.bgs.push(img);
    });

    this.dragon = this.add.image(0, 0, 'intro_dragon').setDepth(2).setVisible(false);

    this.devText = this.add.text(0, 0, "CRYINGDEV STUDIO\nPRESENTS", {
      fontFamily: 'serif', fontSize: '45px', color: '#a8a29e', align: 'center', fontStyle: 'bold'
    }).setOrigin(0.5).setAlpha(0).setDepth(10);

    const n1 = this.createNarrativeText("FIASCO,\nA MASTER OF DISASTER...", '#ef4444');
    const n2 = this.createNarrativeText("EVERTHING WE LOVED IS LOST...", '#ef4444');
    const n3 = this.createNarrativeText("BUT THE HAMMER IS STILL HERE.", '#ef4444');
    const nDespair = this.createNarrativeText("NEVER FORGET...", '#ef4444');
    const nVengeance = this.createNarrativeText("AND FORGED A VENGEANCE.", '#f59e0b');

    this.breathOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xff4400)
        .setAlpha(0).setDepth(5).setBlendMode(Phaser.BlendModes.ADD);

    this.fireEmitter = this.add.particles(0, 0, 'intro_flame', {
        speedY: { min: 1200, max: 2200 },
        speedX: { min: -600, max: 600 },
        scale: { start: 6, end: 15 },
        alpha: { start: 1, end: 0 },
        lifespan: 1500,
        quantity: 40,
        blendMode: 'ADD',
        emitting: false
    });
    this.fireEmitter.setDepth(4);

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.startSequence(n1, n2, n3, nDespair, nVengeance);

    this.time.delayedCall(0, () => this.handleResize());
  }

private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width;
    const h = gameSize?.height ?? this.scale.gameSize.height;
    const cx = w / 2;
    const cy = h / 2;

    // 카메라를 캔버스(래퍼) 크기에 고정
    this.cameras.main.setViewport(0, 0, w, h);

    // UI 스케일은 연속적으로 (짧은 축 기준)
    const uiScale = Phaser.Math.Clamp(Math.min(w, h) / 720, 0.6, 1.2);

    // BG: "세로 딱 맞춤" (가로는 크롭 허용)
    this.bgs.forEach(img => {
      img.setPosition(cx, cy);
      const scale = h / img.height;     // height-fit
      img.setScale(scale);
    });

    // Dragon: height 중심으로 맞추되, width도 과하면 제한
    if (this.dragon) {
      const dScaleByHeight = (h * 0.55) / this.dragon.height; // 화면 높이의 55%
      const dScaleByWidth  = (w * 0.90) / this.dragon.width;  // 화면 너비의 90%
      const dScale = Math.min(dScaleByHeight, dScaleByWidth);
      this.dragon.setScale(dScale);
      this.dragon.setPosition(cx, cy - h * 0.18);
    }

    if (this.devText) {
      this.devText.setPosition(cx, cy);
      this.devText.setFontSize(Math.round(45 * uiScale));
    }

    if (this.skipHint) {
      this.skipHint.setPosition(cx, h - Math.max(24, h * 0.05));
      this.skipHint.setFontSize(Math.round(12 * uiScale));
    }

    if (this.breathOverlay) {
      this.breathOverlay.setPosition(cx, cy).setSize(w, h);
    }

    this.narrativeTexts.forEach(t => {
      t.setPosition(cx, cy);
      t.setFontSize(Math.round(40 * uiScale));
    });

    // 마지막 2줄 간격도 비율 기반
    const despairIdx = this.narrativeTexts.length - 2;
    const gap = Math.max(24, h * 0.06);
    if (this.narrativeTexts[despairIdx]) this.narrativeTexts[despairIdx].y = cy - gap / 2;
    if (this.narrativeTexts[despairIdx + 1]) this.narrativeTexts[despairIdx + 1].y = cy + gap / 2;

    // Fire emitter: 드래곤 “입 근처”로
    if (this.fireEmitter) {
      if (this.dragon) {
        const mouthY = this.dragon.y + this.dragon.displayHeight * 0.10;
        this.fireEmitter.setPosition(cx, mouthY);
      } else {
        this.fireEmitter.setPosition(cx, h * 0.35);
      }
    }
  }

  private startSequence(n1: any, n2: any, n3: any, nD: any, nV: any) {
    this.tweens.chain({
      tweens: [
        { targets: this.devText, alpha: 1, duration: 2500, ease: 'Power2' },
        { targets: this.devText, alpha: 1, duration: 2000, onStart: () => this.cameras.main.shake(6000, 0.005) },
        { targets: this.devText, alpha: 0, duration: 2000, ease: 'Power2' },
        { targets: this.bgs[0], alpha: 1, duration: 1500, ease: 'Linear' },
        {
          targets: this.dragon,
          alpha: { from: 0, to: 1 },
          duration: 3000,
          ease: 'Sine.easeInOut',
          hold: 500,
          onStart: () => {
              this.dragon!.setVisible(true);
              this.cameras.main.shake(3500, 0.005); 
          }
        },
        { targets: this.dragon, y: '-=150', scale: '*=0.7', duration: 1000, ease: 'Quad.easeOut' },
        {
            targets: this.breathOverlay,
            alpha: 0.8,
            duration: 2500,
            yoyo: true, hold: 100,
            onStart: () => {
                this.fireEmitter!.start();
                this.cameras.main.shake(2500, 0.03);
            },
            onComplete: () => {
                this.fireEmitter!.stop();
                this.dragon!.setVisible(false);
            }
        },
        { targets: this.bgs[1], alpha: 1, duration: 2000, hold: 2500, ease: 'Linear' },
        { targets: n1, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n1, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[2], alpha: 1, duration: 2000, hold: 2500, ease: 'Linear' },
        { targets: n2, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n2, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[3], alpha: 1, duration: 3000, hold: 3500, ease: 'Linear' },
        { targets: n3, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n3, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[4], alpha: 1, duration: 3000, ease: 'Linear' },
        { targets: nD, alpha: 1, duration: 2000, ease: 'Power2', delay: 500 },
        { targets: nV, alpha: 1, duration: 2500, ease: 'Power2' },
        {
          targets: [...this.bgs, nD, nV],
          alpha: 0,
          duration: 3000,
          delay: 3000,
          onComplete: () => {
            this.game.events.emit('intro-complete');
          }
        }
      ]
    });
  }
}

import React, { useEffect, useRef, useState } from 'react';
import Phaser from 'phaser';
import { X, Scissors } from 'lucide-react';
import { getAssetUrl } from '../../../utils';

interface WorkbenchMinigameProps {
  onComplete: (score: number, bonus?: number) => void;
  onClose: () => void;
  difficulty?: number;
}

class WorkbenchScene extends Phaser.Scene {
  // Property declarations to ensure TypeScript compatibility with inherited properties
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;
  public children!: Phaser.GameObjects.DisplayList;

  private targetNodes: Phaser.GameObjects.Arc[] = [];
  private cursor!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private progBg!: Phaser.GameObjects.Rectangle;
  private cycleText!: Phaser.GameObjects.Text;
  private comboText!: Phaser.GameObjects.Text;
  private instructionText!: Phaser.GameObjects.Text;
  private wavePathGraphics!: Phaser.GameObjects.Graphics;

  private centerX: number = 0;
  private centerY: number = 0;
  private waveWidth: number = 600;
  private waveAmplitude: number = 60;
  private wavePeriods: number = 2; 
  private cursorProgress: number = 0; 
  private cursorSpeed: number = 0.00015; 
  private currentCycle: number = 1;
  private totalNodesSpawned: number = 0;
  private totalNodesHit: number = 0;
  private hitsInCurrentCycle: number = 0;
  private confirmedProgress: number = 0; 
  private perfectCombo: number = 0;
  private bonusStats: number = 0;
  private persistentElements: (Phaser.GameObjects.GameObject)[] = [];
  private isFinished: boolean = false;
  private onComplete?: (score: number, bonus?: number) => void;

  constructor() {
    super('WorkbenchScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  init(data: { onComplete: (score: number, bonus?: number) => void, difficulty: number }) {
    this.onComplete = data.onComplete;
    this.cursorSpeed = 0.00015 + (data.difficulty * 0.00002);
    this.currentCycle = 1;
    this.totalNodesSpawned = 0;
    this.totalNodesHit = 0;
    this.hitsInCurrentCycle = 0;
    this.confirmedProgress = 0;
    this.perfectCombo = 0;
    this.bonusStats = 0;
    this.isFinished = false;
    this.cursorProgress = 0;
  }

  preload() {
    this.load.image('workbench_table', getAssetUrl('workbench_table.png'));
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    if (this.textures.exists('workbench_table')) {
        this.add.image(0, 0, 'workbench_table').setName('bgImg').setScale(1.2).setAlpha(0.6);
    }

    this.progBg = this.add.rectangle(0, 0, 250, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0, 12, 0x10b981).setOrigin(0, 0.5);
    this.cycleText = this.add.text(0, 0, `PROGRESS: 0%`, { fontFamily: 'monospace', fontSize: '16px', color: '#10b981', fontStyle: 'bold' }).setOrigin(0.5);
    this.wavePathGraphics = this.add.graphics().setDepth(1);
    this.cursor = this.add.rectangle(0, 0, 4, 35, 0xffffff).setDepth(10).setStrokeStyle(1, 0xcccccc);
    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '32px', color: '#10b981', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.instructionText = this.add.text(0, 0, '', { fontFamily: 'monospace', fontSize: '12px', color: '#10b981', stroke: '#000', strokeThickness: 2, align: 'center' }).setOrigin(0.5);

    this.handleResize();
    this.scale.on('resize', this.handleResize, this);
    this.spawnSegmentedNodes();
  }

  private handleResize() {
    const w = this.scale.width;
    const h = this.scale.height;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isCompact = h < 450;

    this.waveAmplitude = isCompact ? 50 : 80;
    this.waveWidth = w * 0.85;

    const bg = this.children.getByName('bgImg') as Phaser.GameObjects.Image;
    if (bg) {
        bg.setPosition(this.centerX, this.centerY);
        bg.setScale(Math.max(w / bg.width, h / bg.height) * 1.1);
    }

    const progW = Math.min(w * 0.7, 300);
    this.progBg.setPosition(this.centerX, 40).setSize(progW, 18);
    this.progressBar.setPosition(this.centerX - progW / 2, 40).width = (this.confirmedProgress / 100) * progW;

    this.cycleText.setPosition(this.centerX, 70).setFontSize(isCompact ? '14px' : '18px');
    this.comboText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 150));
    this.instructionText.setPosition(this.centerX, h - 40).setText(isCompact ? 'STITCH UNTIL 100%' : 'STITCH UNTIL PROGRESS REACHES 100%');

    this.drawWavePath();
    this.repositionNodes();
  }

  private repositionNodes() {
    const startX = this.centerX - (this.waveWidth / 2);
    this.targetNodes.forEach((node: any) => {
        const p = node.progressPos;
        const nx = startX + (p * this.waveWidth);
        const ny = this.centerY + Math.sin(p * Math.PI * 2 * this.wavePeriods) * this.waveAmplitude;
        node.setPosition(nx, ny);
        if (node.xMark) node.xMark.setPosition(nx, ny);
    });
  }

  drawWavePath() {
    this.wavePathGraphics.clear().lineStyle(3, 0x10b981, 0.15).beginPath();
    const startX = this.centerX - (this.waveWidth / 2);
    for (let i = 0; i <= 100; i++) {
        const p = i / 100;
        const x = startX + (p * this.waveWidth);
        const y = this.centerY + Math.sin(p * Math.PI * 2 * this.wavePeriods) * this.waveAmplitude;
        if (i === 0) this.wavePathGraphics.moveTo(x, y); else this.wavePathGraphics.lineTo(x, y);
    }
    this.wavePathGraphics.strokePath();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.targetNodes.forEach((node: any) => {
        if (!node.isHit && !node.isMissed && this.cursorProgress > node.progressPos + 0.06) this.handleMiss(node);
    });

    if (this.cursorProgress > 1) {
        this.cursorProgress = 0;
        if (this.hitsInCurrentCycle > 0) {
            this.confirmedProgress = Math.min(100, this.confirmedProgress + 20);
            this.progressBar.width = (this.confirmedProgress / 100) * this.progBg.width;
            this.cycleText.setText(`PROGRESS: ${this.confirmedProgress}%`);
        }
        if (this.confirmedProgress >= 100) { this.finishGame(); return; }
        this.currentCycle++; this.hitsInCurrentCycle = 0; this.spawnSegmentedNodes(); 
    }

    const startX = this.centerX - (this.waveWidth / 2);
    const x = startX + (this.cursorProgress * this.waveWidth);
    const y = this.centerY + Math.sin(this.cursorProgress * Math.PI * 2 * this.wavePeriods) * this.waveAmplitude;
    const freq = Math.PI * 2 * this.wavePeriods;
    const angle = Math.atan((this.waveAmplitude * freq / this.waveWidth) * Math.cos(this.cursorProgress * freq));
    this.cursor.setPosition(x, y).setRotation(angle + Math.PI / 2);
  }

  spawnSegmentedNodes() {
    this.targetNodes.forEach((n: any) => { if (n.xMark) n.xMark.destroy(); n.destroy(); });
    this.targetNodes = [];
    this.persistentElements.forEach(el => el.destroy());
    this.persistentElements = [];

    const startX = this.centerX - (this.waveWidth / 2);
    const segments = [{ min: 0.1, max: 0.25 }, { min: 0.35, max: 0.5 }, { min: 0.6, max: 0.75 }, { min: 0.85, max: 0.95 }];
    segments.forEach((seg, idx) => {
        const p = seg.min + Math.random() * (seg.max - seg.min);
        const node = this.add.circle(0, 0, 20, 0x10b981, 0.2).setStrokeStyle(3, 0x10b981).setDepth(5).setInteractive();
        (node as any).progressPos = p; (node as any).isHit = false; (node as any).isMissed = false;
        this.targetNodes.push(node);
        node.on('pointerdown', () => this.handleNodeClick(node));
        this.tweens.add({ targets: node, scale: { from: 0, to: 1 }, duration: 300, delay: idx * 50, ease: 'Back.out' });
    });
    this.repositionNodes();
  }

  handleNodeClick(node: Phaser.GameObjects.Arc) {
    if (this.isFinished || (node as any).isHit || (node as any).isMissed) return;
    const diff = Math.abs(this.cursorProgress - (node as any).progressPos);
    if (diff < 0.08) {
        const isPerfect = (1 - (diff / 0.08)) > 0.8;
        (node as any).isHit = true; this.totalNodesHit++; this.hitsInCurrentCycle++; node.disableInteractive();
        if (isPerfect) {
            this.perfectCombo++; this.showFeedback('PERFECT!', 0xfbbf24, node.x, node.y);
            if (this.perfectCombo >= 8) {
                this.bonusStats++;
                const bonusTxt = this.add.text(node.x, node.y, '+1', { fontFamily: 'monospace', fontSize: '18px', color: '#fbbf24', fontStyle: 'bold', stroke: '#000', strokeThickness: 4 }).setOrigin(0.5);
                this.persistentElements.push(bonusTxt);
            }
        } else { this.perfectCombo = 0; this.showFeedback('GOOD!', 0x10b981, node.x, node.y); }
        this.cameras.main.shake(100, 0.005);
        this.tweens.add({ targets: node, scale: 0.4, duration: 200, onStart: () => { node.setFillStyle(isPerfect ? 0xfbbf24 : 0x10b981, 1); node.setStrokeStyle(0); } });
    } else this.handleMiss(node);
  }

  handleMiss(node: Phaser.GameObjects.Arc) {
      if ((node as any).isMissed || (node as any).isHit) return;
      (node as any).isMissed = true; this.perfectCombo = 0; node.disableInteractive();
      node.setFillStyle(0xef4444, 1).setStrokeStyle(0);
      const xMark = this.add.text(node.x, node.y, '×', { fontFamily: 'Arial', fontSize: '16px', color: '#ffffff', fontStyle: 'bold' }).setOrigin(0.5);
      (node as any).xMark = xMark; 
      this.tweens.add({ targets: node, scale: 0.4, duration: 200 });
      this.showFeedback('MISS', 0xef4444, node.x, node.y);
      this.cameras.main.shake(100, 0.005);
  }

  showFeedback(text: string, color: number, x: number, y: number) {
      const fb = this.add.text(x, y - 40, text, { fontFamily: 'Arial Black', fontSize: '24px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(20);
      this.tweens.add({ targets: fb, y: fb.y - 30, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
      if (this.perfectCombo > 1) {
          this.comboText.setText(`${this.perfectCombo} PERFECT!`).setAlpha(1).setColor(this.perfectCombo >= 8 ? '#fbbf24' : '#10b981');
          this.tweens.add({ targets: this.comboText, alpha: 0, duration: 800, delay: 500 });
      }
  }

  finishGame() {
      this.isFinished = true; this.cursor.setVisible(false);
      const quality = Math.round((this.totalNodesSpawned > 0 ? (this.totalNodesHit / this.totalNodesSpawned) : 0) * 100);
      const label = this.getQualityLabel(quality);
      const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000, 0.85).setAlpha(0).setDepth(50);
      const txt = this.add.text(this.centerX, this.centerY - 40, quality < 30 ? 'DEFECTIVE' : `${label} CRAFT!`, { fontFamily: 'serif', fontSize: '40px', color: quality < 30 ? '#ef4444' : '#10b981', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0).setDepth(51);
      this.tweens.add({ targets: [bg, txt], alpha: 1, duration: 500, onComplete: () => { this.time.delayedCall(1500, () => { if (this.onComplete) this.onComplete(quality, this.bonusStats); }); } });
  }
}

const WorkbenchMinigame: React.FC<WorkbenchMinigameProps> = ({ onComplete, onClose, difficulty = 1 }) => {
  const gameRef = useRef<Phaser.Game | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isReady, setIsReady] = useState(false);

  useEffect(() => {
    const checkSize = () => {
        if (containerRef.current && containerRef.current.clientWidth > 0 && containerRef.current.clientHeight > 0) setIsReady(true);
        else requestAnimationFrame(checkSize);
    };
    checkSize();
  }, []);

  useEffect(() => {
    if (!isReady || !containerRef.current) return;
    const config: Phaser.Types.Core.GameConfig = {
      type: Phaser.AUTO, parent: containerRef.current,
      width: containerRef.current.clientWidth, height: containerRef.current.clientHeight,
      backgroundColor: '#0c0a09', scene: [WorkbenchScene],
      scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
    };
    const game = new Phaser.Game(config);
    gameRef.current = game;
    game.scene.start('WorkbenchScene', { onComplete, difficulty });

    const resizeObserver = new ResizeObserver((entries) => {
        for (let entry of entries) {
            const { width, height } = entry.contentRect;
            if (game && game.scale && width > 0 && height > 0) {
                game.scale.resize(width, height);
            }
        }
    });
    if (containerRef.current) resizeObserver.observe(containerRef.current);

    return () => { 
        resizeObserver.disconnect();
        if (gameRef.current) gameRef.current.destroy(true); 
    };
  }, [isReady, onComplete, difficulty]);

  return (
    <div className="absolute inset-0 z-50 flex flex-col bg-stone-950 animate-in fade-in duration-300 overflow-hidden">
        <div className="w-full h-10 md:h-14 shrink-0 bg-stone-900 border-b border-stone-800 flex items-center justify-between px-4 z-10 shadow-lg">
            <div className="flex items-center gap-2">
                <Scissors className="w-4 h-4 text-emerald-400" />
                <span className="text-stone-200 font-bold text-xs md:text-sm tracking-wide">Workbench</span>
            </div>
            <button onClick={onClose} className="flex items-center gap-1 px-3 py-1 bg-stone-800 hover:bg-red-900/20 text-stone-400 hover:text-red-400 rounded border border-stone-700 transition-all text-[10px] font-bold">
                <X className="w-3 h-3" /> CANCEL
            </button>
        </div>
        <div className="flex-1 w-full relative flex items-center justify-center bg-[#1c1917] overflow-hidden">
            <div 
              ref={containerRef} 
              style={{ width: '100%', height: '100dvh' }}
              className="overflow-hidden" 
            />
        </div>
    </div>
  );
};

export default WorkbenchMinigame;

